import { useEffect, useState } from 'react';
import { Wand2, Download, Loader2, Clock } from 'lucide-react';
import { toast } from 'sonner';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '@/lib/utils';

const IMAGE_GEN_URL = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/ai-image-gen`;

const STORAGE_KEY = 'ai_image_history_v1';
const LIMIT_STORAGE_KEY = 'ai_image_gen_limit_v1';
const LIMIT_HOURS = 15;
const LIMIT_MS = LIMIT_HOURS * 60 * 60 * 1000;

const normalizeImageSrc = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const v = value.trim();
  if (!v) return null;
  if (v.startsWith('data:image/')) return v;
  if (v.startsWith('http://') || v.startsWith('https://')) return v;
  const b64Only = /^[A-Za-z0-9+/=]{200,}$/.test(v);
  if (b64Only) return `data:image/png;base64,${v}`;
  return null;
};

const AIImageView = () => {
  const { user } = useAuth();
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [errorDetail, setErrorDetail] = useState<string | null>(null);
  const [lastGenTime, setLastGenTime] = useState<number | null>(null);
  const [timeLeft, setTimeLeft] = useState<string | null>(null);
  const [canGenerate, setCanGenerate] = useState(true);

  // Fetch last generation time from profiles + local backup
  useEffect(() => {
    const fetchLimit = async () => {
      // 1. Try local storage first for immediate feedback
      const local = localStorage.getItem(LIMIT_STORAGE_KEY);
      if (local) {
        setLastGenTime(parseInt(local, 10));
      }

      // 2. Try DB for account-wide sync
      if (!user?.id) return;
      try {
        const { data, error } = await (supabase as any)
          .from('profiles')
          .select('last_image_gen_at')
          .eq('id', user.id) // Corrected from user_id to id
          .maybeSingle();

        if (error) {
          console.error('Limit fetch error:', error);
        }

        if ((data as any)?.last_image_gen_at) {
          const dbTime = new Date((data as any).last_image_gen_at).getTime();
          // Use the most recent of the two
          setLastGenTime(prev => (!prev || dbTime > prev) ? dbTime : prev);
        }
      } catch (err) {
        console.error('Failed to sync image limit:', err);
      }
    };
    fetchLimit();
  }, [user?.id]);

  // Handle countdown timer
  useEffect(() => {
    if (!lastGenTime) {
      setCanGenerate(true);
      setTimeLeft(null);
      return;
    }

    const interval = setInterval(() => {
      const now = Date.now();
      const diff = now - lastGenTime;

      if (diff < LIMIT_MS) {
        setCanGenerate(false);
        const remaining = LIMIT_MS - diff;
        const h = Math.floor(remaining / (1000 * 60 * 60));
        const m = Math.floor((remaining % (1000 * 60 * 60)) / (1000 * 60));
        const s = Math.floor((remaining % (1000 * 60)) / 1000);
        setTimeLeft(`${h}s ${m}m ${s}s`);
      } else {
        setCanGenerate(true);
        setTimeLeft(null);
        clearInterval(interval);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [lastGenTime]);

  useEffect(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw);
      if (typeof parsed?.prompt === 'string') setPrompt(parsed.prompt);
      if (typeof parsed?.resultImage === 'string' || parsed?.resultImage === null) setResultImage(parsed.resultImage ?? null);
      if (typeof parsed?.errorDetail === 'string' || parsed?.errorDetail === null) setErrorDetail(parsed.errorDetail ?? null);
    } catch {
      // ignore
    }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem(
         STORAGE_KEY,
        JSON.stringify({ prompt, resultImage, errorDetail })
      );
    } catch {
      // ignore
    }
  }, [prompt, resultImage, errorDetail]);

  const handleGenerate = async () => {
    if (!prompt.trim() || isGenerating) return;
    setIsGenerating(true);
    setResultImage(null);
    setErrorDetail(null);
    try {
      const resp = await fetch(IMAGE_GEN_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY}`,
        },
        body: JSON.stringify({ prompt }),
      });

      if (resp.status === 429) { 
        toast.error("Limit tugadi! Pro rejaga o'ting"); 
        window.dispatchEvent(new Event('show-plan-overlay'));
        return; 
      }
      if (resp.status === 402) { toast.error("Kredit yetarli emas"); return; }

      const data = await resp.json();

      if (!resp.ok) {
        console.error('Image gen error:', data);
        const detail = data.snapshot || data.details || data.error || 'Unknown error';
        setErrorDetail(typeof detail === 'string' ? detail.slice(0, 200) : JSON.stringify(detail).slice(0, 200));
        toast.error(data.error || 'Rasm yaratishda xatolik');
        return;
      }

      const src = normalizeImageSrc(data.content);
      if (src) {
        setResultImage(src);
        // Update last_image_gen_at in profiles upon success
        if (user?.id) {
          const now = Date.now();
          const nowIso = new Date(now).toISOString();
          
          // Local backup
          localStorage.setItem(LIMIT_STORAGE_KEY, now.toString());
          setLastGenTime(now);
          setCanGenerate(false);

          // DB update
          const { error } = await (supabase as any)
            .from('profiles')
            .update({ last_image_gen_at: nowIso })
            .eq('id', user.id); // Corrected from user_id to id
          
          if (error) {
            console.error('Failed to update image limit in DB:', error);
            // We don't toast error here because local limit is already set
          }
        }
      } else {
        console.error('Could not parse image from response:', data);
        toast.error("Rasm yaratilmadi, qayta urinib ko'ring");
      }
    } catch (error) {
      console.error(error);
      toast.error("Rasm yaratishda xatolik yuz berdi");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!resultImage) return;
    const link = document.createElement('a');
    link.href = resultImage;
    link.download = 'ai-generated.png';
    link.click();
  };

  return (
    <div className="flex-1 flex flex-col items-center justify-center px-4 pb-[calc(2rem + env(safe-area-inset-bottom, 0px))] max-w-lg mx-auto w-full min-h-0">
      {/* Preview Area */}
      <div className="w-full aspect-square mb-6 relative group">
        <AnimatePresence mode="wait">
          {resultImage ? (
            <motion.div
              key="image"
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="w-full h-full relative"
            >
              <img src={resultImage} alt="Generated Art" className="w-full h-full object-cover rounded-[32px] shadow-2xl border border-white/10" />
              <button onClick={handleDownload}
                className="absolute bottom-4 right-4 w-12 h-12 bg-black/40 backdrop-blur-xl rounded-full flex items-center justify-center text-white hover:bg-black/60 transition-all opacity-0 group-hover:opacity-100 shadow-xl border border-white/10">
                <Download className="h-5 w-5" />
              </button>
            </motion.div>
          ) : (
            <motion.div
              key="empty"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="w-full h-full rounded-[32px] border border-dashed border-white/10 bg-white/[0.02] backdrop-blur-sm flex flex-col items-center justify-center text-muted-foreground gap-4 overflow-hidden relative"
            >
              <div className={`w-20 h-20 rounded-full bg-white/[0.05] backdrop-blur-xl border border-white/10 flex items-center justify-center shadow-2xl relative z-10 ${isGenerating ? 'animate-pulse' : ''}`}>
                {isGenerating ? <Loader2 className="h-8 w-8 animate-spin text-purple-400" /> : <Wand2 className="h-8 w-8 text-purple-400/50" />}
              </div>
              <div className="text-center px-6 relative z-10">
                <p className="text-sm font-bold text-foreground/80 mb-1">
                  {isGenerating ? 'Mo\'jiza yuz bermoqda...' : 'Art maydoni tayyor'}
                </p>
                <p className="text-[11px] opacity-40 max-w-[200px] leading-relaxed">
                  Tasavvuringizni matn ko'rinishida yozing va men uni rasmga aylantiraman
                </p>
              </div>
              
              {isGenerating && (
                <motion.div 
                  initial={{ width: "0%" }}
                  animate={{ width: "100%" }}
                  transition={{ duration: 10, ease: "linear" }}
                  className="absolute bottom-0 left-0 h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 opacity-50"
                />
              )}

              {errorDetail && (
                <p className="text-[10px] text-destructive/70 px-4 text-center mt-4 max-w-[250px] break-all bg-destructive/5 py-2 rounded-xl">{errorDetail}</p>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Input */}
      <div className="w-full bg-white/[0.03] backdrop-blur-3xl border border-white/5 rounded-[32px] p-3 shadow-2xl flex flex-col gap-3 relative overflow-hidden">
        <textarea value={prompt} onChange={(e) => setPrompt(e.target.value)}
          placeholder="Rasmni tasvirlab bering..."
          rows={2}
          disabled={!canGenerate || isGenerating}
          className="w-full bg-transparent border-none focus:outline-none text-foreground placeholder:text-muted-foreground/40 px-3 py-1 resize-none text-sm font-medium leading-relaxed disabled:opacity-50"
        />
        
        <div className="flex justify-between items-center px-1">
          <div className="flex items-center gap-2">
            <span className="text-[10px] bg-white/[0.05] px-2.5 py-1 rounded-lg text-muted-foreground border border-white/5 font-bold tracking-widest">1:1</span>
            {!canGenerate && timeLeft && (
              <div className="flex items-center gap-1.5 px-2.5 py-1 rounded-lg bg-orange-500/10 border border-orange-500/20 text-orange-400">
                <Clock className="h-3 w-3" />
                <span className="text-[10px] font-bold">{timeLeft}</span>
              </div>
            )}
          </div>

          <button onClick={handleGenerate} disabled={!prompt.trim() || isGenerating || !canGenerate}
            className={cn(
              "px-6 py-2.5 rounded-2xl font-bold text-sm transition-all duration-300 relative overflow-hidden",
              prompt.trim() && !isGenerating && canGenerate
                ? 'bg-foreground text-background hover:scale-105 active:scale-95 shadow-xl'
                : 'bg-white/[0.05] text-muted-foreground/40 cursor-not-allowed'
            )}>
            {isGenerating ? (
              <div className="flex items-center gap-2">
                <Loader2 className="h-4 w-4 animate-spin" />
                <span>Kuting...</span>
              </div>
            ) : !canGenerate ? (
              'Limit'
            ) : (
              'Yaratish'
            )}
          </button>
        </div>

        {!canGenerate && (
          <div className="absolute inset-0 bg-background/20 backdrop-blur-[2px] pointer-events-none flex items-center justify-center">
            <div className="bg-background/80 backdrop-blur-xl border border-white/10 rounded-2xl px-4 py-2 shadow-2xl">
              <p className="text-[10px] font-bold text-foreground opacity-80 uppercase tracking-widest">Limit: 15 soatda 1 ta rasm</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AIImageView;

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { toast } from 'sonner';
import { Search, Users, Megaphone, Check } from 'lucide-react';

interface ForwardTarget {
  id: string;
  name: string;
  avatar_url: string | null;
  type: 'user' | 'group' | 'channel';
}

interface ForwardMessageDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  messageContent: string;
  mediaUrl?: string | null;
  mediaType?: string | null;
}

export const ForwardMessageDialog = ({
  open,
  onOpenChange,
  messageContent,
  mediaUrl,
  mediaType,
}: ForwardMessageDialogProps) => {
  const { user } = useAuth();
  const [searchQuery, setSearchQuery] = useState('');
  const [targets, setTargets] = useState<ForwardTarget[]>([]);
  const [selectedTargets, setSelectedTargets] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSending, setIsSending] = useState(false);

  useEffect(() => {
    if (open) {
      fetchTargets();
    }
  }, [open]);

  const fetchTargets = async () => {
    if (!user?.id) return;
    setIsLoading(true);

    try {
      // Fetch conversations (users)
      const { data: conversations } = await supabase
        .from('conversations')
        .select('*')
        .or(`participant1_id.eq.${user.id},participant2_id.eq.${user.id}`);

      const userIds = new Set<string>();
      conversations?.forEach(conv => {
        if (conv.participant1_id !== user.id) userIds.add(conv.participant1_id);
        if (conv.participant2_id !== user.id) userIds.add(conv.participant2_id);
      });

      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, avatar_url')
        .in('id', Array.from(userIds));

      // Fetch groups/channels
      const { data: ownedChats } = await supabase
        .from('group_chats')
        .select('id, name, avatar_url, type')
        .eq('owner_id', user.id);

      const { data: memberOf } = await supabase
        .from('group_members')
        .select('group_id')
        .eq('user_id', user.id);

      const memberGroupIds = memberOf?.map(m => m.group_id) || [];
      let memberChats: any[] = [];
      if (memberGroupIds.length > 0) {
        const { data } = await supabase
          .from('group_chats')
          .select('id, name, avatar_url, type')
          .in('id', memberGroupIds);
        memberChats = data || [];
      }

      const allTargets: ForwardTarget[] = [];

      // Add users
      profiles?.forEach(profile => {
        allTargets.push({
          id: profile.id,
          name: profile.name || 'Foydalanuvchi',
          avatar_url: profile.avatar_url,
          type: 'user'
        });
      });

      // Add groups/channels
      [...(ownedChats || []), ...memberChats].forEach(chat => {
        if (!allTargets.find(t => t.id === chat.id)) {
          allTargets.push({
            id: chat.id,
            name: chat.name,
            avatar_url: chat.avatar_url,
            type: chat.type as 'group' | 'channel'
          });
        }
      });

      setTargets(allTargets);
    } catch (error) {
      console.error('Error fetching targets:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleTarget = (targetId: string) => {
    setSelectedTargets(prev => 
      prev.includes(targetId)
        ? prev.filter(id => id !== targetId)
        : [...prev, targetId]
    );
  };

  const handleForward = async () => {
    if (selectedTargets.length === 0) {
      toast.error('Kimgadir tanlang');
      return;
    }

    setIsSending(true);

    try {
      for (const targetId of selectedTargets) {
        const target = targets.find(t => t.id === targetId);
        if (!target) continue;

        if (target.type === 'user') {
          // Get or create conversation
          const { data: existingConv } = await supabase
            .from('conversations')
            .select('id')
            .or(`and(participant1_id.eq.${user?.id},participant2_id.eq.${targetId}),and(participant1_id.eq.${targetId},participant2_id.eq.${user?.id})`)
            .maybeSingle();

          let conversationId = existingConv?.id;

          if (!conversationId) {
            const { data: newConv } = await supabase
              .from('conversations')
              .insert({
                participant1_id: user?.id,
                participant2_id: targetId
              })
              .select('id')
              .single();
            conversationId = newConv?.id;
          }

          if (conversationId) {
            await supabase
              .from('messages')
              .insert({
                conversation_id: conversationId,
                sender_id: user?.id,
                content: `↪️ Yo'naltirilgan: ${messageContent}`,
                media_url: mediaUrl,
                media_type: mediaType,
                status: 'sent'
              });
          }
        } else {
          // Forward to group/channel
          await supabase
            .from('group_messages')
            .insert({
              group_id: targetId,
              sender_id: user?.id,
              content: `↪️ Yo'naltirilgan: ${messageContent}`,
              media_url: mediaUrl,
              media_type: mediaType
            });
        }
      }

      toast.success('Xabar yo\'naltirildi');
      onOpenChange(false);
      setSelectedTargets([]);
    } catch (error) {
      console.error('Error forwarding message:', error);
      toast.error('Xatolik yuz berdi');
    } finally {
      setIsSending(false);
    }
  };

  const getInitials = (name: string) => {
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  const filteredTargets = targets.filter(target =>
    target.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Xabarni yo'naltirish</DialogTitle>
        </DialogHeader>

        <div className="relative mb-4">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Qidirish..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-10"
          />
        </div>

        <ScrollArea className="h-[300px]">
          {isLoading ? (
            <p className="text-center text-muted-foreground py-8">Yuklanmoqda...</p>
          ) : filteredTargets.length === 0 ? (
            <p className="text-center text-muted-foreground py-8">Topilmadi</p>
          ) : (
            <div className="space-y-1">
              {filteredTargets.map((target) => (
                <div
                  key={target.id}
                  className={`flex items-center gap-3 p-3 rounded-lg cursor-pointer transition-colors ${
                    selectedTargets.includes(target.id)
                      ? 'bg-primary/10'
                      : 'hover:bg-muted'
                  }`}
                  onClick={() => toggleTarget(target.id)}
                >
                  <Avatar className="h-10 w-10">
                    <AvatarImage src={target.avatar_url || undefined} />
                    <AvatarFallback className="bg-primary/10">
                      {target.type === 'group' ? (
                        <Users className="h-5 w-5 text-primary" />
                      ) : target.type === 'channel' ? (
                        <Megaphone className="h-5 w-5 text-primary" />
                      ) : (
                        getInitials(target.name)
                      )}
                    </AvatarFallback>
                  </Avatar>
                  <div className="flex-1 min-w-0">
                    <p className="font-medium truncate">{target.name}</p>
                    <p className="text-xs text-muted-foreground">
                      {target.type === 'group' ? 'Guruh' : target.type === 'channel' ? 'Kanal' : 'Foydalanuvchi'}
                    </p>
                  </div>
                  {selectedTargets.includes(target.id) && (
                    <Check className="h-5 w-5 text-primary" />
                  )}
                </div>
              ))}
            </div>
          )}
        </ScrollArea>

        <div className="flex justify-end gap-2 mt-4">
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            Bekor qilish
          </Button>
          <Button 
            onClick={handleForward} 
            disabled={selectedTargets.length === 0 || isSending}
          >
            {isSending ? 'Yuborilmoqda...' : `Yuborish (${selectedTargets.length})`}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
};

import { useEffect, useRef, useState, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Video, VideoOff, Mic, MicOff, PhoneOff, Maximize2, Minimize2, SwitchCamera } from 'lucide-react';
import { DailyCall, DailyParticipant } from '@daily-co/daily-js';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

type LayoutMode = 'pip' | 'split';

interface VideoCallUIProps {
  callObject: DailyCall;
  remoteParticipant: DailyParticipant | null;
  cameraOn: boolean;
  micOn: boolean;
  onToggleCamera: () => void;
  onToggleMic: () => void;
  onEndCall: () => void;
}

export const VideoCallUI = ({
  callObject,
  remoteParticipant,
  cameraOn,
  micOn,
  onToggleCamera,
  onToggleMic,
  onEndCall,
}: VideoCallUIProps) => {
  const localVideoRef = useRef<HTMLVideoElement>(null);
  const remoteVideoRef = useRef<HTMLVideoElement>(null);
  
  const [layoutMode, setLayoutMode] = useState<LayoutMode>('pip');
  const [showControls, setShowControls] = useState(true);
  const hideTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  
  // PiP drag state
  const [pipPosition, setPipPosition] = useState({ x: 16, y: 16 });
  const [pipSize, setPipSize] = useState({ w: 120, h: 170 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0, px: 0, py: 0 });
  
  // Swapped: false = local in PiP (small), remote fullscreen; true = remote in PiP, local fullscreen
  const [swapped, setSwapped] = useState(false);

  // Auto-hide controls
  const resetHideTimer = useCallback(() => {
    setShowControls(true);
    if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    hideTimerRef.current = setTimeout(() => setShowControls(false), 3000);
  }, []);

  useEffect(() => {
    resetHideTimer();
    return () => { if (hideTimerRef.current) clearTimeout(hideTimerRef.current); };
  }, [resetHideTimer]);

  // Attach local video track
  useEffect(() => {
    if (!callObject) return;

    const attachLocal = () => {
      const lp = callObject.participants()?.local;
      if (lp?.videoTrack && localVideoRef.current) {
        const stream = new MediaStream([lp.videoTrack]);
        if (localVideoRef.current.srcObject !== stream) {
          localVideoRef.current.srcObject = stream;
        }
      } else if (localVideoRef.current && !lp?.video) {
        localVideoRef.current.srcObject = null;
      }
    };

    attachLocal();
    
    const handler = (evt: unknown) => {
      const p = (evt as { participant?: { local?: boolean } } | null)?.participant;
      if (p?.local) attachLocal();
    };
    
    callObject.on('participant-updated', handler);
    return () => { callObject.off('participant-updated', handler); };
  }, [callObject, layoutMode, swapped]);

  // Attach remote video + audio tracks
  useEffect(() => {
    if (remoteParticipant?.videoTrack && remoteVideoRef.current) {
      remoteVideoRef.current.srcObject = new MediaStream([remoteParticipant.videoTrack]);
    } else if (remoteVideoRef.current && !remoteParticipant?.video) {
      remoteVideoRef.current.srcObject = null;
    }
    
    if (remoteParticipant?.audioTrack) {
      let audioEl = document.getElementById('remote-audio') as HTMLAudioElement;
      if (!audioEl) {
        audioEl = document.createElement('audio');
        audioEl.id = 'remote-audio';
        audioEl.autoplay = true;
        document.body.appendChild(audioEl);
      }
      audioEl.srcObject = new MediaStream([remoteParticipant.audioTrack]);
    }

    return () => {
      const el = document.getElementById('remote-audio');
      if (el) el.remove();
    };
  }, [remoteParticipant?.videoTrack, remoteParticipant?.audioTrack, layoutMode, swapped]);

  // PiP Drag
  const handlePipPointerDown = (e: React.PointerEvent) => {
    if (layoutMode !== 'pip') return;
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX, y: e.clientY, px: pipPosition.x, py: pipPosition.y };
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handlePipPointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    const dx = e.clientX - dragStartRef.current.x;
    const dy = e.clientY - dragStartRef.current.y;
    const maxX = window.innerWidth - pipSize.w - 8;
    const maxY = window.innerHeight - pipSize.h - 8;
    setPipPosition({
      x: Math.max(8, Math.min(maxX, dragStartRef.current.px + dx)),
      y: Math.max(8, Math.min(maxY, dragStartRef.current.py + dy)),
    });
  };

  const handlePipPointerUp = () => setIsDragging(false);

  const handleFlipCamera = useCallback(async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!callObject) return;
    try {
      // Use Daily.co's built-in cycleCamera() which is more reliable for front/back switching
      await callObject.cycleCamera();
    } catch (err) {
      console.error('Camera flip error:', err);
      toast.error("Kamerani almashtirishda xatolik");
    }
  }, [callObject]);

  // Who is fullscreen vs PiP
  const fullscreenIsRemote = !swapped;
  const fullscreenHasVideo = fullscreenIsRemote ? !!remoteParticipant?.video : cameraOn;
  const pipHasVideo = fullscreenIsRemote ? cameraOn : !!remoteParticipant?.video;

  const renderVideoElement = (
    isLocal: boolean,
    hasVideo: boolean,
    className: string,
    label?: string
  ) => {
    const ref = isLocal ? localVideoRef : remoteVideoRef;
    return (
      <div className={cn("bg-muted flex items-center justify-center overflow-hidden", className)}>
        {hasVideo ? (
          <video
            ref={ref}
            autoPlay
            playsInline
            muted={isLocal}
            className={cn("w-full h-full object-cover", isLocal && "scale-x-[-1]")}
          />
        ) : (
          <div className="text-center text-muted-foreground">
            <div className="w-16 h-16 bg-muted-foreground/20 rounded-full flex items-center justify-center mx-auto mb-2">
              <VideoOff className="h-8 w-8" />
            </div>
            {label && <p className="text-xs">{label}</p>}
          </div>
        )}
      </div>
    );
  };

  return (
    <div 
      className="fixed inset-0 z-50 bg-background" 
      onClick={resetHideTimer}
      onTouchStart={resetHideTimer}
    >
      {layoutMode === 'split' ? (
        <div className="flex flex-col h-full">
          {renderVideoElement(!fullscreenIsRemote, fullscreenIsRemote ? !!remoteParticipant?.video : cameraOn, "flex-1", fullscreenIsRemote ? "Kutilmoqda..." : undefined)}
          <div className="h-px bg-border" />
          {renderVideoElement(fullscreenIsRemote, fullscreenIsRemote ? cameraOn : !!remoteParticipant?.video, "flex-1", !fullscreenIsRemote ? "Kutilmoqda..." : undefined)}
        </div>
      ) : (
        <>
          {/* Fullscreen */}
          {renderVideoElement(!fullscreenIsRemote, fullscreenHasVideo, "absolute inset-0", fullscreenIsRemote ? "Kutilmoqda..." : undefined)}

          {/* PiP Window */}
          <div
            className="absolute rounded-2xl overflow-hidden shadow-2xl border-2 border-background/50 cursor-grab active:cursor-grabbing touch-none"
            style={{
              left: pipPosition.x,
              top: pipPosition.y,
              width: pipSize.w,
              height: pipSize.h,
              zIndex: 10,
            }}
            onPointerDown={handlePipPointerDown}
            onPointerMove={handlePipPointerMove}
            onPointerUp={handlePipPointerUp}
          >
            {renderVideoElement(fullscreenIsRemote, pipHasVideo, "w-full h-full")}
          </div>
        </>
      )}

      {/* Controls */}
      <div 
        className={cn(
          "absolute bottom-0 left-0 right-0 transition-all duration-300",
          showControls ? "opacity-100 translate-y-0" : "opacity-0 translate-y-4 pointer-events-none"
        )}
      >
        <div className="bg-gradient-to-t from-black/60 to-transparent pt-16 pb-8 px-4">
          <div className="flex items-center justify-center gap-3">
            <Button
              variant="ghost"
              size="icon"
              className={cn(
                "h-12 w-12 rounded-full backdrop-blur-md",
                cameraOn ? "bg-white/20 text-white" : "bg-red-500/80 text-white"
              )}
              onClick={(e) => { e.stopPropagation(); onToggleCamera(); }}
            >
              {cameraOn ? <Video className="h-5 w-5" /> : <VideoOff className="h-5 w-5" />}
            </Button>

            <Button
              variant="ghost"
              size="icon"
              className={cn(
                "h-12 w-12 rounded-full backdrop-blur-md",
                micOn ? "bg-white/20 text-white" : "bg-red-500/80 text-white"
              )}
              onClick={(e) => { e.stopPropagation(); onToggleMic(); }}
            >
              {micOn ? <Mic className="h-5 w-5" /> : <MicOff className="h-5 w-5" />}
            </Button>

            <Button
              variant="ghost"
              size="icon"
              className="h-14 w-14 rounded-full bg-destructive text-destructive-foreground"
              onClick={(e) => { e.stopPropagation(); onEndCall(); }}
            >
              <PhoneOff className="h-6 w-6" />
            </Button>

            <Button
              variant="ghost"
              size="icon"
              className="h-12 w-12 rounded-full bg-white/20 text-white backdrop-blur-md"
              onClick={(e) => {
                e.stopPropagation();
                setLayoutMode(prev => prev === 'pip' ? 'split' : 'pip');
              }}
            >
              {layoutMode === 'pip' ? <Maximize2 className="h-5 w-5" /> : <Minimize2 className="h-5 w-5" />}
            </Button>

            <Button
              variant="ghost"
              size="icon"
              className="h-12 w-12 rounded-full bg-white/20 text-white backdrop-blur-md"
              onClick={handleFlipCamera}
            >
              <SwitchCamera className="h-5 w-5" />
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

import { useState, useRef, useEffect, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Slider } from '@/components/ui/slider';
import { Check, RotateCcw, Sun, Contrast, Droplets, Palette } from 'lucide-react';
import { cn } from '@/lib/utils';

interface ImageEditorProps {
  src: string;
  onSave: (blob: Blob) => void;
  onCancel: () => void;
}

interface Filters {
  brightness: number;
  contrast: number;
  saturation: number;
}

const PRESETS: { name: string; filters: Filters }[] = [
  { name: 'Original', filters: { brightness: 100, contrast: 100, saturation: 100 } },
  { name: 'Vivid', filters: { brightness: 105, contrast: 115, saturation: 140 } },
  { name: 'Warm', filters: { brightness: 108, contrast: 105, saturation: 120 } },
  { name: 'Cool', filters: { brightness: 100, contrast: 110, saturation: 80 } },
  { name: 'B&W', filters: { brightness: 105, contrast: 120, saturation: 0 } },
  { name: 'Fade', filters: { brightness: 110, contrast: 85, saturation: 90 } },
];

const ImageEditor = ({ src, onSave, onCancel }: ImageEditorProps) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const imgRef = useRef<HTMLImageElement | null>(null);
  const [filters, setFilters] = useState<Filters>({ brightness: 100, contrast: 100, saturation: 100 });
  const [activePreset, setActivePreset] = useState(0);
  const [showSliders, setShowSliders] = useState(false);

  useEffect(() => {
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => {
      imgRef.current = img;
      drawImage();
    };
    img.src = src;
  }, [src]);

  const drawImage = useCallback(() => {
    const canvas = canvasRef.current;
    const img = imgRef.current;
    if (!canvas || !img) return;

    const maxW = 1080;
    const maxH = 1080;
    let w = img.naturalWidth;
    let h = img.naturalHeight;
    if (w > maxW || h > maxH) {
      const ratio = Math.min(maxW / w, maxH / h);
      w = Math.round(w * ratio);
      h = Math.round(h * ratio);
    }
    canvas.width = w;
    canvas.height = h;

    const ctx = canvas.getContext('2d')!;
    ctx.filter = `brightness(${filters.brightness}%) contrast(${filters.contrast}%) saturate(${filters.saturation}%)`;
    ctx.drawImage(img, 0, 0, w, h);
  }, [filters]);

  useEffect(() => {
    drawImage();
  }, [drawImage]);

  const applyPreset = (idx: number) => {
    setActivePreset(idx);
    setFilters(PRESETS[idx].filters);
  };

  const resetFilters = () => {
    setFilters({ brightness: 100, contrast: 100, saturation: 100 });
    setActivePreset(0);
  };

  const handleSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    canvas.toBlob(
      (blob) => {
        if (blob) onSave(blob);
      },
      'image/webp',
      0.9
    );
  };

  const sliders = [
    { key: 'brightness' as const, icon: Sun, label: 'Yorqinlik' },
    { key: 'contrast' as const, icon: Contrast, label: 'Kontrast' },
    { key: 'saturation' as const, icon: Droplets, label: 'To\'yinganlik' },
  ];

  return (
    <div className="space-y-4">
      {/* Canvas preview */}
      <div className="relative rounded-xl overflow-hidden bg-muted flex items-center justify-center max-h-[50vh]">
        <canvas
          ref={canvasRef}
          className="max-w-full max-h-[50vh] object-contain"
        />
      </div>

      {/* Filter presets */}
      <div className="flex gap-2 overflow-x-auto pb-1 px-1">
        {PRESETS.map((preset, i) => (
          <button
            key={preset.name}
            onClick={() => applyPreset(i)}
            className={cn(
              'flex-shrink-0 text-center space-y-1',
              activePreset === i && 'ring-2 ring-primary rounded-xl'
            )}
          >
            <div className="w-16 h-16 rounded-lg overflow-hidden bg-muted">
              <img
                src={src}
                alt={preset.name}
                className="w-full h-full object-cover"
                style={{
                  filter: `brightness(${preset.filters.brightness}%) contrast(${preset.filters.contrast}%) saturate(${preset.filters.saturation}%)`,
                }}
              />
            </div>
            <p className="text-[10px] text-muted-foreground font-medium">{preset.name}</p>
          </button>
        ))}
      </div>

      {/* Toggle sliders */}
      <Button
        variant="ghost"
        size="sm"
        className="w-full gap-2"
        onClick={() => setShowSliders(!showSliders)}
      >
        <Palette className="h-4 w-4" />
        {showSliders ? 'Yashirish' : 'Qo\'lda sozlash'}
      </Button>

      {/* Manual sliders */}
      {showSliders && (
        <div className="space-y-3 p-3 rounded-xl border border-border bg-muted/30">
          {sliders.map(({ key, icon: Icon, label }) => (
            <div key={key} className="space-y-1">
              <div className="flex items-center justify-between text-xs">
                <span className="flex items-center gap-1.5 text-muted-foreground">
                  <Icon className="h-3.5 w-3.5" />
                  {label}
                </span>
                <span className="font-mono text-muted-foreground">{filters[key]}%</span>
              </div>
              <Slider
                min={0}
                max={200}
                step={1}
                value={[filters[key]]}
                onValueChange={([v]) => {
                  setFilters((f) => ({ ...f, [key]: v }));
                  setActivePreset(-1);
                }}
              />
            </div>
          ))}
          <Button variant="ghost" size="sm" className="w-full gap-1" onClick={resetFilters}>
            <RotateCcw className="h-3.5 w-3.5" />
            Asliga qaytarish
          </Button>
        </div>
      )}

      {/* Actions */}
      <div className="flex gap-3">
        <Button variant="outline" className="flex-1 rounded-xl" onClick={onCancel}>
          Bekor qilish
        </Button>
        <Button className="flex-1 rounded-xl" onClick={handleSave}>
          <Check className="h-4 w-4 mr-1" />
          Saqlash
        </Button>
      </div>
    </div>
  );
};

export default ImageEditor;

