      mediaRecorderRef.current.stop();
      setIsRecording(false);
      clearInterval(recordTimerRef.current);
      clearTimeout(musicStopTimerRef.current);
      
      // Stop music when recording stops
      if (musicAudioRef.current && isMusicPlaying) {
