      return;
    }

    setIsCapturing(true);
    captureTimerRef.current = window.setTimeout(() => startRecording(), 500);
  }, [captureMode, isRecording, startRecording]);

  const handleVideoToggleCapture = useCallback(() => {
    if (isRecording) stopRecording();
