    const currentLen = itemsRef.current.length;
    const remaining = maxItems - currentLen;
    if (remaining <= 0) {
      e.target.value = '';
      return;
    }

    const newMedias: CapturedMedia[] = Array.from(files).slice(0, remaining).map((file, i) => {
      const isVideo = file.type.startsWith('video/');
