      };
    });

    const newItems: EditableItem[] = newMedias.map(media => ({
      media,
      filter: 'original',
      texts: [],
      images: [],
      strokes: [],
      mediaTransform: { x: 0, y: 0, scale: 1, rotation: 0 },
