    setItems(prev => [...prev, ...newItems]);
    setActiveIndex(currentLen + newItems.length - 1);
    setFocusedMediaId(newMedias[newMedias.length - 1].id);
    setTrayOpen(false);

    e.target.value = '';
  }, [maxItems]);

  const addGif = useCallback((gif: GiphyItem) => {
    if (!active) return;
    updateActive({
      images: [
        ...active.images,
        {
          id: gif.id + '_' + Date.now(),
