                {/* Add Child button - faqat jufti bor bo'lsa ko'rsatiladi (JUFT o'rniga) */}
                {hasSpouse && canAddChild && onAddChild && (
                  <Button
                    variant="outline"
                    size="sm"
                    className="flex flex-col h-auto py-2 bg-emerald-500/10 hover:bg-emerald-500/20 border-emerald-500/30"
