// Inline Add Member Dialog
interface AddMemberInlineDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onComplete: (userIds: string[]) => void;
  existingMemberIds: string[];
}

const AddMemberInlineDialog = ({ open, onOpenChange, onComplete, existingMemberIds }: AddMemberInlineDialogProps) => {
  const { user } = useAuth();
  const [searchQuery, setSearchQuery] = useState('');
  const [allUsers, setAllUsers] = useState<{ id: string; name: string | null; username: string | null; avatar_url: string | null }[]>([]);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (!user?.id || !open) return;
    setIsLoading(true);
    const fetchUsers = async () => {
      try {
        // Get followers + following
        const [{ data: frs }, { data: fng }] = await Promise.all([
          supabase.from('follows').select('follower_id').eq('following_id', user.id),
          supabase.from('follows').select('following_id').eq('follower_id', user.id),
        ]);
        const ids = [...new Set([...(frs || []).map(f => f.follower_id), ...(fng || []).map(f => f.following_id)])];
        const availableIds = ids.filter(id => !existingMemberIds.includes(id));
        if (availableIds.length > 0) {
          const { data: profiles } = await supabase.from('profiles').select('id, name, username, avatar_url').in('id', availableIds);
          setAllUsers(profiles || []);
        } else {
          setAllUsers([]);
        }
      } catch { setAllUsers([]); }
      setIsLoading(false);
    };
    fetchUsers();
  }, [user?.id, open, existingMemberIds]);

  const filteredUsers = allUsers.filter(u => {
    if (!searchQuery) return true;
    const q = searchQuery.toLowerCase();
    return (u.name?.toLowerCase().includes(q)) || (u.username?.toLowerCase().includes(q));
  });

  const toggleUser = (uid: string) => {
    const s = new Set(selectedIds);
    if (s.has(uid)) s.delete(uid); else s.add(uid);
    setSelectedIds(s);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="w-[calc(100vw-2rem)] max-w-md max-h-[90vh] flex flex-col p-0 overflow-hidden">
        <DialogHeader>
          <DialogTitle className="flex items-center justify-between">
            <span>A'zo qo'shish</span>
            {selectedIds.size > 0 && <span className="text-sm font-normal text-primary">{selectedIds.size} tanlandi</span>}
          </DialogTitle>
        </DialogHeader>
        <div className="relative px-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input placeholder="Qidirish..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="pl-10 rounded-xl" />
        </div>
        <ScrollArea className="flex-1 -mx-6 px-6">
          <div className="space-y-1">
            {isLoading ? (
              <p className="text-center py-8 text-muted-foreground text-sm">Yuklanmoqda...</p>
            ) : filteredUsers.length === 0 ? (
              <p className="text-center py-8 text-muted-foreground text-sm">
                {searchQuery ? 'Hech kim topilmadi' : 'Qo\'shish uchun foydalanuvchi yo\'q'}
              </p>
            ) : (
              filteredUsers.map(u => (
                <div key={u.id} onClick={() => toggleUser(u.id)}
                  className="flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted/50 cursor-pointer transition-colors">
                  <Avatar className="h-10 w-10">
                    <AvatarImage src={u.avatar_url || undefined} />
                    <AvatarFallback className="text-xs">{(u.name || 'U')[0]}</AvatarFallback>
                  </Avatar>
                  <div className="flex-1 min-w-0">
                    <p className="font-medium text-sm truncate">{u.name || 'Foydalanuvchi'}</p>
                    <div className="truncate">
                      <StarUsername username={u.username || 'username'} />
                    </div>
                  </div>
                  <Checkbox checked={selectedIds.has(u.id)} onCheckedChange={() => toggleUser(u.id)} />
                </div>
              ))
            )}
          </div>
        </ScrollArea>
        <div className="flex justify-end gap-2 px-6 pb-4 pt-3 border-t border-border/50">
          <Button variant="ghost" onClick={() => { onOpenChange(false); setSelectedIds(new Set()); }} className="rounded-xl">
            Bekor
          </Button>
          <Button onClick={() => { onComplete(Array.from(selectedIds)); setSelectedIds(new Set()); }}
            disabled={selectedIds.size === 0}
            className="rounded-xl bg-gradient-to-r from-[hsl(217,91%,60%)] to-[hsl(263,70%,50%)] text-white">
            Qo'shish ({selectedIds.size})
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
};

import { RefObject, useMemo } from "react";
import { Virtuoso } from "react-virtuoso";
import { TreePostCard } from "@/components/feed/TreePostCard";
import { PostCard } from "@/components/feed/PostCard";
import { EndOfFeed } from "@/components/feed/EndOfFeed";
import { Post } from "@/types";
import { FeedTreePost } from "@/hooks/useTreeFeed";

type FeedItem =
  | { kind: 'post'; data: Post; created_at: string }
  | { kind: 'tree'; data: FeedTreePost; created_at: string };

interface FeedListLayoutProps {
  posts: Post[];
  treePosts: FeedTreePost[];
  isLoadingMore: boolean;
  hasMore: boolean;
  t: (key: string) => string;
  scrollContainerRef: RefObject<HTMLDivElement>;
  loadMoreSentinelRef: RefObject<HTMLDivElement>;
  openPostViewer: (index: number) => void;
}

export const FeedListLayout = ({
  posts,
  treePosts,
  isLoadingMore,
  hasMore,
  t,
  scrollContainerRef,
  loadMoreSentinelRef,
  openPostViewer
}: FeedListLayoutProps) => {
  // Merge tree posts and regular posts into one list sorted by created_at desc
  const unified = useMemo(() => {
    const items: FeedItem[] = [
      ...posts.map((p): FeedItem => ({ kind: 'post', data: p, created_at: p.created_at })),
      ...treePosts.map((tp): FeedItem => ({ kind: 'tree', data: tp, created_at: tp.created_at })),
    ];
    items.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
    return items;
  }, [posts, treePosts]);

  // Build a mapping from unified index to the original posts-only index
  // (needed so openPostViewer receives the correct index into the posts array)
  const postIndexMap = useMemo(() => {
    const map = new Map<number, number>();
    let postIdx = 0;
    // posts are sorted by created_at desc already, same order as in the unified list
    // We need to iterate unified and track the original post index
    const postOrder = posts.map(p => p.id);
    const postIdToIdx = new Map(postOrder.map((id, i) => [id, i]));
    unified.forEach((item, i) => {
      if (item.kind === 'post') {
        map.set(i, postIdToIdx.get((item.data as Post).id) ?? 0);
      }
    });
    return map;
  }, [unified, posts]);

  return (
    <div ref={scrollContainerRef} className="space-y-3 pb-20 px-[5px]">
      <Virtuoso
        useWindowScroll
        data={unified}
        itemContent={(index, item) => (
          <div className="mb-3">
            {item.kind === 'tree' ? (
              <TreePostCard
                post={item.data as FeedTreePost}
                author={(item.data as FeedTreePost).author}
                index={index}
              />
            ) : (
              <PostCard
                post={item.data as Post}
                onMediaClick={() => openPostViewer(postIndexMap.get(index) ?? 0)}
                index={index}
              />
            )}
          </div>
        )}
      />

      <div ref={loadMoreSentinelRef} className="h-4 min-h-4" aria-hidden />
      {isLoadingMore && <div className="text-center py-4 text-muted-foreground text-sm">{t('loading')}</div>}
      {!hasMore && posts.length > 0 && <EndOfFeed />}
    </div>
  );
};

import { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import { Button } from '@/components/ui/button';

const STORAGE_KEY = 'avlodona:cookie-consent:v1';
type ConsentValue = 'accepted' | 'necessary';

const applyConsent = (consent: ConsentValue) => {
  try {
    (window as any).__avlodonaCookieConsent = consent;
    (window as any).__avlodonaAllowAnalytics = consent === 'accepted';
    (window as any).__avlodonaAllowYoutubeCookies = consent === 'accepted';
    (window as any).__avlodonaAllowDailyTracking = consent === 'accepted';
    window.dispatchEvent(new CustomEvent('avlodona:cookie-consent', { detail: { consent } }));
  } catch {
    // ignore
  }
};

export const CookieBanner = () => {
  const [open, setOpen] = useState(false);

  const storedConsent = useMemo(() => {
    try {
      const value = localStorage.getItem(STORAGE_KEY);
      if (value === 'accepted' || value === 'necessary') return value;
      return null;
    } catch {
      return null;
    }
  }, []);

  useEffect(() => {
    if (storedConsent) {
      applyConsent(storedConsent);
      setOpen(false);
      return;
    }
    setOpen(true);
  }, [storedConsent]);

  const acceptAll = () => {
    try {
      localStorage.setItem(STORAGE_KEY, 'accepted');
    } catch {}
    applyConsent('accepted');
    setOpen(false);
  };

  const necessaryOnly = () => {
    try {
      localStorage.setItem(STORAGE_KEY, 'necessary');
    } catch {}
    applyConsent('necessary');
    setOpen(false);
  };

  if (!open) return null;

  return (
    <div className="fixed bottom-3 left-3 right-3 z-[90]">
      <div className="max-w-lg mx-auto rounded-2xl border border-white/10 bg-background/80 backdrop-blur-xl shadow-[0_16px_50px_rgba(0,0,0,0.25)] px-4 py-3 flex flex-col sm:flex-row sm:items-center gap-3 animate-in fade-in slide-in-from-bottom-3 duration-300">
        <p className="text-xs text-white/70 flex-1 leading-relaxed">
          We use cookies. You can accept all cookies, or allow necessary cookies only.
        </p>
        <div className="flex items-center gap-2 justify-end flex-wrap">
          <Link
            to="/privacy-policy#cookies"
            className="text-xs font-semibold text-white/70 hover:text-white underline-offset-4 hover:underline whitespace-nowrap"
          >
            Learn More
          </Link>
          <Button size="sm" variant="outline" className="rounded-xl" onClick={necessaryOnly}>
            Necessary Only
          </Button>
          <Button size="sm" className="rounded-xl" onClick={acceptAll}>
            Accept All
          </Button>
        </div>
      </div>
    </div>
  );
};

