export const PushNotification = () => {
  const { user } = useAuth();
  const location = useLocation();
  const locationRef = useRef(location.pathname);
  useEffect(() => { locationRef.current = location.pathname; }, [location.pathname]);

  const [alerts, setAlerts] = useState<AlertData[]>([]);
  const timers = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());

  const dismiss = useCallback((id: string) => {
    clearTimeout(timers.current.get(id));
    timers.current.delete(id);
    setAlerts(prev => prev.filter(a => a.id !== id));
  }, []);

  const addAlert = useCallback((alert: AlertData) => {
    setAlerts(prev => {
      // Replace same-id or same-sender message (de-dup)
      const filtered = prev.filter(a => a.id !== alert.id && !(a.kind === 'message' && a.actor.id === alert.actor.id));
      return [alert, ...filtered].slice(0, 3); // max 3 stacked
    });
    // Auto-dismiss after 6s
    const t = setTimeout(() => dismiss(alert.id), 6000);
    timers.current.set(alert.id, t);
  }, [dismiss]);

  // Listen to incoming-message custom events
  useEffect(() => {
    const handler = (e: Event) => {
      const ce = e as CustomEvent<{
        id: string;
        conversationId: string;
        sender: ActorProfile;
        preview: string;
        mediaThumb: string | null;
        mediaType: string | null;
      }>;
      const d = ce.detail;

      // Don't show if user is already in this chat
      if (locationRef.current === `/chat/${d.sender.id}`) return;

      addAlert({
        id: d.id,
        kind: 'message',
        type: d.mediaType || 'text',
        actor: d.sender,
        text: d.preview,
        mediaThumb: d.mediaThumb,
        conversationId: d.conversationId,
        created_at: new Date().toISOString(),
      });
    };
    window.addEventListener('avlodona:incoming-message', handler as EventListener);
    return () => window.removeEventListener('avlodona:incoming-message', handler as EventListener);
  }, [addAlert]);

  // Listen to Supabase notifications table
  useEffect(() => {
    if (!user?.id) return;

    const channel = supabase
      .channel('push-notifications-v2')
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'notifications',
        filter: `user_id=eq.${user.id}`,
      }, async (payload) => {
        const raw = payload.new as Record<string, unknown>;

        const { data: actor } = await supabase
          .from('profiles')
          .select('id, name, username, avatar_url')
          .eq('id', raw.actor_id as string)
          .single();

        if (!actor) return;

        let mediaThumb: string | null = null;
        if (raw.post_id) {
          const { data: post } = await supabase.from('posts').select('media_urls').eq('id', raw.post_id as string).single();
          if (post?.media_urls?.[0]) mediaThumb = post.media_urls[0];
        }

        addAlert({
          id: raw.id as string,
          kind: 'notification',
          type: raw.type as string,
          actor: actor as ActorProfile,
          text: '',
          mediaThumb,
          created_at: raw.created_at as string,
        });
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [user?.id, addAlert]);

  useEffect(() => {
    return () => { timers.current.forEach(t => clearTimeout(t)); };
  }, []);

  if (alerts.length === 0) return null;

  return (
    <div className="fixed top-3 left-0 right-0 z-[200] flex justify-center px-4 pointer-events-none">
      <div className="w-full max-w-[390px] flex flex-col gap-2 pointer-events-auto">
        <AnimatePresence mode="popLayout">
          {alerts.map((alert) => (
            <motion.div
              key={alert.id}
              layout
              initial={{ y: -90, opacity: 0, scale: 0.88 }}
              animate={{ y: 0, opacity: 1, scale: 1 }}
              exit={{ y: -90, opacity: 0, scale: 0.88 }}
              transition={{ type: 'spring', damping: 22, stiffness: 320, mass: 0.8 }}
            >
              <BannerCard alert={alert} onDismiss={() => dismiss(alert.id)} />
            </motion.div>
          ))}
        </AnimatePresence>
      </div>
    </div>
  );
};

import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Textarea } from '@/components/ui/textarea';
import { Check, Search } from 'lucide-react';
import { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

interface ShareDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  postId?: string;
  shortId?: string;
}

export const ShareDialog = ({ open, onOpenChange, postId, shortId }: ShareDialogProps) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const shareMarker = postId
    ? `[[POST:${postId}]]`
    : shortId
    ? `[[SHORT:${shortId}]]`
    : '';
  const [searchQuery, setSearchQuery] = useState('');
  const [messageText, setMessageText] = useState('');
  const [profiles, setProfiles] = useState<Array<{ id: string; name: string | null; username: string | null; avatar_url: string | null }>>([]);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isLoading, setIsLoading] = useState(false);
  const [isSending, setIsSending] = useState(false);

  useEffect(() => {
    if (!open) return;
    if (!user?.id) return;
    setSearchQuery('');
    setMessageText('');
    setSelectedIds(new Set());
    const fetchProfiles = async () => {
      setIsLoading(true);
      try {
        const [followersRes, followingRes] = await Promise.all([
          supabase.from('follows').select('follower_id').eq('following_id', user.id),
          supabase.from('follows').select('following_id').eq('follower_id', user.id),
        ]);

        const followerIds = (followersRes.data || []).map((r: any) => r.follower_id).filter(Boolean);
        const followingIds = (followingRes.data || []).map((r: any) => r.following_id).filter(Boolean);

        const ids = Array.from(new Set([...followerIds, ...followingIds])).filter((id) => id !== user.id);
        if (ids.length === 0) {
          setProfiles([]);
          return;
        }

        const { data, error } = await supabase
          .from('profiles')
          .select('id, name, username, avatar_url')
          .in('id', ids);

        if (error) throw error;
        setProfiles((data || []) as any);
      } catch (e) {
        console.error('Failed to fetch share targets:', e);
        setProfiles([]);
      } finally {
        setIsLoading(false);
      }
    };

    fetchProfiles();
  }, [open, user?.id]);

  const filteredProfiles = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    if (!q) return profiles;
    return profiles.filter((p) => {
      const name = (p.name || '').toLowerCase();
      const username = (p.username || '').toLowerCase();
      return name.includes(q) || username.includes(q);
    });
  }, [profiles, searchQuery]);

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const getInitials = (name?: string | null) => {
    if (!name) return 'U';
    return name.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2);
  };

  const handleSend = async () => {
    if (!user?.id) return;
    if (!shareMarker) {
      toast.error('Xatolik yuz berdi');
      return;
    }
    if (selectedIds.size === 0) {
      toast.error('Tanlang');
      return;
    }
    if (isSending) return;
    setIsSending(true);
    try {
      const ids = Array.from(selectedIds);
      const trimmedMessage = messageText.trim();
      const contentToSend = trimmedMessage
        ? `${trimmedMessage}\n\n${shareMarker}`
        : `${shareMarker}`;
      for (const targetUserId of ids) {
        const { data: existingConv, error: convErr } = await supabase
          .from('conversations')
          .select('id')
          .or(`and(participant1_id.eq.${user.id},participant2_id.eq.${targetUserId}),and(participant1_id.eq.${targetUserId},participant2_id.eq.${user.id})`)
          .maybeSingle();
        if (convErr) throw convErr;

        let conversationId = existingConv?.id as string | undefined;
        if (!conversationId) {
          const { data: newConv, error: newConvErr } = await supabase
            .from('conversations')
            .insert({ participant1_id: user.id, participant2_id: targetUserId })
            .select('id')
            .single();
          if (newConvErr) throw newConvErr;
          conversationId = newConv?.id;
        }

        if (conversationId) {
          const { error: msgErr } = await supabase
            .from('messages')
            .insert({
              conversation_id: conversationId,
              sender_id: user.id,
              content: contentToSend,
              status: 'sent'
            });
          if (msgErr) throw msgErr;
        }
      }

      toast.success('Yuborildi');
      onOpenChange(false);
      navigate('/messages');
    } catch (e) {
      console.error('Failed to send post:', e);
      toast.error('Xatolik yuz berdi');
    } finally {
      setIsSending(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-lg rounded-3xl p-4">
        <DialogHeader>
          <DialogTitle>Yuborish</DialogTitle>
        </DialogHeader>

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Qidirish..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-10 rounded-2xl"
          />
        </div>

        <ScrollArea className="h-[380px]">
          {isLoading ? (
            <div className="py-10 text-center text-muted-foreground">Yuklanmoqda...</div>
          ) : filteredProfiles.length === 0 ? (
            <div className="py-10 text-center text-muted-foreground">Topilmadi</div>
          ) : (
            <div className="grid grid-cols-3 sm:grid-cols-4 gap-3 pr-3">
              {filteredProfiles.map((p) => {
                const selected = selectedIds.has(p.id);
                return (
                  <button
                    key={p.id}
                    type="button"
                    onClick={() => toggleSelect(p.id)}
                    className="flex flex-col items-center text-center gap-2 p-2 rounded-2xl hover:bg-muted/60 transition-colors"
                  >
                    <div className="relative">
                      <Avatar className="h-16 w-16">
                        <AvatarImage src={p.avatar_url || undefined} />
                        <AvatarFallback>{getInitials(p.name)}</AvatarFallback>
                      </Avatar>
                      {selected && (
                        <div className="absolute -bottom-1 -right-1 h-6 w-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center">
                          <Check className="h-4 w-4" />
                        </div>
                      )}
                    </div>
                    <div className="w-full">
                      <div className="text-sm font-semibold truncate">{p.username ? `@${p.username}` : (p.name || 'User')}</div>
                    </div>
                  </button>
                );
              })}
            </div>
          )}
        </ScrollArea>

        <div className="space-y-2">
          <Textarea
            value={messageText}
            onChange={(e) => setMessageText(e.target.value)}
            placeholder="Xabar yozing..."
            className="min-h-[70px] rounded-2xl"
          />
        </div>

        <div className="flex justify-end gap-2">
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            Bekor qilish
          </Button>
          <Button onClick={handleSend} disabled={selectedIds.size === 0 || isSending}>
            {isSending ? 'Yuborilmoqda...' : `Yuborish (${selectedIds.size})`}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
};

import { useMemo, useRef, useState } from 'react';
import { Plus } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { cn } from '@/lib/utils';
import { type PostCollection } from '@/hooks/usePostCollections';

interface CollectionsFilterProps {
  collections: PostCollection[];
  selectedId: string | null;
  onSelect: (id: string | null) => void;
  isOwner: boolean;
  onCreateCollection?: (name: string, theme?: number) => void;
  onLongPressCollection?: (collection: PostCollection) => void;
}

export function CollectionsFilter({ collections, selectedId, onSelect, isOwner, onCreateCollection, onLongPressCollection }: CollectionsFilterProps) {
  const [showCreate, setShowCreate] = useState(false);
  const [newName, setNewName] = useState('');
  const [newTheme, setNewTheme] = useState(0);

  const colorThemes = useMemo(
    () => [
      { bg: 'from-rose-500/25 via-fuchsia-500/15 to-indigo-500/25', ring: 'ring-rose-500/25' },
      { bg: 'from-emerald-500/25 via-teal-500/15 to-cyan-500/25', ring: 'ring-emerald-500/25' },
      { bg: 'from-amber-500/25 via-orange-500/15 to-rose-500/25', ring: 'ring-amber-500/25' },
      { bg: 'from-sky-500/25 via-blue-500/15 to-violet-500/25', ring: 'ring-sky-500/25' },
      { bg: 'from-violet-500/25 via-purple-500/15 to-pink-500/25', ring: 'ring-violet-500/25' },
      { bg: 'from-lime-500/20 via-green-500/15 to-emerald-500/25', ring: 'ring-lime-500/25' },
    ],
    []
  );

  const pressTimerRef = useRef<number | null>(null);
  const longPressFiredRef = useRef(false);

  if (collections.length === 0 && !isOwner) return null;

  const handleCreate = () => {
    if (!newName.trim()) return;
    onCreateCollection?.(newName.trim(), newTheme);
    setNewName('');
    setShowCreate(false);
  };

  return (
    <>
      <div
        className="flex gap-1.5 overflow-x-auto py-0.5 px-2 mb-1 cf-scroll"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' } as any}
      >
        {collections.map((c, idx) => {
          const themeIndex = Number.isFinite((c as any).theme) ? ((c as any).theme as number) : (idx % colorThemes.length);
          const theme = colorThemes[((themeIndex % colorThemes.length) + colorThemes.length) % colorThemes.length];
          const isActive = selectedId === c.id;
          const postsCount = c.posts_count ?? 0;

          return (
            <button
              key={c.id}
              type="button"
              onPointerDown={() => {
                if (!isOwner || !onLongPressCollection) return;
                longPressFiredRef.current = false;
                if (pressTimerRef.current) window.clearTimeout(pressTimerRef.current);
                pressTimerRef.current = window.setTimeout(() => {
                  longPressFiredRef.current = true;
                  onLongPressCollection(c);
                }, 520);
              }}
              onPointerUp={() => {
                if (pressTimerRef.current) window.clearTimeout(pressTimerRef.current);
                pressTimerRef.current = null;
              }}
              onPointerCancel={() => {
                if (pressTimerRef.current) window.clearTimeout(pressTimerRef.current);
                pressTimerRef.current = null;
              }}
              onContextMenu={(e) => {
                if (!isOwner || !onLongPressCollection) return;
                e.preventDefault();
                onLongPressCollection(c);
              }}
              onClick={() => {
                if (longPressFiredRef.current) {
                  longPressFiredRef.current = false;
                  return;
                }
                onSelect(isActive ? null : c.id);
              }}
              className={cn(
                'flex-shrink-0 relative rounded-full px-3 py-1.5 text-[13px] font-semibold',
                'border border-white/10 backdrop-blur-xl shadow-sm',
                'transition-all duration-200 active:scale-[0.98]',
                isActive
                  ? cn('bg-gradient-to-br text-white ring-2', theme.bg, theme.ring)
                  : cn('bg-gradient-to-br text-foreground/95 hover:text-foreground', theme.bg, 'ring-1 ring-white/10 opacity-85 hover:opacity-100')
              )}
            >
              <span className="flex items-center gap-2">
                <span className="max-w-[8rem] truncate">{c.name}</span>
                {postsCount > 0 && (
                  <span
                    className={cn(
                      'text-[11px] px-2 py-0.5 rounded-full font-bold',
                      isActive ? 'bg-white/15 text-white' : 'bg-white/12 text-foreground/80'
                    )}
                  >
                    {postsCount}
                  </span>
                )}
              </span>
            </button>
          );
        })}

        {isOwner && (
          <button
            onClick={() => setShowCreate(true)}
            className={cn(
              'flex-shrink-0 rounded-full px-3 py-1.5 text-[13px] font-semibold',
              'border border-dashed border-white/20 text-muted-foreground',
              'bg-white/6 hover:bg-white/10 backdrop-blur-xl',
              'flex items-center gap-1.5 transition-colors'
            )}
          >
            <Plus className="h-3.5 w-3.5" />
            Yangi
          </button>
        )}
      </div>

      <style>{`
        .cf-scroll::-webkit-scrollbar { display: none; width: 0; height: 0; }
      `}</style>

      <Dialog open={showCreate} onOpenChange={setShowCreate}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Yangi ro'yxat</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <Input
              value={newName}
              onChange={e => setNewName(e.target.value)}
              placeholder="Ro'yxat nomi"
              onKeyDown={e => e.key === 'Enter' && handleCreate()}
              autoFocus
            />

            <div className="flex items-center gap-2">
              {colorThemes.map((th, idx) => {
                const active = newTheme === idx;
                return (
                  <button
                    key={idx}
                    type="button"
                    onClick={() => setNewTheme(idx)}
                    className={cn(
                      'h-7 w-7 rounded-full bg-gradient-to-br ring-2 transition-all',
                      th.bg,
                      active ? cn('scale-105', th.ring) : 'ring-white/10 hover:scale-105'
                    )}
                    aria-label={`Theme ${idx + 1}`}
                  />
                );
              })}
            </div>

            <Button className="w-full" onClick={handleCreate} disabled={!newName.trim()}>
              Yaratish
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Trash2, Check, Image as ImageIcon } from 'lucide-react';
import { useStoryHighlights, type StoryHighlight } from '@/hooks/useStoryHighlights';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { uploadMedia } from '@/lib/r2Upload';
import { toast } from 'sonner';
import { cn } from '@/lib/utils';

interface HighlightEditorProps {
  highlight?: StoryHighlight;
  open: boolean;
  onClose: () => void;
  isNew?: boolean;
}

interface StoryItem {
  id: string;
  media_url: string;
  media_type: string;
  caption: string | null;
  created_at: string;
}

export function HighlightEditor({ highlight, open, onClose, isNew }: HighlightEditorProps) {
  const { user } = useAuth();
  const { createHighlight, updateHighlight, deleteHighlight, addItemToHighlight, removeItemFromHighlight, fetchHighlights } = useStoryHighlights();
  const [name, setName] = useState(highlight?.name || new Date().getFullYear().toString());
  const [coverUrl, setCoverUrl] = useState(highlight?.cover_url || '');
  const [selectedStoryIds, setSelectedStoryIds] = useState<Set<string>>(new Set(highlight?.items.map(i => i.story_id) || []));
  const [allStories, setAllStories] = useState<StoryItem[]>([]);
  const [activeTab, setActiveTab] = useState<'selected' | 'stories'>('stories');
  const [isSaving, setIsSaving] = useState(false);
  const coverInputRef = useRef<HTMLInputElement>(null);

  // Fetch all past stories (including expired)
  useEffect(() => {
    if (!user || !open) return;
    (async () => {
      const { data } = await supabase
        .from('stories')
        .select('id, media_url, media_type, caption, created_at')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });
      setAllStories(data || []);
    })();
  }, [user, open]);

  const toggleStory = (id: string) => {
    setSelectedStoryIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const handleCoverUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;
    try {
      const url = await uploadMedia(file, 'highlights', user.id);
      setCoverUrl(url);
    } catch (err) {
      toast.error("Rasm yuklashda xatolik");
    }
  };

  const handleSave = async () => {
    if (!name.trim()) { toast.error("Nom kiriting"); return; }
    setIsSaving(true);
    try {
      if (isNew || !highlight) {
        const created = await createHighlight(name, coverUrl || undefined);
        if (created) {
          for (const storyId of selectedStoryIds) {
            const story = allStories.find(s => s.id === storyId);
            if (story) await addItemToHighlight(created.id, story.id, story.media_url, story.media_type, story.caption);
          }
        }
      } else {
        await updateHighlight(highlight.id, { name, cover_url: coverUrl || null });
        // Sync items: remove deselected, add new
        const existingIds = new Set(highlight.items.map(i => i.story_id));
        for (const item of highlight.items) {
          if (!selectedStoryIds.has(item.story_id)) await removeItemFromHighlight(item.id);
        }
        for (const storyId of selectedStoryIds) {
          if (!existingIds.has(storyId)) {
            const story = allStories.find(s => s.id === storyId);
            if (story) await addItemToHighlight(highlight.id, story.id, story.media_url, story.media_type, story.caption);
          }
        }
      }
      await fetchHighlights();
      toast.success("Saqlandi!");
      onClose();
    } catch (err) {
      toast.error("Xatolik yuz berdi");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!highlight) return;
    await deleteHighlight(highlight.id);
    toast.success("O'chirildi");
    onClose();
  };

  const selectedStories = allStories.filter(s => selectedStoryIds.has(s.id));
  const displayCover = coverUrl || selectedStories[0]?.media_url;

  return (
    <Dialog open={open} onOpenChange={() => onClose()}>
      <DialogContent className="max-w-md max-h-[90vh] flex flex-col p-0">
        <DialogHeader className="p-4 pb-2 flex-row items-center justify-between">
          <DialogTitle>{isNew ? 'Yangi highlight' : 'Tahrirlash'}</DialogTitle>
          <div className="flex gap-2">
            {highlight && !isNew && (
              <Button variant="ghost" size="icon" onClick={handleDelete} className="text-destructive">
                <Trash2 className="h-4 w-4" />
              </Button>
            )}
            <Button size="sm" onClick={handleSave} disabled={isSaving}>
              {isSaving ? '...' : 'Saqlash'}
            </Button>
          </div>
        </DialogHeader>

        <div className="px-4 space-y-3">
          {/* Cover preview */}
          <div className="flex flex-col items-center gap-2">
            <button
              onClick={() => coverInputRef.current?.click()}
              className="w-20 h-20 rounded-full border-2 border-dashed border-border overflow-hidden bg-muted flex items-center justify-center"
            >
              {displayCover ? (
                <img src={displayCover} alt="" className="w-full h-full object-cover" />
              ) : (
                <ImageIcon className="h-6 w-6 text-muted-foreground" />
              )}
            </button>
            <button onClick={() => coverInputRef.current?.click()} className="text-xs text-primary">
              Muqova tanlash
            </button>
            <input ref={coverInputRef} type="file" accept="image/*" className="hidden" onChange={handleCoverUpload} />
          </div>

          {/* Name */}
          <Input value={name} onChange={e => setName(e.target.value)} placeholder="Nom" className="text-center font-medium" />
        </div>

        {/* Story selection tabs */}
        <Tabs value={activeTab} onValueChange={v => setActiveTab(v as any)} className="flex-1 flex flex-col min-h-0">
          <TabsList className="mx-4 grid grid-cols-2">
            <TabsTrigger value="selected">Tanlangan ({selectedStoryIds.size})</TabsTrigger>
            <TabsTrigger value="stories">Hikoyalar</TabsTrigger>
          </TabsList>

          <TabsContent value="selected" className="flex-1 overflow-y-auto p-4">
            {selectedStories.length === 0 ? (
              <p className="text-center text-muted-foreground text-sm py-8">Hikoya tanlanmagan</p>
            ) : (
              <div className="grid grid-cols-3 gap-1">
                {selectedStories.map(s => (
                  <StoryThumbnail key={s.id} story={s} selected onClick={() => toggleStory(s.id)} />
                ))}
              </div>
            )}
          </TabsContent>

          <TabsContent value="stories" className="flex-1 overflow-y-auto p-4">
            {allStories.length === 0 ? (
              <p className="text-center text-muted-foreground text-sm py-8">Hikoyalar topilmadi</p>
            ) : (
              <div className="grid grid-cols-3 gap-1">
                {allStories.map(s => (
                  <StoryThumbnail key={s.id} story={s} selected={selectedStoryIds.has(s.id)} onClick={() => toggleStory(s.id)} />
                ))}
              </div>
            )}
          </TabsContent>
        </Tabs>
      </DialogContent>
    </Dialog>
  );
}

function StoryThumbnail({ story, selected, onClick }: { story: StoryItem; selected: boolean; onClick: () => void }) {
  const date = new Date(story.created_at);
  return (
    <button onClick={onClick} className="relative aspect-[9/16] rounded-lg overflow-hidden bg-muted">
      {story.media_type === 'video' ? (
        <video src={story.media_url} className="w-full h-full object-cover" muted />
      ) : (
        <img src={story.media_url} alt="" className="w-full h-full object-cover" />
      )}
      {/* Date badge */}
      <span className="absolute top-1 left-1 text-[10px] bg-black/60 text-white px-1 rounded">
        {date.getDate()}/{date.getMonth() + 1}
      </span>
      {/* Selection indicator */}
      <div className={cn(
        "absolute top-1 right-1 w-5 h-5 rounded-full border-2 flex items-center justify-center",
        selected ? "bg-primary border-primary" : "border-white/70 bg-black/30"
      )}>
        {selected && <Check className="h-3 w-3 text-primary-foreground" />}
      </div>
    </button>
  );
}

import { useState, useEffect } from 'react';
import { type StoryHighlight } from '@/hooks/useStoryHighlights';
import { supabase } from '@/integrations/supabase/client';
import { StoryViewer } from '@/components/stories/StoryViewer';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import type { StoryGroup, Story } from '@/hooks/useStories';

interface HighlightViewerProps {
  highlight: StoryHighlight;
  onClose: () => void;
}

export function HighlightViewer({ highlight, onClose }: HighlightViewerProps) {
  const { user } = useAuth();
  const [groups, setGroups] = useState<StoryGroup[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        setLoading(true);
        const storyIds = (highlight.items || []).map((i) => i.story_id).filter(Boolean);
        if (storyIds.length === 0) {
          setGroups([]);
          return;
        }

        const { data: stories, error: storiesError } = await supabase
          .from('stories')
          .select('*')
          .in('id', storyIds)
          .order('created_at', { ascending: true });

        if (storiesError) throw storiesError;
        if (!stories || stories.length === 0) {
          setGroups([]);
          return;
        }

        const ownerId = stories[0].user_id as string;
        const { data: profiles } = await supabase
          .from('profiles')
          .select('id, name, username, avatar_url')
          .in('id', [ownerId]);

        const authorProfile = profiles?.[0];

        const viewerId = user?.id;
        const [viewsRes, likesRes] = await Promise.all([
          viewerId
            ? supabase.from('story_views').select('story_id').eq('viewer_id', viewerId).in('story_id', storyIds)
            : Promise.resolve({ data: [] as any[] }),
          viewerId
            ? supabase.from('story_likes').select('story_id').eq('user_id', viewerId).in('story_id', storyIds)
            : Promise.resolve({ data: [] as any[] }),
        ]);

        const viewedStoryIds = new Set((viewsRes as any)?.data?.map((v: any) => v.story_id) || []);
        const likedStoryIds = new Set((likesRes as any)?.data?.map((l: any) => l.story_id) || []);

        const byId = new Map((stories as any[]).map((s) => [s.id, s]));
        const ordered = storyIds.map((id) => byId.get(id)).filter(Boolean);

        const normalizedStories: Story[] = (ordered as any[]).map((s) => ({
          ...s,
          media_type: s.media_type as 'image' | 'video',
          ring_id: s.ring_id || 'default',
          author: authorProfile
            ? {
                id: authorProfile.id,
                name: authorProfile.name,
                username: authorProfile.username,
                avatar_url: authorProfile.avatar_url,
              }
            : undefined,
          has_viewed: viewerId ? viewedStoryIds.has(s.id) : false,
          has_liked: viewerId ? likedStoryIds.has(s.id) : false,
        }));

        if (cancelled) return;
        setGroups([
          {
            user_id: ownerId,
            user: authorProfile || { id: ownerId, name: null, username: null, avatar_url: null },
            stories: normalizedStories,
            has_unviewed: normalizedStories.some((s) => !s.has_viewed),
          },
        ]);
      } catch (e) {
        console.error('HighlightViewer error:', e);
        toast.error('Highlight yuklanmadi');
        setGroups([]);
      } finally {
        setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [highlight.id, highlight.items, user?.id]);

  if (loading) return null;
  if (groups.length === 0) {
    onClose();
    return null;
  }

  return (
    <StoryViewer
      storyGroups={groups}
      initialGroupIndex={0}
      initialStoryIndex={0}
      persistKey={`highlight:${highlight.id}`}
      onClose={onClose}
    />
  );
}

