// HELPER COMPONENTS

// ═══════════════════════════════════════════════════════════════



interface ControlButtonProps {

  onClick: () => void;

  children: React.ReactNode;

  theme: Record<string, string>;

  active?: boolean;

  title?: string;

}



const ControlButton = ({ onClick, children, theme, active, title }: ControlButtonProps) =>

<button

  onClick={onClick}

  title={title}

  className={`p-3 rounded-xl transition-all hover:scale-105 active:scale-95 ${

  active ?

  `${theme.accent} text-white` :

  `${theme.buttonBg} ${theme.text} ${theme.buttonHover}`} border ${

  theme.border}`}>



    {children}

  </button>;





interface InfoItemProps {

  label: string;

  value: string;

  icon: React.ReactNode;

  theme: Record<string, string>;

}



const InfoItem = ({ label, value, icon, theme }: InfoItemProps) =>

<div className={`px-4 py-3 rounded-xl ${theme.buttonBg} border ${theme.border}`}>

    <div className="flex items-center gap-2 mb-1">

      <span className={theme.textMuted}>{icon}</span>

      <span className={`${theme.textMuted} text-xs font-medium uppercase tracking-wide`}>

        {label}

      </span>

    </div>

    <span className={`${theme.text} text-lg font-bold`}>{value}</span>

  </div>;





export default SamsungUltraVideoPlayer;

import React, { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';
import type { User as SupabaseUser, Session } from '@supabase/supabase-js';
import { generateBaseUsername, ensureUniqueUsername } from '@/utils/usernameUtils';

interface Profile {
  id: string;
  name: string | null;
  username: string | null;
  bio: string | null;
  avatar_url: string | null;
  theme_mode?: string | null;
  bg_theme?: string | null;
  gender: string | null;
  hide_highlights?: boolean | null;
  hide_collections?: boolean | null;
  is_private?: boolean | null;
  hide_online_status?: boolean | null;
  hide_mentions?: boolean | null;
  hide_saved_posts?: boolean | null;
  subscription_tier?: 'free' | 'pro' | string;
  created_at: string;
  updated_at: string;
}

interface AuthContextType {
  user: SupabaseUser | null;
  profile: Profile | null;
  session: Session | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  logout: () => Promise<void>;
  refreshProfile: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<SupabaseUser | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  const fetchProfile = async (userId: string) => {
    try {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const sb: any = supabase;
      const { data, error } = await sb
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
        console.error('Error fetching profile:', error);
        return null;
      }

      // If profile row is missing OR incomplete, self-heal from OAuth metadata
      if (!data || !data.username || !data.name || data.name === 'Foydalanuvchi' || !data.avatar_url) {
        // Generate a username for users who don't have one (e.g., Google login)
        // Also sync their name from OAuth metadata if missing
        const { data: userData } = await supabase.auth.getUser();
        const user = userData?.user;
        const currentUserEmail = user?.email;
        const currentFullName = user?.user_metadata?.full_name || user?.user_metadata?.name;
        const currentAvatarUrl =
          (user?.user_metadata as { avatar_url?: string; picture?: string } | undefined)?.avatar_url ||
          (user?.user_metadata as { avatar_url?: string; picture?: string } | undefined)?.picture;
        
        const updates: Partial<Profile> = {};

        if ((!data || !data.username) && currentUserEmail) {
          const baseUsername = generateBaseUsername(currentUserEmail);
          const finalUsername = await ensureUniqueUsername(supabase, baseUsername, userId);
          updates.username = finalUsername;
        }

        if ((!data || !data.name || data.name === 'Foydalanuvchi') && currentFullName) {
          updates.name = currentFullName;
        }

        if ((!data || !data.avatar_url) && currentAvatarUrl) {
          updates.avatar_url = currentAvatarUrl;
        }
        
        if (Object.keys(updates).length > 0) {
          console.log('Fixing profile data for user:', userId, updates);
          const { data: updatedData, error: updateError } = await sb
            .from('profiles')
            .upsert({ id: userId, ...updates }, { onConflict: 'id' })
            .select()
            .single();
            
          if (updateError) {
            console.error('Error auto-updating profile:', updateError);
          } else {
            console.log('Successfully auto-updated profile for user:', userId, updatedData);
            return updatedData as Profile;
          }
        }
      }

      return data as Profile | null;
    } catch (error) {
      console.error('Error fetching profile:', error);
      return null;
    }
  };

  const refreshProfile = async () => {
    if (user) {
      const profileData = await fetchProfile(user.id);
      setProfile(profileData);
    }
  };

  // Update last_seen periodically
  useEffect(() => {
    if (!user) return;
    
    const updateLastSeen = () => {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const sb: any = supabase;
      sb.from('profiles').update({ last_seen: new Date().toISOString() }).eq('id', user.id).then();
    };
    
    updateLastSeen(); // on mount
    const interval = setInterval(updateLastSeen, 60000); // every 60s
    
    return () => clearInterval(interval);
  }, [user]);

  useEffect(() => {
    let isMounted = true;

    // Set up auth state listener FIRST
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event, session) => {
        if (!isMounted) return;

        console.log('Auth state changed:', event, session?.user?.email);
        
        setSession(session);
        setUser(session?.user ?? null);

        if (session?.user) {
          setTimeout(async () => {
            if (isMounted) {
              const profileData = await fetchProfile(session.user.id);
              if (isMounted) {
                setProfile(profileData);
              }
            }
          }, 0);
        } else {
          setProfile(null);
        }
        
        setIsLoading(false);
      }
    );

    // Then check for existing session
    const initializeAuth = async () => {
      try {
        const hashParams = new URLSearchParams(window.location.hash.substring(1));
        const accessToken = hashParams.get('access_token');
        
        if (accessToken) {
          console.log('OAuth callback detected, waiting for auth state change...');
          return;
        }

        const { data: { session } } = await supabase.auth.getSession();
        
        if (!isMounted) return;
        
        if (session) {
          setSession(session);
          setUser(session.user);
          const profileData = await fetchProfile(session.user.id);
          if (isMounted) {
            setProfile(profileData);
          }
        }
      } catch (error) {
        console.error('Error initializing auth:', error);
      } finally {
        if (isMounted) {
          setIsLoading(false);
        }
      }
    };

    initializeAuth();

    return () => {
      isMounted = false;
      subscription.unsubscribe();
    };
  }, []);

  const logout = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setProfile(null);
    setSession(null);
  };

  return (
    <AuthContext.Provider 
      value={{ 
        user, 
        profile, 
        session,
        isLoading, 
        isAuthenticated: !!user,
        logout,
        refreshProfile
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { useLocalStorage } from '@/hooks/useLocalStorage';

export type ThemeMode = 'light' | 'dark' | 'system';
export type BackgroundTheme = 'none' | 'aurora' | 'sunset' | 'ocean';

interface ThemeContextType {
  mode: ThemeMode;
  setMode: (mode: ThemeMode) => void;
  bgTheme: BackgroundTheme;
  setBgTheme: (bg: BackgroundTheme) => void;
  setOverride: (override: { mode?: ThemeMode; bgTheme?: BackgroundTheme } | null) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [mode, setMode] = useLocalStorage<ThemeMode>('theme-mode', 'dark');
  const [bgTheme, setBgTheme] = useLocalStorage<BackgroundTheme>('bg-theme', 'none');
  const [override, setOverride] = useState<{ mode?: ThemeMode; bgTheme?: BackgroundTheme } | null>(null);

  const effectiveMode = override?.mode ?? mode;
  const effectiveBgTheme = override?.bgTheme ?? bgTheme;

  useEffect(() => {
    const root = document.documentElement;
    const applyTheme = (isDark: boolean) => {
      if (isDark) {
        root.classList.add('dark');
      } else {
        root.classList.remove('dark');
      }
    };

    if (effectiveMode === 'system') {
      const mq = window.matchMedia('(prefers-color-scheme: dark)');
      applyTheme(mq.matches);
      const handler = (e: MediaQueryListEvent) => applyTheme(e.matches);
      mq.addEventListener('change', handler);
      return () => mq.removeEventListener('change', handler);
    } else {
      applyTheme(effectiveMode === 'dark');
    }
  }, [effectiveMode]);

  return (
    <ThemeContext.Provider
      value={useMemo(
        () => ({
          mode: effectiveMode,
          setMode,
          bgTheme: effectiveBgTheme,
          setBgTheme,
          setOverride,
        }),
        [effectiveBgTheme, effectiveMode, setBgTheme, setMode]
      )}
    >
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within ThemeProvider');
  return context;
};

import { useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

interface Position {
  x: number;
  y: number;
}

interface Connection {
  from: Position;
  to: Position;
  type: 'parent' | 'child' | 'spouse';
  path?: string; // AI-generated SVG path
  fromMemberId?: string;
  toMemberId?: string;
}

interface MemberPosition {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  relationType: string;
}

interface HeartPosition {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
}

// Fallback path generation when AI is not available
const generateFallbackPath = (from: Position, to: Position, type: 'parent' | 'child' | 'spouse'): string => {
  const dx = to.x - from.x;
  const dy = to.y - from.y;
  
  if (type === 'spouse') {
    const midY = from.y;
    return `M ${from.x} ${from.y} Q ${from.x + dx / 2} ${midY - 10} ${to.x} ${to.y}`;
  }
  
  if (type === 'parent') {
    const controlY = from.y - Math.abs(dy) * 0.5;
    return `M ${from.x} ${from.y} C ${from.x} ${controlY}, ${to.x} ${to.y + Math.abs(dy) * 0.3}, ${to.x} ${to.y}`;
  }
  
  const controlY = from.y + Math.abs(dy) * 0.5;
  return `M ${from.x} ${from.y} C ${from.x} ${controlY}, ${to.x} ${to.y - Math.abs(dy) * 0.3}, ${to.x} ${to.y}`;
};

export const useAIConnectorLines = (
  containerRef: React.RefObject<HTMLDivElement>,
  memberElements: Map<string, HTMLElement | null>,
  members: any[],
  heartElements: Map<string, HTMLElement | null>,
  useAI: boolean = true
) => {
  const [connections, setConnections] = useState<Connection[]>([]);
  const [isCalculating, setIsCalculating] = useState(false);
  const { toast } = useToast();
  const lastCalculationRef = useRef<string>('');
  const debounceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Calculate positions from DOM elements
  const calculatePositions = useCallback(() => {
    if (!containerRef.current) return null;
    
    const containerRect = containerRef.current.getBoundingClientRect();
    
    const memberPositions: MemberPosition[] = [];
    const heartPositions: HeartPosition[] = [];

    memberElements.forEach((el, id) => {
      if (el) {
        const rect = el.getBoundingClientRect();
        const member = members.find(m => m.id === id);
        memberPositions.push({
          id,
          x: rect.left - containerRect.left + rect.width / 2,
          y: rect.top - containerRect.top + rect.height / 2,
          width: rect.width,
          height: rect.height,
          relationType: member?.relation_type || 'unknown',
        });
      }
    });

    heartElements.forEach((el, id) => {
      if (el) {
        const rect = el.getBoundingClientRect();
        heartPositions.push({
          id,
          x: rect.left - containerRect.left + rect.width / 2,
          y: rect.top - containerRect.top + rect.height / 2,
          width: rect.width,
          height: rect.height,
        });
      }
    });

    return {
      members: memberPositions,
      hearts: heartPositions,
      containerWidth: containerRect.width,
      containerHeight: containerRect.height,
    };
  }, [containerRef, memberElements, members, heartElements]);

  // Calculate connections using AI
  const calculateWithAI = useCallback(async () => {
    const positions = calculatePositions();
    if (!positions || positions.members.length === 0) return;

    // Create hash to avoid duplicate calculations
    const positionHash = JSON.stringify(positions);
    if (positionHash === lastCalculationRef.current) return;
    
    setIsCalculating(true);
    
    try {
      const { data, error } = await supabase.functions.invoke('calculate-family-lines', {
        body: positions,
      });

      if (error) throw error;

      if (data?.connections) {
        const aiConnections: Connection[] = data.connections.map((conn: any) => {
          // Find positions for from/to
          const fromMember = positions.members.find(m => m.id === conn.fromId);
          const toHeart = positions.hearts.find(h => h.id === conn.toId);
          const toMember = positions.members.find(m => m.id === conn.toId);
          const fromHeart = positions.hearts.find(h => h.id === conn.fromId);

          return {
            from: {
              x: fromMember?.x || fromHeart?.x || 0,
              y: fromMember?.y - (fromMember?.height || 0) / 2 || fromHeart?.y + (fromHeart?.height || 0) / 2 || 0,
            },
            to: {
              x: toMember?.x || toHeart?.x || 0,
              y: toMember?.y - (toMember?.height || 0) / 2 || toHeart?.y + (toHeart?.height || 0) / 2 || 0,
            },
            type: conn.type,
            path: conn.path,
            fromMemberId: conn.fromId,
            toMemberId: conn.toId,
          };
        });

        setConnections(aiConnections);
        lastCalculationRef.current = positionHash;
      }
    } catch (error: any) {
      console.error('AI calculation error:', error);
      // Fallback to standard calculation
      calculateFallback();
    } finally {
      setIsCalculating(false);
    }
  }, [calculatePositions]);

  // Fallback calculation without AI
  const calculateFallback = useCallback(() => {
    if (!containerRef.current) return;
    
    const containerRect = containerRef.current.getBoundingClientRect();
    const newConnections: Connection[] = [];

    // Calculate parent-to-member connections
    members.forEach((member) => {
      const memberEl = memberElements.get(member.id);
      if (!memberEl) return;

      const memberRect = memberEl.getBoundingClientRect();
      const memberTop = {
        x: memberRect.left - containerRect.left + memberRect.width / 2,
        y: memberRect.top - containerRect.top,
      };

      // Check for parents-of-X heart element
      const parentsHeartEl = heartElements.get(`parents-of-${member.id}`);
      if (parentsHeartEl) {
        const heartRect = parentsHeartEl.getBoundingClientRect();
        const from = memberTop;
        const to = {
          x: heartRect.left - containerRect.left + heartRect.width / 2,
          y: heartRect.top - containerRect.top + heartRect.height,
        };
        
        newConnections.push({
          from,
          to,
          type: 'parent',
          path: generateFallbackPath(from, to, 'parent'),
          fromMemberId: member.id,
          toMemberId: 'parents',
        });
      } else {
        // Find fathers of this member
        const fathers = members.filter(m => 
          m.relation_type === `father_of_${member.id}` || 
          m.relation_type === `father_2_of_${member.id}`
        );

        fathers.forEach((father) => {
          const fatherEl = memberElements.get(father.id);
          if (fatherEl) {
            const fatherRect = fatherEl.getBoundingClientRect();
            const from = memberTop;
            const to = {
              x: fatherRect.left - containerRect.left + fatherRect.width / 2,
              y: fatherRect.top - containerRect.top + fatherRect.height,
            };
            
            newConnections.push({
              from,
              to,
              type: 'parent',
              path: generateFallbackPath(from, to, 'parent'),
              fromMemberId: member.id,
              toMemberId: father.id,
            });
          }
        });

        // Find mothers of this member
        const mothers = members.filter(m => 
          m.relation_type === `mother_of_${member.id}` || 
          m.relation_type === `mother_2_of_${member.id}`
        );

        mothers.forEach((mother) => {
          const motherEl = memberElements.get(mother.id);
          if (motherEl) {
            const motherRect = motherEl.getBoundingClientRect();
            const from = memberTop;
            const to = {
              x: motherRect.left - containerRect.left + motherRect.width / 2,
              y: motherRect.top - containerRect.top + motherRect.height,
            };
            
            newConnections.push({
              from,
              to,
              type: 'parent',
              path: generateFallbackPath(from, to, 'parent'),
              fromMemberId: member.id,
              toMemberId: mother.id,
            });
          }
        });
      }
    });

    // Calculate child connections (from heart to child)
    heartElements.forEach((heartEl, heartKey) => {
      if (!heartEl || heartKey.startsWith('parent-') || heartKey.startsWith('parents-of-')) return;

      const heartRect = heartEl.getBoundingClientRect();
      const heartCenter = {
        x: heartRect.left - containerRect.left + heartRect.width / 2,
        y: heartRect.top - containerRect.top + heartRect.height,
      };

      const parentMemberId = heartKey;
      const childMembers = members.filter(m => 
        m.relation_type.startsWith(`child_of_${parentMemberId}`)
      );

      childMembers.forEach((child) => {
        const childEl = memberElements.get(child.id);
        if (childEl) {
          const childRect = childEl.getBoundingClientRect();
          const from = heartCenter;
          const to = {
            x: childRect.left - containerRect.left + childRect.width / 2,
            y: childRect.top - containerRect.top,
          };
          
          newConnections.push({
            from,
            to,
            type: 'child',
            path: generateFallbackPath(from, to, 'child'),
            fromMemberId: parentMemberId,
            toMemberId: child.id,
          });
        }
      });
    });

    setConnections(newConnections);
  }, [containerRef, memberElements, members, heartElements]);

  // Main calculation function with debounce
  const calculate = useCallback(() => {
    if (debounceTimerRef.current) {
      clearTimeout(debounceTimerRef.current);
    }

    debounceTimerRef.current = setTimeout(() => {
      if (useAI) {
        calculateWithAI();
      } else {
        calculateFallback();
      }
    }, 200);
  }, [useAI, calculateWithAI, calculateFallback]);

  // Effect to trigger calculation
  useEffect(() => {
    const timer = setTimeout(calculate, 150);
    
    window.addEventListener('resize', calculate);
    
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', calculate);
      if (debounceTimerRef.current) {
        clearTimeout(debounceTimerRef.current);
      }
    };
  }, [calculate, members]);

  return { connections, isCalculating, recalculate: calculate };
};

import { useEffect, useRef } from 'react';

export const useAutoPreviewVideo = (
  videoRef: React.RefObject<HTMLVideoElement>,
  {
    enabled = true,
    delayMs = 3000,
    threshold = 0.6,
    rootMargin = '0px',
  }: {
    enabled?: boolean;
    delayMs?: number;
    threshold?: number;
    rootMargin?: string;
  } = {}
) => {
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    if (!enabled) return;

    const el = videoRef.current;
    if (!el) return;

    const clearTimer = () => {
      if (timerRef.current !== null) {
        window.clearTimeout(timerRef.current);
        timerRef.current = null;
      }
    };

    const ensureMutedInline = () => {
      el.muted = true;
      el.playsInline = true;
      el.loop = true;
    };

    ensureMutedInline();

    const stop = () => {
      clearTimer();
      try {
        el.pause();
      } catch {
        // ignore
      }
    };

    const start = () => {
      clearTimer();
      timerRef.current = window.setTimeout(() => {
        ensureMutedInline();
        const p = el.play();
        if (p && typeof (p as any).catch === 'function') (p as any).catch(() => {});
      }, delayMs);
    };

    const observer = new IntersectionObserver(
      (entries) => {
        const entry = entries[0];
        if (!entry) return;
        if (entry.isIntersecting && entry.intersectionRatio >= threshold) start();
        else stop();
      },
      { threshold: [threshold], rootMargin }
    );

    observer.observe(el);

    return () => {
      stop();
      observer.disconnect();
    };
  }, [delayMs, enabled, rootMargin, threshold, videoRef]);
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface UserStoryStatus {
  userId: string;
  hasStory: boolean;
  hasUnviewed: boolean;
}

export const useFamilyStories = (userIds: string[]) => {
  const { user } = useAuth();
  const [storyStatuses, setStoryStatuses] = useState<Map<string, UserStoryStatus>>(new Map());
  const [isLoading, setIsLoading] = useState(false);

  const fetchStoryStatuses = useCallback(async () => {
    if (!user?.id || userIds.length === 0) return;

    setIsLoading(true);
    try {
      // Get active stories for these users
      const { data: stories, error } = await supabase
        .from('stories')
        .select('id, user_id')
        .in('user_id', userIds)
        .gt('expires_at', new Date().toISOString());

      if (error) throw error;

      if (!stories || stories.length === 0) {
        setStoryStatuses(new Map());
        return;
      }

      // Get viewed stories by current user
      const { data: views } = await supabase
        .from('story_views')
        .select('story_id')
        .eq('viewer_id', user.id)
        .in('story_id', stories.map(s => s.id));

      const viewedIds = new Set(views?.map(v => v.story_id) || []);

      // Build status map
      const statusMap = new Map<string, UserStoryStatus>();
      userIds.forEach(userId => {
        const userStories = stories.filter(s => s.user_id === userId);
        const hasStory = userStories.length > 0;
        const hasUnviewed = userStories.some(s => !viewedIds.has(s.id));
        statusMap.set(userId, { userId, hasStory, hasUnviewed });
      });

      setStoryStatuses(statusMap);
    } catch (error) {
      console.error('Error fetching story statuses:', error);
    } finally {
      setIsLoading(false);
    }
  }, [user?.id, userIds.join(',')]);

  useEffect(() => {
    fetchStoryStatuses();
  }, [fetchStoryStatuses]);

  const getStoryStatus = useCallback((userId: string): UserStoryStatus => {
    return storyStatuses.get(userId) || { userId, hasStory: false, hasUnviewed: false };
  }, [storyStatuses]);

  return {
    storyStatuses,
    getStoryStatus,
    isLoading,
    refetch: fetchStoryStatuses,
  };
};

