  const deleteMember = async (memberId: string) => {
    if (!user?.id) return false;

    try {
      // Also delete any spouses of this member
      const spouseRelations = members.filter(m => 
        m.relation_type === `spouse_of_${memberId}` || 
        m.relation_type === `spouse_2_of_${memberId}`
      );
      
      // Also delete any children of this member
      const childRelations = members.filter(m => 
        m.relation_type === `child_of_${memberId}` ||
        m.relation_type.startsWith(`child_`) && m.relation_type.includes(memberId)
      );

      // Delete spouses first
      for (const spouse of spouseRelations) {
        await supabase
          .from('family_tree_members')
          .delete()
          .eq('id', spouse.id);
      }

      // Delete children
      for (const child of childRelations) {
        await supabase
          .from('family_tree_members')
          .delete()
          .eq('id', child.id);
      }

      const { error } = await supabase
        .from('family_tree_members')
        .delete()
        .eq('id', memberId)
        .eq('owner_id', user.id);

      if (error) throw error;

      await fetchMembers();
      toast({
        title: "O'chirildi!",
        description: "Qarindosh oila daraxtidan o'chirildi",
      });

      return true;
    } catch (error: any) {
      toast({
        title: "Xato",
        description: error.message,
        variant: "destructive",
      });
      return false;
    }
  };

  // Count spouses for a member
  // Barcha holatlarni tekshiradi:
  // 1. Bu profilga juft qo'shilganmi (spouse_of_${memberId})
  // 2. Bu profil o'zi boshqa profilga juft sifatida qo'shilganmi
  // 3. Bu profil ota bo'lsa va shu farzandning onasi ham bormi (yoki aksincha)
  // 4. Bu profil biror memberning otasi bo'lsa va shu memberning onasi ham alohida qo'shilgan bo'lsa
  const countSpousesForMember = (memberId: string): number => {
    // Tekshirish 1: bu profilga juft qo'shilganmi
    const spousesAdded = members.filter(m => 
      m.relation_type === `spouse_of_${memberId}`
    ).length;
    
    if (spousesAdded > 0) return spousesAdded;
    
    const memberSelf = members.find(m => m.id === memberId);
    if (!memberSelf) return 0;
    
    // Tekshirish 2: bu profil o'zi boshqa profilga juft sifatida qo'shilganmi
    if (memberSelf.relation_type.startsWith('spouse_of_')) {
      return 1;
    }
    
    // Tekshirish 3: Bu profil ota yoki ona bo'lsa (father_of_X / mother_of_X formatida)
    // va shu farzandning teskari ota-onasi ham bormi
    const fatherMatch = memberSelf.relation_type.match(/^father_of_(.+)$/);
    if (fatherMatch) {
      const childId = fatherMatch[1];
      // Shu farzandning onasi bormi? Yoki otaga juft qo'shilganmi?
      const hasMotherPair = members.some(m => m.relation_type === `mother_of_${childId}`);
      const hasSpouseAdded = members.some(m => m.relation_type === `spouse_of_${memberId}`);
      if (hasMotherPair || hasSpouseAdded) return 1;
    }
    
    const motherMatch = memberSelf.relation_type.match(/^mother_of_(.+)$/);
    if (motherMatch) {
      const childId = motherMatch[1];
      // Shu farzandning otasi bormi? Yoki onaga juft qo'shilganmi?
      const hasFatherPair = members.some(m => m.relation_type === `father_of_${childId}`);
      const hasSpouseAdded = members.some(m => m.relation_type === `spouse_of_${memberId}`);
      if (hasFatherPair || hasSpouseAdded) return 1;
    }
    
    // Tekshirish 4: Bu profil biror memberning otasi bo'lsa va shu memberning onasi ham alohida qo'shilgan bo'lsa
    // Masalan: "father" legacy type
    if (memberSelf.relation_type === 'father') {
      // Legacy father - ona bormi?
      const hasMother = members.some(m => m.relation_type === 'mother');
      if (hasMother) return 1;
    }
    
    if (memberSelf.relation_type === 'mother') {
      // Legacy mother - ota bormi?
      const hasFather = members.some(m => m.relation_type === 'father');
      if (hasFather) return 1;
    }
    
    return 0;
  };

  // Count children for a member
  // MUHIM: Agar member kimningdir jufti bo'lsa, juftining bolalari ham shu memberga tegishli
  const countChildrenForMember = (memberId: string): number => {
    // 1. To'g'ridan-to'g'ri shu memberning bolalari
    const directChildren = members.filter(m => 
      m.relation_type.startsWith(`child_of_${memberId}`)
    ).length;
    
    if (directChildren > 0) return directChildren;
    
    // 2. Agar bu member kimningdir jufti bo'lsa - juftining bolalarini qaytaramiz
    const memberSelf = members.find(m => m.id === memberId);
    if (memberSelf) {
      // spouse_of_X formatidan X ni topamiz
      const spouseMatch = memberSelf.relation_type.match(/^spouse_of_(.+)$/);
      if (spouseMatch) {
        const partnerId = spouseMatch[1];
        // Juftning bolalari = mening bolalarim
        const partnerChildren = members.filter(m => 
          m.relation_type.startsWith(`child_of_${partnerId}`)
        ).length;
        return partnerChildren;
      }
    }
    
    return 0;
  };

  // Count parents (fathers) for a member
  // TO'G'RI QOIDA: Har qanday odam o'z ota-onasiga ega bo'lishi mumkin
  // child_of_ orqali yaratilgan bo'lsa HAM - bu faqat BITTA juftlikdan yaratilganini bildiradi
  // lekin shu farzandning o'z ALOHIDA ota-onasi bo'lishi ham mumkin (masalan: asrab olgan ota-ona)
  // LEKIN: child_of_X dagi X ning O'ZI ota yoki ona hisoblanadi
  const countFathersForMember = (memberId: string): number => {
    const memberSelf = members.find(m => m.id === memberId);
    if (!memberSelf) return 0;
    
    // Agar bu member child_of_X orqali yaratilgan bo'lsa
    // X ning jinsi tekshiriladi - agar X erkak bo'lsa - u OTA
    const childMatch = memberSelf.relation_type.match(/^child_of_([^_]+)/);
    if (childMatch) {
      const parentId = childMatch[1];
      const parent = members.find(m => m.id === parentId);
      if (parent) {
        const parentGender = parent.gender || parent.linked_profile?.gender;
        // Agar parent erkak bo'lsa - bu OTA
        if (parentGender === 'male') {
          return 1; // Ota bor (parent o'zi)
        }
        // Agar parent ayol bo'lsa (ONA) - otani spouse orqali tekshiramiz
        if (parentGender === 'female') {
          const parentSpouse = members.find(m => m.relation_type === `spouse_of_${parentId}`);
          if (parentSpouse) {
            return 1; // Ota bor (ona jufti)
          }
          return 0; // Ota yo'q - qo'shish mumkin (lekin ona ota-onasi emas!)
        }
      }
      // Agar parent topilmasa yoki jins aniqlanmasa - 0
      return 0;
    }
    
    // To'g'ridan-to'g'ri father_of_ relation bilan qo'shilgan ota
    const directFatherCount = members.filter(m => 
      m.relation_type === `father_of_${memberId}`
    ).length;
    
    if (directFatherCount > 0) return directFatherCount;
    
    // Agar ona bor va onaga juft qo'shilgan bo'lsa - bu ota
    const mother = members.find(m => m.relation_type === `mother_of_${memberId}`);
    if (mother) {
      const motherSpouse = members.find(m => m.relation_type === `spouse_of_${mother.id}`);
      if (motherSpouse) {
        return 1; // Ota bor (ona jufti sifatida)
      }
    }
    
    return 0;
  };

  // Count parents (mothers) for a member
  // TO'G'RI QOIDA: Har qanday odam o'z ota-onasiga ega bo'lishi mumkin
  const countMothersForMember = (memberId: string): number => {
    const memberSelf = members.find(m => m.id === memberId);
    if (!memberSelf) return 0;
    
    // Agar bu member child_of_X orqali yaratilgan bo'lsa
    // X ning jinsi tekshiriladi - agar X ayol bo'lsa - u ONA
    const childMatch = memberSelf.relation_type.match(/^child_of_([^_]+)/);
    if (childMatch) {
      const parentId = childMatch[1];
      const parent = members.find(m => m.id === parentId);
      if (parent) {
        const parentGender = parent.gender || parent.linked_profile?.gender;
        // Agar parent ayol bo'lsa - bu ONA
        if (parentGender === 'female') {
          return 1; // Ona bor (parent o'zi)
        }
        // Agar parent erkak bo'lsa (OTA) - onani spouse orqali tekshiramiz
        if (parentGender === 'male') {
          const parentSpouse = members.find(m => m.relation_type === `spouse_of_${parentId}`);
          if (parentSpouse) {
            return 1; // Ona bor (ota jufti)
          }
          return 0; // Ona yo'q - qo'shish mumkin
        }
      }
      return 0;
    }
    
    // To'g'ridan-to'g'ri mother_of_ relation bilan qo'shilgan ona
    const directMotherCount = members.filter(m => 
      m.relation_type === `mother_of_${memberId}`
    ).length;
    
    if (directMotherCount > 0) return directMotherCount;
    
    // Agar ota bor va otaga juft qo'shilgan bo'lsa - bu ona
    const father = members.find(m => m.relation_type === `father_of_${memberId}`);
    if (father) {
      const fatherSpouse = members.find(m => m.relation_type === `spouse_of_${father.id}`);
      if (fatherSpouse) {
        return 1; // Ona bor (ota jufti sifatida)
      }
    }
    
    return 0;
  };
  
  // Ota jufti = ona ekanligini tekshirish
  // Agar memberga ota qo'shilgan bo'lsa va shu otaga juft qo'shilsa - bu ona
  // Shuning uchun "Ona qo'shish" tugmasi yo'qolishi kerak
  const isFatherSpouseAsMother = (memberId: string): boolean => {
    const father = members.find(m => m.relation_type === `father_of_${memberId}`);
    if (father) {
      const fatherSpouse = members.find(m => m.relation_type === `spouse_of_${father.id}`);
      return !!fatherSpouse;
    }
    return false;
  };
  
  // Ona jufti = ota ekanligini tekshirish
  const isMotherSpouseAsFather = (memberId: string): boolean => {
    const mother = members.find(m => m.relation_type === `mother_of_${memberId}`);
    if (mother) {
      const motherSpouse = members.find(m => m.relation_type === `spouse_of_${mother.id}`);
      return !!motherSpouse;
    }
    return false;
  };

  // Add spouse to an existing member
  // Barcha network userlarning memberlarini tekshiradi
  const addSpouseToMember = async (
    memberId: string, 
    spouseData: { name: string; gender: 'male' | 'female'; avatarUrl?: string },
    isSecondSpouse: boolean = false
  ) => {
    if (!user?.id) return null;

    try {
      // Fetch fresh data from ALL network users to get accurate spouse count
      const users = await getNetworkUsersForCurrentUser();
      
      const { data: existingSpouses, error: countError } = await supabase
        .from('family_tree_members')
        .select('id, relation_type')
        .in('owner_id', users)
        .or(`relation_type.eq.spouse_of_${memberId},relation_type.eq.spouse_2_of_${memberId}`);

      if (countError) throw countError;

      const currentSpouseCount = existingSpouses?.length || 0;
      
      if (currentSpouseCount >= FAMILY_LIMITS.MAX_SPOUSES) {
        toast({
          title: "Limit",
          description: `Maksimal ${FAMILY_LIMITS.MAX_SPOUSES} ta juft qo'shish mumkin`,
          variant: "destructive",
        });
        return null;
      }

      // Ensure user has a network before adding member
      await ensureFamilyNetwork(user.id);

      const relationType = isSecondSpouse ? `spouse_2_of_${memberId}` : `spouse_of_${memberId}`;

      const { data, error } = await supabase
        .from('family_tree_members')
        .insert({
          owner_id: user.id,
          member_name: spouseData.name,
          relation_type: relationType,
          avatar_url: spouseData.avatarUrl || null,
          gender: spouseData.gender,
          is_placeholder: true,
        })
        .select()
        .single();

      if (error) throw error;

      await fetchMembers();
      toast({
        title: "Juft qo'shildi!",
        description: `${spouseData.name} juft sifatida qo'shildi`,
      });

      return data;
    } catch (error: any) {
      toast({
        title: "Xato",
        description: error.message,
        variant: "destructive",
      });
      return null;
    }
  };

  // Add child to a member (requires spouse)
  // Barcha network userlarning memberlarini tekshiradi
  // MUHIM: Agar member kimningdir jufti bo'lsa (spouse_of_X), bolani X ga bog'laymiz
  const addChildToMember = async (
    memberId: string,
    childData: { name: string; gender: 'male' | 'female'; avatarUrl?: string }
  ) => {
    if (!user?.id) return null;

    try {
      // Avval bu memberning o'zi kimningdir jufti ekanligini tekshiramiz
      const memberSelf = members.find(m => m.id === memberId);
      let targetParentId = memberId;
      
      if (memberSelf) {
        const spouseMatch = memberSelf.relation_type.match(/^spouse_of_(.+)$/);
        if (spouseMatch) {
          // Bu member kimningdir jufti - bolani asosiy ota/onaga bog'laymiz
          targetParentId = spouseMatch[1];
        }
      }

      // Fetch fresh data from ALL network users to get accurate child count
      const users = await getNetworkUsersForCurrentUser();
      
      const { data: existingChildren, error: countError } = await supabase
        .from('family_tree_members')
        .select('id, relation_type')
        .in('owner_id', users)
        .like('relation_type', `child_of_${targetParentId}%`);

      if (countError) throw countError;

      const currentChildCount = existingChildren?.length || 0;
      
      if (currentChildCount >= FAMILY_LIMITS.MAX_CHILDREN) {
        toast({
          title: "Limit",
          description: `Maksimal ${FAMILY_LIMITS.MAX_CHILDREN} ta farzand qo'shish mumkin`,
          variant: "destructive",
        });
        return null;
      }

      await ensureFamilyNetwork(user.id);

      const childNumber = currentChildCount + 1;
      const relationType = `child_of_${targetParentId}_${childNumber}`;

      const { data, error } = await supabase
        .from('family_tree_members')
        .insert({
          owner_id: user.id,
          member_name: childData.name,
          relation_type: relationType,
          avatar_url: childData.avatarUrl || null,
          gender: childData.gender,
          is_placeholder: true,
        })
        .select()
        .single();

      if (error) throw error;

      await fetchMembers();
      toast({
        title: "Farzand qo'shildi!",
        description: `${childData.name} farzand sifatida qo'shildi`,
      });

      return data;
    } catch (error: any) {
      toast({
        title: "Xato",
        description: error.message,
        variant: "destructive",
      });
      return null;
    }
  };

  // Add father to a member (faqat bitta ota)
  // Barcha network userlarning memberlarini tekshiradi
  const addFatherToMember = async (
    memberId: string,
    fatherData: { name: string; avatarUrl?: string }
  ) => {
    if (!user?.id) return null;

    try {
      // Fetch fresh data from ALL network users to get accurate count
      const users = await getNetworkUsersForCurrentUser();
      
      const { data: existingFathers, error: countError } = await supabase
        .from('family_tree_members')
        .select('id, relation_type')
        .in('owner_id', users)
        .eq('relation_type', `father_of_${memberId}`);

      if (countError) throw countError;

      const currentFatherCount = existingFathers?.length || 0;

      if (currentFatherCount >= FAMILY_LIMITS.MAX_FATHERS) {
        toast({
          title: "Limit",
          description: `Maksimal ${FAMILY_LIMITS.MAX_FATHERS} ta ota qo'shish mumkin`,
          variant: "destructive",
        });
        return null;
      }

      await ensureFamilyNetwork(user.id);

      const relationType = `father_of_${memberId}`;

      const { data, error } = await supabase
        .from('family_tree_members')
        .insert({
          owner_id: user.id,
          member_name: fatherData.name,
          relation_type: relationType,
          avatar_url: fatherData.avatarUrl || null,
          gender: 'male',
          is_placeholder: true,
        })
        .select()
        .single();

      if (error) throw error;

      await fetchMembers();
      toast({
        title: "Ota qo'shildi!",
        description: `${fatherData.name} ota sifatida qo'shildi`,
      });

      return data;
    } catch (error: any) {
      toast({
        title: "Xato",
        description: error.message,
        variant: "destructive",
      });
      return null;
    }
  };

  // Add mother to a member (faqat bitta ona)
  // Barcha network userlarning memberlarini tekshiradi
  const addMotherToMember = async (
    memberId: string,
    motherData: { name: string; avatarUrl?: string }
  ) => {
    if (!user?.id) return null;

    try {
      // Fetch fresh data from ALL network users to get accurate count
      const users = await getNetworkUsersForCurrentUser();
      
      const { data: existingMothers, error: countError } = await supabase
        .from('family_tree_members')
        .select('id, relation_type')
        .in('owner_id', users)
        .eq('relation_type', `mother_of_${memberId}`);

      if (countError) throw countError;

      const currentMotherCount = existingMothers?.length || 0;

      if (currentMotherCount >= FAMILY_LIMITS.MAX_MOTHERS) {
        toast({
          title: "Limit",
          description: `Maksimal ${FAMILY_LIMITS.MAX_MOTHERS} ta ona qo'shish mumkin`,
          variant: "destructive",
        });
        return null;
      }

      await ensureFamilyNetwork(user.id);

      const relationType = `mother_of_${memberId}`;

      const { data, error } = await supabase
        .from('family_tree_members')
        .insert({
          owner_id: user.id,
          member_name: motherData.name,
          relation_type: relationType,
          avatar_url: motherData.avatarUrl || null,
          gender: 'female',
          is_placeholder: true,
        })
        .select()
        .single();

      if (error) throw error;

      await fetchMembers();
      toast({
        title: "Ona qo'shildi!",
        description: `${motherData.name} ona sifatida qo'shildi`,
      });

      return data;
    } catch (error: any) {
      toast({
        title: "Xato",
        description: error.message,
        variant: "destructive",
      });
      return null;
    }
  };

  return {
    members,
    invitations,
    isLoading,
    networkUsers,
    addMember,
    addSpouseToMember,
    addChildToMember,
    addFatherToMember,
    addMotherToMember,
    countSpousesForMember,
    countChildrenForMember,
    countFathersForMember,
    countMothersForMember,
    isFatherSpouseAsMother,
    isMotherSpouseAsFather,
    sendInvitation,
    respondToInvitation,
    linkExistingMemberToUser,
    deleteMember,
    refetch: fetchMembers,
    refetchInvitations: fetchInvitations,
  };
};

import { useCallback, useEffect, useMemo, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';

export type FollowListMode = 'followers' | 'following';

export interface FollowListUser {
  id: string;
  name: string | null;
  username: string | null;
  avatar_url: string | null;
}

export const useFollowLists = (userId: string | undefined, mode: FollowListMode, enabled: boolean) => {
  const [users, setUsers] = useState<FollowListUser[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const title = useMemo(() => {
    if (mode === 'followers') return 'Kuzatuvchilar';
    return 'Kuzatilmoqda';
  }, [mode]);

  const fetchUsers = useCallback(async () => {
    if (!userId) {
      setUsers([]);
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const idColumn = mode === 'followers' ? 'follower_id' : 'following_id';
      const filterColumn = mode === 'followers' ? 'following_id' : 'follower_id';

      const { data: followRows, error: followsError } = await supabase
        .from('follows')
        .select(idColumn)
        .eq(filterColumn, userId)
        .limit(500);

      if (followsError) throw followsError;

      const ids = (followRows || [])
        .map((r: any) => r[idColumn] as string)
        .filter(Boolean);

      if (ids.length === 0) {
        setUsers([]);
        return;
      }

      const { data: profiles, error: profilesError } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url')
        .in('id', ids);

      if (profilesError) throw profilesError;

      const map = new Map<string, FollowListUser>();
      (profiles || []).forEach((p: any) => {
        map.set(p.id, {
          id: p.id,
          name: p.name ?? null,
          username: p.username ?? null,
          avatar_url: p.avatar_url ?? null,
        });
      });

      const ordered = ids.map((id) => map.get(id)).filter(Boolean) as FollowListUser[];
      setUsers(ordered);
    } catch (e: any) {
      setError(e?.message || 'Xatolik');
      setUsers([]);
    } finally {
      setIsLoading(false);
    }
  }, [mode, userId]);

  useEffect(() => {
    if (!enabled) return;
    fetchUsers();
  }, [enabled, fetchUsers]);

  return { users, isLoading, error, title, refetch: fetchUsers };
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export function useMemorialPostSocial(memorialPostId: string) {
  const { user } = useAuth();
  const [isLiked, setIsLiked] = useState(false);
  const [likesCount, setLikesCount] = useState(0);
  const [commentsCount, setCommentsCount] = useState(0);
  const [isSaved, setIsSaved] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const init = useCallback(async () => {
    if (!memorialPostId) return;

    const [likeRes, saveRes, countRes, commentRes] = await Promise.all([
      user
        ? (supabase as any)
            .from('memorial_post_likes')
            .select('id')
            .eq('memorial_post_id', memorialPostId)
            .eq('user_id', user.id)
            .maybeSingle()
        : Promise.resolve({ data: null }),
      user
        ? (supabase as any)
            .from('memorial_post_saves')
            .select('id')
            .eq('memorial_post_id', memorialPostId)
            .eq('user_id', user.id)
            .maybeSingle()
        : Promise.resolve({ data: null }),
      (supabase as any)
        .from('memorial_post_likes')
        .select('*', { count: 'exact', head: true })
        .eq('memorial_post_id', memorialPostId),
      (supabase as any)
        .from('memorial_post_comments')
        .select('*', { count: 'exact', head: true })
        .eq('memorial_post_id', memorialPostId),
    ]);

    setIsLiked(!!likeRes.data);
    setIsSaved(!!saveRes.data);
    setLikesCount(countRes.count ?? 0);
    setCommentsCount(commentRes.count ?? 0);
  }, [memorialPostId, user]);

  useEffect(() => {
    init();
  }, [init]);

  const toggleLike = useCallback(async () => {
    if (!user || isLoading) return;
    setIsLoading(true);

    const newLiked = !isLiked;
    const newCount = newLiked ? likesCount + 1 : Math.max(0, likesCount - 1);
    setIsLiked(newLiked);
    setLikesCount(newCount);

    try {
      if (newLiked) {
        await (supabase as any)
          .from('memorial_post_likes')
          .insert({ memorial_post_id: memorialPostId, user_id: user.id });
      } else {
        await (supabase as any)
          .from('memorial_post_likes')
          .delete()
          .eq('memorial_post_id', memorialPostId)
          .eq('user_id', user.id);
      }
    } catch (e) {
      // Rollback on error
      setIsLiked(!newLiked);
      setLikesCount(likesCount);
      console.error('Error toggling memorial post like:', e);
    } finally {
      setIsLoading(false);
    }
  }, [user, isLoading, isLiked, likesCount, memorialPostId]);

  const toggleSave = useCallback(async () => {
    if (!user || isLoading) return;
    setIsLoading(true);

    const newSaved = !isSaved;
    setIsSaved(newSaved);

    try {
      if (newSaved) {
        await (supabase as any)
          .from('memorial_post_saves')
          .insert({ memorial_post_id: memorialPostId, user_id: user.id });
      } else {
        await (supabase as any)
          .from('memorial_post_saves')
          .delete()
          .eq('memorial_post_id', memorialPostId)
          .eq('user_id', user.id);
      }
    } catch (e) {
      setIsSaved(!newSaved);
      console.error('Error toggling memorial post save:', e);
    } finally {
      setIsLoading(false);
    }
  }, [user, isLoading, isSaved, memorialPostId]);

  const trackView = useCallback(async () => {
    if (!user) return;
    try {
      await (supabase as any)
        .from('memorial_post_views')
        .upsert({ memorial_post_id: memorialPostId, user_id: user.id }, { onConflict: 'memorial_post_id,user_id', ignoreDuplicates: true });
    } catch {
      // Unique constraint violation means already viewed — ignore
    }
  }, [user, memorialPostId]);

  const handleShare = useCallback(async () => {
    const shareUrl = `${window.location.origin}/memorial-post/${memorialPostId}`;
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Xotira post',
          url: shareUrl,
        });
      } catch (err) {
        console.error('Error sharing:', err);
      }
    } else {
      try {
        await navigator.clipboard.writeText(shareUrl);
        // We could add a toast here if we had access to one
      } catch (err) {
        console.error('Error copying to clipboard:', err);
      }
    }
  }, [memorialPostId]);

  return { isLiked, likesCount, commentsCount, isSaved, toggleLike, toggleSave, trackView, handleShare };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { uploadMedia } from '@/lib/r2Upload';

export interface MemorialPostAuthor {
  id: string;
  name: string | null;
  username: string | null;
  avatar_url: string | null;
}

export interface MemorialPost {
  id: string;
  family_member_id: string;
  created_by: string;
  media_url: string | null;
  media_type: string | null;
  caption: string | null;
  created_at: string;
  likes_count?: number;
  views_count?: number;
  author?: MemorialPostAuthor | null;
}

export function useMemorialPosts(familyMemberId: string | undefined) {
  const [posts, setPosts] = useState<MemorialPost[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchPosts = useCallback(async () => {
    if (!familyMemberId) {
      setPosts([]);
      setLoading(false);
      return;
    }
    setLoading(true);
    const { data } = await (supabase as any)
      .from('memorial_posts')
      .select('*, author:profiles!memorial_posts_created_by_fkey(id, name, username, avatar_url)')
      .eq('family_member_id', familyMemberId)
      .order('created_at', { ascending: false });

    // If the join failed, fall back to plain select and do a manual profile lookup
    if (!data || (data.length > 0 && data[0].author === undefined)) {
      const { data: plain } = await (supabase as any)
        .from('memorial_posts')
        .select('*')
        .eq('family_member_id', familyMemberId)
        .order('created_at', { ascending: false });

      const plainPosts = (plain || []) as MemorialPost[];

      // Batch fetch author profiles
      const creatorIds = [...new Set(plainPosts.map((p) => p.created_by))];
      let profiles: MemorialPostAuthor[] = [];
      if (creatorIds.length > 0) {
        const { data: profileData } = await (supabase as any)
          .from('profiles')
          .select('id, name, username, avatar_url')
          .in('id', creatorIds);
        profiles = (profileData || []) as MemorialPostAuthor[];
      }

      const profileMap = new Map(profiles.map((p) => [p.id, p]));
      setPosts(plainPosts.map((p) => ({ ...p, author: profileMap.get(p.created_by) ?? null })));
    } else {
      setPosts((data || []) as MemorialPost[]);
    }

    setLoading(false);
  }, [familyMemberId]);

  useEffect(() => {
    fetchPosts();
  }, [fetchPosts]);

  async function addPost(file: File, caption: string) {
    if (!familyMemberId) return null;

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return null;

    // Upload to R2 via edge function
    const mediaUrl = await uploadMedia(file, 'memorial', user.id);

    const { data: newPost } = await (supabase as any)
      .from('memorial_posts')
      .insert({
        family_member_id: familyMemberId,
        created_by: user.id,
        media_url: mediaUrl,
        media_type: file.type.startsWith('video') ? 'video' : 'image',
        caption: caption || '',
      })
      .select()
      .single();

    if (newPost) {
      // Fetch author profile for the new post
      const { data: authorData } = await (supabase as any)
        .from('profiles')
        .select('id, name, username, avatar_url')
        .eq('id', user.id)
        .single();

      setPosts(prev => [{ ...newPost as MemorialPost, author: authorData ?? null }, ...prev]);
    }
    return newPost;
  }

  return { posts, loading, addPost, refetch: fetchPosts };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Post } from '@/types';

const MEMBER_MENTION_COLUMNS = ['family_member_id', 'family_tree_member_id', 'member_id'] as const;

const fetchMentionPostIdsForMembers = async (memberIds: string[]) => {
  if (memberIds.length === 0) return [] as string[];
  let lastErr: any = null;
  const columnErrors: string[] = [];
  for (const col of MEMBER_MENTION_COLUMNS) {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const sb: any = supabase;
    const { data, error } = await sb
      .from('post_mentions')
      .select('post_id, created_at')
      .in(col, memberIds)
      .order('created_at', { ascending: false });

    if (!error) {
      return (data || []).map((m: any) => m.post_id).filter(Boolean);
    }

    lastErr = error;
    const msg = String((error as any)?.message || '');
    if (msg.toLowerCase().includes('column')) {
      columnErrors.push(msg);
      continue;
    }

    break;
  }

  if (columnErrors.length === MEMBER_MENTION_COLUMNS.length) {
    throw new Error(
      "Supabase API schema cache yangilanmagan ko'rinadi: post_mentions jadvalida memorial ustun(lar)i topilmadi. " +
        "Kerakli ustun: post_mentions.family_member_id. Supabase Settings → API → Reload schema qiling va dev serverni qayta ishga tushiring."
    );
  }
  throw lastErr;
};

export interface MentionedPost extends Post {
  mentionedAt: string;
}

export interface CollabRequest {
  id: string;
  post_id: string;
  user_id: string;
  status: 'pending' | 'accepted' | 'rejected';
  created_at: string;
  post?: {
    id: string;
    content: string | null;
    media_urls: string[] | null;
    user_id: string;
  };
  author?: {
    id: string;
    name: string | null;
    username: string | null;
    avatar_url: string | null;
  };
}

export const useMentionsCollabs = (userId?: string, isMemorial?: boolean) => {
  const { user } = useAuth();
  const targetId = userId || user?.id;
  const [mentionedPosts, setMentionedPosts] = useState<Post[]>([]);
  const [collabPosts, setCollabPosts] = useState<Post[]>([]);
  const [pendingCollabs, setPendingCollabs] = useState<CollabRequest[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const fetchMentionedPosts = useCallback(async () => {
    if (!targetId) return;
    try {
      let targetIds = [targetId];

      if (isMemorial) {
        // Also fetch any members merged into this one
        const { data: merged } = await supabase
          .from('family_tree_members')
          .select('id')
          .eq('merged_into', targetId);
          
        if (merged && merged.length > 0) {
          targetIds = [...targetIds, ...merged.map(m => m.id)];
        }
      }

      // 1) Standard @mentions for living users
      let mentionPostIds: string[] = [];
      if (!isMemorial) {
        const { data: mentions } = await supabase
          .from('post_mentions')
          .select('post_id, created_at')
          .in('mentioned_user_id', targetIds)
          .order('created_at', { ascending: false });

        mentionPostIds = (mentions || []).map(m => m.post_id);
      }

      // 2) Memorial posts left for this user's linked family member node(s)
      // If someone leaves a "xotira post" for a living user via their family tree node,
      // it is stored as post_mentions.family_member_id.
      let memoryTargetPostIds: string[] = [];
      if (!isMemorial) {
        const { data: myMemberRows, error: myMemberErr } = await supabase
          .from('family_tree_members')
          .select('id')
          .eq('linked_user_id', targetId);

        if (myMemberErr) throw myMemberErr;

        const myMemberIds = (myMemberRows || []).map(r => r.id).filter(Boolean);
        if (myMemberIds.length > 0) {
          memoryTargetPostIds = await fetchMentionPostIdsForMembers(myMemberIds);
        }
      }

      // 3) Memorial profile mentions (xotira sahifasi ichida @ tab) - keep existing behavior
      let memorialMentionPostIds: string[] = [];
      if (isMemorial) {
        memorialMentionPostIds = await fetchMentionPostIdsForMembers(targetIds);
      }

      const allPostIds = [...new Set([
        ...mentionPostIds,
        ...memoryTargetPostIds,
        ...memorialMentionPostIds,
      ])];
      
      if (allPostIds.length === 0) {
        setMentionedPosts([]);
        return;
      }

      const { data: posts } = await supabase
        .from('posts')
        .select('*')
        .in('id', allPostIds)
        .order('created_at', { ascending: false });

      if (!posts || posts.length === 0) {
        setMentionedPosts([]);
        return;
      }

      const authorIds = [...new Set(posts.map(p => p.user_id))];
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url, bio')
        .in('id', authorIds);

      const enriched = posts.map(post => ({
        ...post,
        media_urls: post.media_urls || [],
        author: profiles?.find(p => p.id === post.user_id)
          ? {
              id: post.user_id,
              full_name: profiles.find(p => p.id === post.user_id)?.name || '',
              username: profiles.find(p => p.id === post.user_id)?.username || '',
              bio: profiles.find(p => p.id === post.user_id)?.bio || '',
              avatar_url: profiles.find(p => p.id === post.user_id)?.avatar_url || '',
              cover_url: '',
              instagram: '',
              telegram: '',
              followers_count: 0,
              following_count: 0,
              relatives_count: 0,
              created_at: post.created_at,
            }
          : undefined,
      }));

      setMentionedPosts(enriched);
    } catch (e) {
      console.error('Error fetching mentioned posts:', e);
    }
  }, [targetId, isMemorial]);

  const fetchCollabPosts = useCallback(async () => {
    if (!targetId) return;
    try {
      const { data: collabs } = await supabase
        .from('post_collabs')
        .select('post_id')
        .eq('user_id', targetId)
        .eq('status', 'accepted');

      if (!collabs || collabs.length === 0) {
        setCollabPosts([]);
        return;
      }

      const postIds = collabs.map(c => c.post_id);
      const { data: posts } = await supabase
        .from('posts')
        .select('*')
        .in('id', postIds)
        .order('created_at', { ascending: false });

      if (!posts || posts.length === 0) {
        setCollabPosts([]);
        return;
      }

      const authorIds = [...new Set(posts.map(p => p.user_id))];
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url, bio')
        .in('id', authorIds);

      const enriched = posts.map(post => ({
        ...post,
        media_urls: post.media_urls || [],
        author: profiles?.find(p => p.id === post.user_id)
          ? {
              id: post.user_id,
              full_name: profiles.find(p => p.id === post.user_id)?.name || '',
              username: profiles.find(p => p.id === post.user_id)?.username || '',
              bio: profiles.find(p => p.id === post.user_id)?.bio || '',
              avatar_url: profiles.find(p => p.id === post.user_id)?.avatar_url || '',
              cover_url: '',
              instagram: '',
              telegram: '',
              followers_count: 0,
              following_count: 0,
              relatives_count: 0,
              created_at: post.created_at,
            }
          : undefined,
      }));

      setCollabPosts(enriched);
    } catch (e) {
      console.error('Error fetching collab posts:', e);
    }
  }, [targetId]);

  const fetchPendingCollabs = useCallback(async () => {
    if (!user?.id) return;
    try {
      const { data } = await supabase
        .from('post_collabs')
        .select('*')
        .eq('user_id', user.id)
        .eq('status', 'pending')
        .order('created_at', { ascending: false });

      if (!data || data.length === 0) {
        setPendingCollabs([]);
        return;
      }

      // Fetch post info
      const postIds = data.map(c => c.post_id);
      const { data: posts } = await supabase
        .from('posts')
        .select('id, content, media_urls, user_id')
        .in('id', postIds);

      // Fetch authors
      const authorIds = [...new Set((posts || []).map(p => p.user_id))];
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url')
        .in('id', authorIds);

      const enriched: CollabRequest[] = data.map(collab => ({
        ...collab,
        status: collab.status as 'pending' | 'accepted' | 'rejected',
        post: posts?.find(p => p.id === collab.post_id) || undefined,
        author: (() => {
          const post = posts?.find(p => p.id === collab.post_id);
          return post ? profiles?.find(p => p.id === post.user_id) || undefined : undefined;
        })(),
      }));

      setPendingCollabs(enriched);
    } catch (e) {
      console.error('Error fetching pending collabs:', e);
    }
  }, [user?.id]);

  const respondToCollab = async (collabId: string, accept: boolean) => {
    try {
      const collab = pendingCollabs.find(c => c.id === collabId);
      
      await supabase
        .from('post_collabs')
        .update({ status: accept ? 'accepted' : 'rejected', updated_at: new Date().toISOString() })
        .eq('id', collabId);

      setPendingCollabs(prev => prev.filter(c => c.id !== collabId));

      if (accept && collab?.post?.user_id && user?.id) {
        // Send collab_accepted notification
        await supabase.from('notifications').insert({
          user_id: collab.post.user_id,
          actor_id: user.id,
          type: 'collab_accepted',
          post_id: collab.post_id,
        });

        // Send a message to the post author
        const authorId = collab.post.user_id;
        // Find or create conversation
        const { data: existing } = await supabase
          .from('conversations')
          .select('id')
          .or(`and(participant1_id.eq.${user.id},participant2_id.eq.${authorId}),and(participant1_id.eq.${authorId},participant2_id.eq.${user.id})`)
          .maybeSingle();

        let convId = existing?.id;
        if (!convId) {
          const { data: newConv } = await supabase
            .from('conversations')
            .insert({ participant1_id: user.id, participant2_id: authorId })
            .select('id')
            .single();
          convId = newConv?.id;
        }

        if (convId) {
          await supabase.from('messages').insert({
            conversation_id: convId,
            sender_id: user.id,
            content: `✅ Hamkorlik so'rovini qabul qildim! Postingizda hamkor sifatida ko'rinaman.`,
          });
          // Update conversation timestamp
          await supabase.from('conversations').update({ last_message_at: new Date().toISOString() }).eq('id', convId);
        }

        fetchCollabPosts();
      }
    } catch (e) {
      console.error('Error responding to collab:', e);
    }
  };

  const addMentions = async (postId: string, userIds: string[]) => {
    if (userIds.length === 0) return;
    try {
      const rows = userIds.map(uid => ({ post_id: postId, mentioned_user_id: uid }));
      const { error: mentionError } = await supabase.from('post_mentions').insert(rows);
      if (mentionError) {
        console.error('Mention insert error:', mentionError);
        return;
      }

      // Send notifications
      for (const uid of userIds) {
        if (uid !== user?.id) {
          const { error: notifError } = await supabase.from('notifications').insert({
            user_id: uid,
            actor_id: user!.id,
            type: 'mention',
            post_id: postId,
          });
          if (notifError) console.error('Mention notification error:', notifError);
        }
      }
    } catch (e) {
      console.error('Error adding mentions:', e);
    }
  };

  const addCollabs = async (postId: string, userIds: string[]) => {
    if (userIds.length === 0) return;
    try {
      const rows = userIds.map(uid => ({ post_id: postId, user_id: uid }));
      const { error: collabError } = await supabase.from('post_collabs').insert(rows);
      if (collabError) {
        console.error('Collab insert error:', collabError);
        return;
      }

      // Send notifications
      for (const uid of userIds) {
        if (uid !== user?.id) {
          const { error: notifError } = await supabase.from('notifications').insert({
            user_id: uid,
            actor_id: user!.id,
            type: 'collab_request',
            post_id: postId,
          });
          if (notifError) console.error('Collab notification error:', notifError);
        }
      }
    } catch (e) {
      console.error('Error adding collabs:', e);
    }
  };

  useEffect(() => {
    setIsLoading(true);
    Promise.all([fetchMentionedPosts(), fetchCollabPosts(), fetchPendingCollabs()])
      .finally(() => setIsLoading(false));
  }, [fetchMentionedPosts, fetchCollabPosts, fetchPendingCollabs]);

  return {
    mentionedPosts,
    collabPosts,
    pendingCollabs,
    isLoading,
    addMentions,
    addCollabs,
    respondToCollab,
    refetchMentions: fetchMentionedPosts,
    refetchCollabs: fetchCollabPosts,
    refetchPending: fetchPendingCollabs,
  };
};

import { useState, useCallback, useMemo } from 'react';
import { FamilyMember } from '@/types/family';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import { 
  MergeCandidate, 
  ChildProfile, 
  ChildMergeSuggestion, 
  CoupleGroup, 
  calculateSimilarity,
  computeMatchScore,
  birthYearScore,
} from './useTreeMerging';
import { MergeDialogData } from './useFamilyInvitations';

export interface MergeSuggestion {
  sourceId: string;
  targetId: string;
  sourceName: string;
  targetName: string;
  reason: string;
  gender: 'male' | 'female';
}

export interface MergedProfile {
  primaryId: string;
  mergedIds: string[];
  mergedNames: string[];
}

export const useMergeMode = (members: Record<string, FamilyMember>) => {
  const { user } = useAuth();
  const [isActive, setIsActive] = useState(false);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [mergedProfiles, setMergedProfiles] = useState<Map<string, MergedProfile>>(new Map());
  const [isProcessing, setIsProcessing] = useState(false);

  const startMergeMode = useCallback((memberId: string) => {
    setIsActive(true);
    setSelectedIds([memberId]);
  }, []);

  const toggleSelection = useCallback((memberId: string) => {
    if (!isActive) return;
    
    const member = members[memberId];
    const firstMember = members[selectedIds[0]];
    
    if (firstMember && member && firstMember.gender !== member.gender) {
      toast.error("Faqat bir xil jinsdagi profillarni birlashtirish mumkin");
      return;
    }
    
    setSelectedIds(prev => {
      if (prev.includes(memberId)) {
        if (prev[0] === memberId) {
          cancelMerge();
          return [];
        }
        return prev.filter(id => id !== memberId);
      }
      return [...prev, memberId];
    });
  }, [isActive, members, selectedIds]);

  const cancelMerge = useCallback(() => {
    setIsActive(false);
    setSelectedIds([]);
  }, []);

  /**
   * Tanlangan profillardan MergeDialogData yaratish
   */
  const computeMergeData = useCallback((): MergeDialogData | null => {
    if (selectedIds.length < 2) return null;
    
    const primaryId = selectedIds[0];
    const primary = members[primaryId];
    if (!primary) return null;
    
    const parentMerges: MergeCandidate[] = [];
    const coupleGroups: CoupleGroup[] = [];
    
    for (const otherId of selectedIds.slice(1)) {
      const other = members[otherId];
      if (!other) continue;
      
      // Asosiy birlashtirish: tanlangan profillar
      parentMerges.push({
        sourceId: primaryId,
        targetId: otherId,
        sourceName: primary.name,
        targetName: other.name,
        sourcePhotoUrl: primary.photoUrl,
        targetPhotoUrl: other.photoUrl,
        relationship: 'parent',
      });
      
      // Ota-onalarni birlashtirish tavsiyasi
      const primaryParentIds = primary.parentIds || [];
      const otherParentIds = other.parentIds || [];
      
      const coupleParentMerges: MergeCandidate[] = [];
      const matchedPrimary = new Set<string>();
      const matchedOther = new Set<string>();
      
      for (const ppId of primaryParentIds) {
        const pp = members[ppId];
        if (!pp) continue;
        for (const opId of otherParentIds) {
          const op = members[opId];
          if (!op) continue;
          if (pp.gender === op.gender && ppId !== opId && !matchedPrimary.has(ppId) && !matchedOther.has(opId)) {
            const merge: MergeCandidate = {
              sourceId: ppId,
              targetId: opId,
              sourceName: pp.name,
              targetName: op.name,
              sourcePhotoUrl: pp.photoUrl,
              targetPhotoUrl: op.photoUrl,
              relationship: 'parent',
            };
            parentMerges.push(merge);
            coupleParentMerges.push(merge);
            matchedPrimary.add(ppId);
            matchedOther.add(opId);
          }
        }
      }
      
      // Farzandlarni topish (birthYear 30% ball uchun)
      const getChildren = (memberId: string): ChildProfile[] => {
        const m = members[memberId];
        if (!m) return [];
        const childIds = new Set(m.childrenIds || []);
        if (m.spouseId && members[m.spouseId]) {
          (members[m.spouseId].childrenIds || []).forEach(id => childIds.add(id));
        }
        return [...childIds]
          .filter(id => members[id])
          .map(id => ({
            id,
            name: members[id].name,
            photoUrl: members[id].photoUrl,
            gender: members[id].gender,
            birthYear: members[id].birthYear,
          }));
      };

      const sourceChildren = getChildren(primaryId);
      const targetChildren = getChildren(otherId);

      // Tavsiyalar: ball bo‘yicha eng yaxshi juftliklar birinchi (keraklisi keraklisi bilan)
      const allPairs: { source: ChildProfile; target: ChildProfile; score: number }[] = [];
      const MERGE_THRESHOLD = 1;

      for (const sc of sourceChildren) {
        for (const t of targetChildren) {
          if (t.gender !== sc.gender) continue;
          const nameSim = calculateSimilarity(sc.name, t.name);
          const birthSim = birthYearScore(sc.birthYear, t.birthYear);
          const score = computeMatchScore(nameSim, birthSim, 100, 0);
          if (score >= MERGE_THRESHOLD) {
            allPairs.push({ source: sc, target: t, score });
          }
        }
      }
      allPairs.sort((a, b) => b.score - a.score);

      const childSuggestions: ChildMergeSuggestion[] = [];
      const usedSourceIds = new Set<string>();
      const usedTargetIds = new Set<string>();
      for (const { source, target, score } of allPairs) {
        if (usedSourceIds.has(source.id) || usedTargetIds.has(target.id)) continue;
        childSuggestions.push({ sourceChild: source, targetChild: target, similarity: score });
        usedSourceIds.add(source.id);
        usedTargetIds.add(target.id);
      }
      
      if (sourceChildren.length > 0 || targetChildren.length > 0) {
        coupleGroups.push({
          label: `${primary.name} va ${other.name}`,
          parentMerges: coupleParentMerges,
          sourceChildren,
          targetChildren,
          childSuggestions,
        });
      }
    }
    
    return {
      senderName: primary.name,
      receiverName: selectedIds.slice(1).map(id => members[id]?.name || '').join(', '),
      parentMerges,
      coupleGroups,
      childSuggestions: coupleGroups.flatMap(g => g.childSuggestions),
      allSourceChildren: coupleGroups.flatMap(g => g.sourceChildren),
      allTargetChildren: coupleGroups.flatMap(g => g.targetChildren),
    };
  }, [selectedIds, members]);

  // Direct merge execution (backward compat)
  const executeMerge = useCallback(async () => {
    if (selectedIds.length < 2 || !user?.id) return;
    
    setIsProcessing(true);
    
    try {
      const primaryId = selectedIds[0];
      const primary = members[primaryId];
      if (!primary) throw new Error('Primary member not found');
      
      const mergedIds = selectedIds.slice(1);
      const mergedNames = mergedIds.map(id => members[id]?.name || 'Noma\'lum');
      
      for (const mergedId of mergedIds) {
        const merged = members[mergedId];
        if (!merged) continue;
        
        await supabase
          .from('family_tree_members')
          .update({ 
            merged_into: primaryId,
            updated_at: new Date().toISOString()
          })
          .eq('id', mergedId);
        
        if (merged.linkedUserId && !primary.linkedUserId) {
          await supabase
            .from('family_tree_members')
            .update({ 
              linked_user_id: merged.linkedUserId,
              is_placeholder: false 
            })
            .eq('id', primaryId);
        }
      }
      
      setMergedProfiles(prev => {
        const next = new Map(prev);
        const existing = next.get(primaryId);
        next.set(primaryId, {
          primaryId,
          mergedIds: existing ? [...existing.mergedIds, ...mergedIds] : mergedIds,
          mergedNames: existing ? [...existing.mergedNames, ...mergedNames] : mergedNames,
        });
        return next;
      });
      
      toast.success(`${mergedIds.length} ta profil birlashtirildi`);
      cancelMerge();
      
      window.dispatchEvent(new CustomEvent('family-tree-reload'));
      
    } catch (error) {
      console.error('Error executing merge:', error);
      toast.error('Birlashtirishda xatolik');
    } finally {
      setIsProcessing(false);
    }
  }, [selectedIds, members, user?.id, cancelMerge]);

  const suggestions = useMemo((): MergeSuggestion[] => {
    if (selectedIds.length < 2) return [];
    // Keeping for backward compat but suggestions now go through computeMergeData
    return [];
  }, [selectedIds]);

  const applySuggestion = useCallback((suggestion: MergeSuggestion) => {
    setSelectedIds(prev => {
      const newIds = [...prev];
      if (!newIds.includes(suggestion.sourceId)) newIds.push(suggestion.sourceId);
      if (!newIds.includes(suggestion.targetId)) newIds.push(suggestion.targetId);
      return newIds;
    });
  }, []);

  return {
    isActive,
    selectedIds,
    mergedProfiles,
    suggestions,
    isProcessing,
    startMergeMode,
    toggleSelection,
    cancelMerge,
    executeMerge,
    computeMergeData,
    applySuggestion,
  };
};

import { useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { getCache, setCache } from '@/lib/localCache';

export interface Message {
  id: string;
  conversation_id: string;
  sender_id: string;
  content: string;
  status: 'sent' | 'delivered' | 'seen';
  created_at: string;
  updated_at: string;
  media_url?: string | null;
  media_type?: 'image' | 'video' | 'audio' | null;
}

const cacheKey = (convId: string) => `messages_cache_${convId}`;

const PAGE_SIZE = 30;

type Cursor = {
  oldestCreatedAt: string | null;
  hasMore: boolean;
};

const memoryCache = new Map<string, Message[]>();
const memoryCursorCache = new Map<string, Cursor>();

export const useMessages = (conversationId: string | null) => {
  const { user } = useAuth();
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const [hasMore, setHasMore] = useState(false);
  const [oldestCreatedAt, setOldestCreatedAt] = useState<string | null>(null);
  const [otherUserTyping, setOtherUserTyping] = useState(false);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout>>();

  // Load from cache first (memory -> localStorage)
  useEffect(() => {
    if (!conversationId) return;

    const mem = memoryCache.get(conversationId);
    if (mem && mem.length > 0) {
      setMessages(mem);
      const cur = memoryCursorCache.get(conversationId);
      if (cur) {
        setOldestCreatedAt(cur.oldestCreatedAt);
        setHasMore(cur.hasMore);
      }
      setIsLoading(false);
      return;
    }

    const cached = getCache<Message[]>(cacheKey(conversationId));
    if (cached && cached.length > 0) {
      setMessages(cached);
      memoryCache.set(conversationId, cached);
      setIsLoading(false);

      const oldest = cached[0]?.created_at ?? null;
      const cursor = { oldestCreatedAt: oldest, hasMore: cached.length >= PAGE_SIZE };
      setOldestCreatedAt(cursor.oldestCreatedAt);
      setHasMore(cursor.hasMore);
      memoryCursorCache.set(conversationId, cursor);
    }
  }, [conversationId]);

  const updateCursor = useCallback((convId: string, nextMessages: Message[]) => {
    const oldest = nextMessages[0]?.created_at ?? null;
    const cursor: Cursor = {
      oldestCreatedAt: oldest,
      hasMore: nextMessages.length >= PAGE_SIZE
    };
    setOldestCreatedAt(cursor.oldestCreatedAt);
    setHasMore(cursor.hasMore);
    memoryCursorCache.set(convId, cursor);
  }, []);

  const fetchMessages = useCallback(async () => {
    if (!conversationId) return;

    if (messages.length === 0) {
      setIsLoading(true);
    }

    try {
      // Fetch only last PAGE_SIZE messages initially
      const { data, error } = await supabase
        .from('messages')
        .select('*')
        .eq('conversation_id', conversationId)
        .order('created_at', { ascending: false })
        .limit(PAGE_SIZE);

      if (error) throw error;
      const msgs = ((data || []) as Message[]).slice().reverse();
      setMessages(msgs);
      setCache(cacheKey(conversationId), msgs);
      memoryCache.set(conversationId, msgs);
      updateCursor(conversationId, msgs);

      // Mark messages as seen
      if (user?.id && data && data.length > 0) {
        await supabase
          .from('messages')
          .update({ status: 'seen' })
          .eq('conversation_id', conversationId)
          .neq('sender_id', user.id)
          .neq('status', 'seen');
      }
    } catch (error) {
      console.error('Error fetching messages:', error);
    } finally {
      setIsLoading(false);
    }
  }, [conversationId, messages.length, updateCursor, user?.id]);

  const loadOlder = useCallback(async () => {
    if (!conversationId) return;
    if (!oldestCreatedAt) return;
    if (!hasMore) return;
    if (isLoadingMore) return;

    setIsLoadingMore(true);
    try {
      const { data, error } = await supabase
        .from('messages')
        .select('*')
        .eq('conversation_id', conversationId)
        .lt('created_at', oldestCreatedAt)
        .order('created_at', { ascending: false })
        .limit(PAGE_SIZE);

      if (error) throw error;
      const older = ((data || []) as Message[]).slice().reverse();
      if (older.length === 0) {
        setHasMore(false);
        memoryCursorCache.set(conversationId, { oldestCreatedAt, hasMore: false });
        return;
      }

      setMessages((prev) => {
        const merged = [...older, ...prev];
        setCache(cacheKey(conversationId), merged);
        memoryCache.set(conversationId, merged);
        updateCursor(conversationId, merged);
        return merged;
      });
    } catch (error) {
      console.error('Error loading older messages:', error);
    } finally {
      setIsLoadingMore(false);
    }
  }, [conversationId, hasMore, isLoadingMore, oldestCreatedAt, updateCursor]);

  useEffect(() => {
    fetchMessages();
  }, [fetchMessages]);

  // Real-time subscription for messages
  useEffect(() => {
    if (!conversationId) return;

    const channel = supabase
      .channel(`messages-${conversationId}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'messages',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          const newMessage = payload.new as Message;
          setMessages(prev => {
            const updated = [...prev, newMessage];
            setCache(cacheKey(conversationId), updated);
            memoryCache.set(conversationId, updated);
            updateCursor(conversationId, updated);
            return updated;
          });
          
          // Mark as seen if from other user
          if (user?.id && newMessage.sender_id !== user.id) {
            supabase
              .from('messages')
              .update({ status: 'seen' })
              .eq('id', newMessage.id)
              .then();
          }
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'messages',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          const updatedMessage = payload.new as Message;
          setMessages(prev => {
            const updated = prev.map(m => m.id === updatedMessage.id ? updatedMessage : m);
            setCache(cacheKey(conversationId), updated);
            memoryCache.set(conversationId, updated);
            return updated;
          });
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'DELETE',
          schema: 'public',
          table: 'messages',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          const deletedId = (payload.old as any).id;
          setMessages(prev => {
            const updated = prev.filter(m => m.id !== deletedId);
            setCache(cacheKey(conversationId), updated);
            memoryCache.set(conversationId, updated);
            updateCursor(conversationId, updated);
            return updated;
          });
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [conversationId, user?.id]);

  // Typing indicator subscription
  useEffect(() => {
    if (!conversationId || !user?.id) return;

    const channel = supabase
      .channel(`typing-${conversationId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'typing_indicators',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          if (payload.new && (payload.new as any).user_id !== user.id) {
            setOtherUserTyping((payload.new as any).is_typing);
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [conversationId, user?.id]);

  const sendMessage = async (content: string, mediaUrl?: string, mediaType?: string) => {
    if (!conversationId || !user?.id) return null;
    
    if (!content.trim() && !mediaUrl) return null;

    try {
      const messageData: any = {
        conversation_id: conversationId,
        sender_id: user.id,
        content: content.trim() || (mediaType === 'audio' ? '🎤 Ovozli xabar' : '📎 Media'),
        status: 'sent'
      };

      if (mediaUrl) {
        messageData.media_url = mediaUrl;
        messageData.media_type = mediaType;
      }

      const { data, error } = await supabase
        .from('messages')
        .insert(messageData)
        .select()
        .single();

      if (error) throw error;
      return data as Message;
    } catch (error) {
      console.error('Error sending message:', error);
      return null;
    }
  };

  const setTyping = useCallback(async (isTyping: boolean) => {
    if (!conversationId || !user?.id) return;

    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }

    try {
      await supabase
        .from('typing_indicators')
        .upsert({
          conversation_id: conversationId,
          user_id: user.id,
          is_typing: isTyping,
          updated_at: new Date().toISOString()
        }, {
          onConflict: 'conversation_id,user_id'
        });

      if (isTyping) {
        typingTimeoutRef.current = setTimeout(() => {
          setTyping(false);
        }, 3000);
      }
    } catch (error) {
      console.error('Error setting typing:', error);
    }
  }, [conversationId, user?.id]);

  return {
    messages,
    isLoading,
    isLoadingMore,
    hasMore,
    otherUserTyping,
    sendMessage,
    setTyping,
    loadOlder,
    refetch: fetchMessages
  };
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface PostCollection {
  id: string;
  user_id: string;
  name: string;
  cover_url: string | null;
  theme?: number | null;
  sort_order: number;
  created_at: string;
  posts_count?: number;
}

export const usePostCollections = (userId?: string) => {
  const { user } = useAuth();
  const [collections, setCollections] = useState<PostCollection[]>([]);
  const [selectedCollectionId, setSelectedCollectionId] = useState<string | null>(null);
  const [collectionPosts, setCollectionPosts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const targetUserId = userId || user?.id;

  const fetchCollections = useCallback(async () => {
    if (!targetUserId) { setCollections([]); setIsLoading(false); return; }
    
    try {
      const { data, error } = await supabase
        .from('post_collections')
        .select('*')
        .eq('user_id', targetUserId)
        .order('sort_order', { ascending: true });

      if (error) throw error;

      if (!data || data.length === 0) {
        setCollections([]);
        setIsLoading(false);
        return;
      }

      // Count items per collection
      const { data: items } = await supabase
        .from('post_collection_items')
        .select('collection_id')
        .in('collection_id', data.map(c => c.id));

      const countMap = new Map<string, number>();
      items?.forEach(i => countMap.set(i.collection_id, (countMap.get(i.collection_id) || 0) + 1));

      setCollections(data.map(c => ({ ...c, posts_count: countMap.get(c.id) || 0 })));
    } catch (error) {
      console.error('Error fetching collections:', error);
    } finally {
      setIsLoading(false);
    }
  }, [targetUserId]);

  const fetchCollectionPosts = useCallback(async (collectionId: string) => {
    const { data: items } = await supabase
      .from('post_collection_items')
      .select('post_id')
      .eq('collection_id', collectionId)
      .order('sort_order', { ascending: true });

    if (!items || items.length === 0) { setCollectionPosts([]); return; }

    const postIds = items.map(i => i.post_id);
    const { data: posts } = await supabase
      .from('posts')
      .select('*')
      .in('id', postIds);

    if (!posts) { setCollectionPosts([]); return; }

    // Get profiles
    const userIds = [...new Set(posts.map(p => p.user_id))];
    const { data: profiles } = await supabase.from('profiles').select('id, name, username, avatar_url').in('id', userIds);

    const enriched = posts.map(p => ({
      ...p,
      author: profiles?.find(pr => pr.id === p.user_id) || null,
    }));

    // Maintain order from collection items
    const ordered = postIds.map(pid => enriched.find(p => p.id === pid)).filter(Boolean);
    setCollectionPosts(ordered);
  }, []);

  const createCollection = async (name: string, theme?: number) => {
    if (!user) return null;

    const sort_order = collections.length;
    const themeValue = Number.isFinite(theme as number) ? (theme as number) : (collections.length % 6);

    const attemptWithTheme = await supabase
      .from('post_collections')
      .insert({ user_id: user.id, name, sort_order, theme: themeValue })
      .select()
      .single();

    if (!attemptWithTheme.error) {
      await fetchCollections();
      return attemptWithTheme.data;
    }

    const msg = (attemptWithTheme.error as any)?.message || String(attemptWithTheme.error);
    if (/theme/i.test(msg) && /(column|field)/i.test(msg)) {
      const attemptWithoutTheme = await supabase
        .from('post_collections')
        .insert({ user_id: user.id, name, sort_order })
        .select()
        .single();
      if (attemptWithoutTheme.error) {
        console.error(attemptWithoutTheme.error);
        return null;
      }
      await fetchCollections();
      return attemptWithoutTheme.data;
    }

    console.error(attemptWithTheme.error);
    return null;
  };

  const updateCollection = async (id: string, updates: { name?: string; cover_url?: string | null; theme?: number | null }) => {
    const { error } = await supabase.from('post_collections').update(updates).eq('id', id);
    if (!error) {
      await fetchCollections();
      return;
    }

    const msg = (error as any)?.message || String(error);
    if ('theme' in updates && /theme/i.test(msg) && /(column|field)/i.test(msg)) {
      const { theme: _theme, ...rest } = updates;
      const retry = await supabase.from('post_collections').update(rest).eq('id', id);
      if (!retry.error) await fetchCollections();
      else console.error(retry.error);
      return;
    }

    console.error(error);
  };

  const deleteCollection = async (id: string) => {
    const { error } = await supabase.from('post_collections').delete().eq('id', id);
    if (!error) { await fetchCollections(); if (selectedCollectionId === id) setSelectedCollectionId(null); }
  };

  const addPostToCollection = async (collectionId: string, postId: string) => {
    const { error } = await supabase.from('post_collection_items').insert({ collection_id: collectionId, post_id: postId });
    if (error) console.error(error);
    else await fetchCollections();
  };

  const removePostFromCollection = async (collectionId: string, postId: string) => {
    const { error } = await supabase.from('post_collection_items').delete()
      .eq('collection_id', collectionId).eq('post_id', postId);
    if (!error) await fetchCollections();
  };

  useEffect(() => { fetchCollections(); }, [fetchCollections]);

  useEffect(() => {
    if (selectedCollectionId) fetchCollectionPosts(selectedCollectionId);
    else setCollectionPosts([]);
  }, [selectedCollectionId, fetchCollectionPosts]);

  return {
    collections, isLoading, selectedCollectionId, collectionPosts,
    setSelectedCollectionId, fetchCollections,
    createCollection, updateCollection, deleteCollection,
    addPostToCollection, removePostFromCollection, fetchCollectionPosts,
  };
};

import { useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

interface LikeUser {
  id: string;
  name: string | null;
  username: string | null;
  avatar_url: string | null;
}

// Simple in-memory cache
const likeCache = new Map<string, { isLiked: boolean; count: number; timestamp: number }>();
const CACHE_TTL = 2 * 60 * 1000; // 2 minutes

type LikeSyncEvent = { postId: string; isLiked: boolean; count: number };
const likeSyncEmitter = new EventTarget();
const emitLikeSync = (e: LikeSyncEvent) => {
  likeSyncEmitter.dispatchEvent(new CustomEvent<LikeSyncEvent>('post-like-sync', { detail: e }));
};

export const usePostLikes = (postId: string) => {
  const { user } = useAuth();
  const userId = user?.id;
  
  const [isLiked, setIsLiked] = useState(false);
  const [likesCount, setLikesCount] = useState(0);
  const [likedUsers, setLikedUsers] = useState<LikeUser[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);
  const abortRef = useRef<AbortController | null>(null);

  // Update cache helper
  const updateCache = useCallback((liked: boolean, count: number) => {
    likeCache.set(postId, { isLiked: liked, count, timestamp: Date.now() });
    emitLikeSync({ postId, isLiked: liked, count });
  }, [postId]);

  useEffect(() => {
    if (!postId) return;
    const handler = (evt: Event) => {
      const ce = evt as CustomEvent<LikeSyncEvent>;
      if (!ce.detail || ce.detail.postId !== postId) return;
      setIsLiked(ce.detail.isLiked);
      setLikesCount(ce.detail.count);
    };
    likeSyncEmitter.addEventListener('post-like-sync', handler);
    return () => likeSyncEmitter.removeEventListener('post-like-sync', handler);
  }, [postId]);

  // Check like status from DB
  const checkLikeStatus = useCallback(async (): Promise<boolean> => {
    if (!userId) return false;
    
    const { data } = await supabase
      .from('post_likes')
      .select('id')
      .eq('post_id', postId)
      .eq('user_id', userId)
      .maybeSingle();
    
    return !!data;
  }, [postId, userId]);

  // Get likes count from DB
  const fetchLikesCount = useCallback(async (): Promise<number> => {
    const { count } = await supabase
      .from('post_likes')
      .select('*', { count: 'exact', head: true })
      .eq('post_id', postId);
    
    return count || 0;
  }, [postId]);

  // Fetch users who liked (for dialog)
  const fetchLikedUsers = useCallback(async () => {
    const { data: likes } = await supabase
      .from('post_likes')
      .select('user_id')
      .eq('post_id', postId)
      .order('created_at', { ascending: false })
      .limit(50);

    if (likes && likes.length > 0) {
      const userIds = likes.map(l => l.user_id);
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url')
        .in('id', userIds);

      setLikedUsers(profiles || []);
    } else {
      setLikedUsers([]);
    }
  }, [postId]);

  // OPTIMISTIC Toggle like
  const toggleLike = useCallback(async () => {
    if (!userId || isLoading) return;

    // Cancel pending request
    if (abortRef.current) {
      abortRef.current.abort();
    }

    const prevIsLiked = isLiked;
    const prevCount = likesCount;

    // OPTIMISTIC UPDATE - instant UI change
    const newIsLiked = !isLiked;
    const newCount = newIsLiked ? likesCount + 1 : Math.max(0, likesCount - 1);
    
    setIsLiked(newIsLiked);
    setLikesCount(newCount);
    updateCache(newIsLiked, newCount);

    setIsLoading(true);
    abortRef.current = new AbortController();

    try {
      if (prevIsLiked) {
        // Unlike
        const { error } = await supabase
          .from('post_likes')
          .delete()
          .eq('post_id', postId)
          .eq('user_id', userId);
        
        if (error) throw error;
      } else {
        // Like
        const { error } = await supabase
          .from('post_likes')
          .insert({ post_id: postId, user_id: userId });
        
        if (error) throw error;

        // Get post owner and create notification
        const { data: post } = await supabase
          .from('posts')
          .select('user_id')
          .eq('id', postId)
          .single();

        if (post && post.user_id !== userId) {
          // Avoid accidental duplicates (e.g. rapid toggles / retries)
          const { data: existing } = await supabase
            .from('notifications')
            .select('id')
            .eq('user_id', post.user_id)
            .eq('actor_id', userId)
            .eq('type', 'like')
            .eq('post_id', postId)
            .order('created_at', { ascending: false })
            .limit(1)
            .maybeSingle();

          if (!existing) {
            const { error: notifError } = await supabase.from('notifications').insert({
              user_id: post.user_id,
              actor_id: userId,
              type: 'like',
              post_id: postId,
              comment_id: null,
              message_id: null,
              is_read: false,
            });

            if (notifError) {
              console.error('Error creating like notification:', notifError);
            }
          }
        }
      }
    } catch (error: any) {
      if (error?.name === 'AbortError') return;
      
      console.error('Error toggling like:', error);
      // ROLLBACK on error
      setIsLiked(prevIsLiked);
      setLikesCount(prevCount);
      updateCache(prevIsLiked, prevCount);
    } finally {
      setIsLoading(false);
      abortRef.current = null;
    }
  }, [userId, isLoading, isLiked, likesCount, postId, updateCache]);

  // Initialize from cache or fetch from DB
  useEffect(() => {
    if (!postId) return;
    
    let isMounted = true;

    const init = async () => {
      // Check cache first
      const cached = likeCache.get(postId);
      if (cached && (Date.now() - cached.timestamp) < CACHE_TTL) {
        if (isMounted) {
          setIsLiked(cached.isLiked);
          setLikesCount(cached.count);
          setIsInitialized(true);
          emitLikeSync({ postId, isLiked: cached.isLiked, count: cached.count });
        }
        return;
      }

      // Fetch from DB
      try {
        const [liked, count] = await Promise.all([
          checkLikeStatus(),
          fetchLikesCount()
        ]);

        if (isMounted) {
          setIsLiked(liked);
          setLikesCount(count);
          updateCache(liked, count);
          setIsInitialized(true);
          emitLikeSync({ postId, isLiked: liked, count });
        }
      } catch (error) {
        console.error('Error initializing likes:', error);
        if (isMounted) {
          setIsInitialized(true);
        }
      }
    };

    init();

    return () => {
      isMounted = false;
    };
  }, [postId, checkLikeStatus, fetchLikesCount, updateCache]);

  // Re-check when user changes (login/logout) - using stable userId
  useEffect(() => {
    if (isInitialized) {
      checkLikeStatus().then(liked => {
        setIsLiked(liked);
        updateCache(liked, likesCount);
        emitLikeSync({ postId, isLiked: liked, count: likesCount });
      });
    }
    // Only react to userId changes, not the whole effect dependencies
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [userId]);

  return {
    isLiked,
    likesCount,
    likedUsers,
    isLoading,
    toggleLike,
    fetchLikedUsers,
    refresh: async () => {
      likeCache.delete(postId);
      const [liked, count] = await Promise.all([
        checkLikeStatus(),
        fetchLikesCount()
      ]);
      setIsLiked(liked);
      setLikesCount(count);
      updateCache(liked, count);
      emitLikeSync({ postId, isLiked: liked, count });
    }
  };
};

import { useCallback, useEffect, useRef, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';

export const usePostViews = (postId: string, initialCount?: number) => {
  const [viewsCount, setViewsCount] = useState<number>(initialCount ?? 0);
  const [viewedUsers, setViewedUsers] = useState<Array<{id: string;name: string | null;username: string | null;avatar_url: string | null;}>>([]);
  const [isTracking, setIsTracking] = useState(false);
  const hasTrackedRef = useRef(false);

  useEffect(() => {
    if (initialCount !== undefined) setViewsCount(initialCount);
  }, [initialCount]);

  useEffect(() => {
    hasTrackedRef.current = false;
  }, [postId]);

  const fetchViewsCount = async () => {
    if (!postId) return;
    try {
      const { data, error } = await supabase
        .from('posts')
        .select('views_count')
        .eq('id', postId)
        .single();
      if (!error && data) {
        setViewsCount((data as any).views_count ?? 0);
      }
    } catch (e) {
      // ignore
    }
  };

  const trackView = async () => {
    if (!postId || isTracking || hasTrackedRef.current) return;
    setIsTracking(true);
    hasTrackedRef.current = true;
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) {
        setViewsCount(prev => prev + 1);
        return;
      }
      const { error } = await supabase
        .from('post_views')
        .upsert({ post_id: postId, user_id: user.id }, { onConflict: 'post_id,user_id', ignoreDuplicates: true });
      
      if (!error) {
        setViewsCount(prev => prev + 1);
      }
      // If unique constraint violation / conflict, user already viewed - that's fine
    } catch (error) {
      const msg = String((error as any)?.message || '');
      if (!msg.toLowerCase().includes('conflict') && !msg.toLowerCase().includes('duplicate')) {
        console.error('Error tracking view:', error);
      }
    } finally {
      setIsTracking(false);
    }
  };

  const fetchViewedUsers = useCallback(async () => {
    if (!postId) return;
    const { data: views } = await supabase
      .from('post_views')
      .select('user_id')
      .eq('post_id', postId)
      .order('created_at', { ascending: false })
      .limit(50);

    if (views && views.length > 0) {
      const userIds = views.map((v: any) => v.user_id);
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url')
        .in('id', userIds);
      setViewedUsers(profiles || []);
    } else {
      setViewedUsers([]);
    }
  }, [postId]);

  return {
    viewsCount,
    setViewsCount,
    trackView,
    isTracking,
    fetchViewsCount,
    viewedUsers,
    fetchViewedUsers,
  };
};

// Hook for intersection observer to detect when post is visible
export const useIntersectionObserver = (
  elementRef: React.RefObject<Element>,
  onIntersect: () => void,
  options: IntersectionObserverInit = {}
) => {
  useEffect(() => {
    const element = elementRef.current;
    if (!element) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            onIntersect();
          }
        });
      },
      {
        threshold: 0.5,
        ...options
      }
    );

    observer.observe(element);

    return () => {
      observer.disconnect();
    };
  }, [elementRef, onIntersect, options]);
};

import { useCallback, useEffect, useMemo, useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';

export type SavedMusicRow = {
  id: string;
  user_id: string;
  audio_url: string;
  audio_title: string | null;
  audio_artist: string | null;
  created_at: string;
};

export function useSavedMusic() {
  const { user } = useAuth();
  const [items, setItems] = useState<SavedMusicRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const savedUrlSet = useMemo(() => new Set(items.map((i) => i.audio_url)), [items]);

  const fetchSaved = useCallback(async () => {
    if (!user) {
      setItems([]);
      return;
    }
    setIsLoading(true);
    try {
      const { data, error } = await (supabase as any)
        .from('saved_tracks')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });
      if (error) throw error;
      setItems((data || []) as SavedMusicRow[]);
    } catch (e) {
      setItems([]);
    } finally {
      setIsLoading(false);
    }
  }, [user]);

  useEffect(() => {
    void fetchSaved();
  }, [fetchSaved]);

  const isSaved = useCallback(
    (audioUrl?: string | null) => {
      if (!audioUrl) return false;
      return savedUrlSet.has(audioUrl);
    },
    [savedUrlSet]
  );

  const save = useCallback(
    async (payload: { audio_url: string; audio_title?: string | null; audio_artist?: string | null }) => {
      if (!user) return;
      await (supabase as any).from('saved_tracks').upsert(
        {
          user_id: user.id,
          audio_url: payload.audio_url,
          audio_title: payload.audio_title ?? null,
          audio_artist: payload.audio_artist ?? null,
        },
        { onConflict: 'user_id,audio_url' }
      );
      await fetchSaved();
    },
    [fetchSaved, user]
  );

  const unsave = useCallback(
    async (audioUrl: string) => {
      if (!user) return;
      await (supabase as any).from('saved_tracks').delete().eq('user_id', user.id).eq('audio_url', audioUrl);
      await fetchSaved();
    },
    [fetchSaved, user]
  );

  return {
    items,
    isLoading,
    fetchSaved,
    isSaved,
    save,
    unsave,
  };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Post } from '@/types';

export interface SavedMemorialPost {
  id: string;
  isMemorial: true;
  media_url: string | null;
  media_type: string | null;
  caption: string | null;
  created_by: string;
  created_at: string;
  likes_count?: number;
  views_count?: number;
  savedAt: string;
  author?: {
    id: string;
    name: string | null;
    username: string | null;
    avatar_url: string | null;
  } | null;
}

export type SavedItem = Post | SavedMemorialPost;

export const isMemorialSave = (item: SavedItem): item is SavedMemorialPost =>
  (item as SavedMemorialPost).isMemorial === true;

export const useSavedPosts = (targetUserId?: string) => {
  const { user } = useAuth();
  const effectiveUserId = targetUserId || user?.id;

  const [savedPosts, setSavedPosts] = useState<Post[]>([]);
  const [savedMemorialPosts, setSavedMemorialPosts] = useState<SavedMemorialPost[]>([]);
  const [savedPostIds, setSavedPostIds] = useState<Set<string>>(new Set());
  const [isLoading, setIsLoading] = useState(true);

  const fetchSavedPosts = useCallback(async () => {
    if (!effectiveUserId) {
      setSavedPosts([]);
      setSavedMemorialPosts([]);
      setSavedPostIds(new Set());
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    try {
      // ── Regular saved posts ──────────────────────────────────────────
      const { data: savedData, error: savedError } = await supabase
        .from('saved_posts')
        .select('post_id, created_at')
        .eq('user_id', effectiveUserId)
        .order('created_at', { ascending: false });

      if (savedError) throw savedError;

      const postIds = savedData?.map(s => s.post_id) || [];
      setSavedPostIds(new Set(postIds));

      let finalPosts: Post[] = [];
      if (postIds.length > 0) {
        const { data: postsData } = await supabase
          .from('posts')
          .select('*')
          .in('id', postIds);

        if (postsData && postsData.length > 0) {
          const userIds = [...new Set(postsData.map(p => p.user_id))];
          const { data: profiles } = await supabase
            .from('profiles')
            .select('*')
            .in('id', userIds);

          finalPosts = postIds
            .map(postId => {
              const post = postsData.find(p => p.id === postId);
              if (!post) return null;
              const profile = profiles?.find(p => p.id === post.user_id);
              return {
                ...post,
                media_urls: post.media_urls || [],
                author: profile ? {
                  id: post.user_id,
                  full_name: profile.name || 'Foydalanuvchi',
                  username: profile.username || 'user',
                  bio: profile.bio || '',
                  avatar_url: profile.avatar_url || '',
                  cover_url: '',
                  instagram: '',
                  telegram: '',
                  followers_count: 0,
                  following_count: 0,
                  relatives_count: 0,
                  created_at: post.created_at,
                } : undefined
              };
            })
            .filter((p): p is NonNullable<typeof p> => p !== null) as Post[];
        }
      }
      setSavedPosts(finalPosts);

      // ── Memorial saved posts ─────────────────────────────────────────
      const { data: memSavedData } = await (supabase as any)
        .from('memorial_post_saves')
        .select('memorial_post_id, created_at')
        .eq('user_id', effectiveUserId)
        .order('created_at', { ascending: false });

      const memPostIds: string[] = (memSavedData || []).map((s: any) => s.memorial_post_id);

      if (memPostIds.length > 0) {
        const { data: memPosts } = await (supabase as any)
          .from('memorial_posts')
          .select('*')
          .in('id', memPostIds);

        const memCreatorIds = [...new Set((memPosts || []).map((p: any) => p.created_by))];
        let memProfiles: any[] = [];
        if (memCreatorIds.length > 0) {
          const { data: profs } = await (supabase as any)
            .from('profiles')
            .select('id, name, username, avatar_url')
            .in('id', memCreatorIds);
          memProfiles = profs || [];
        }
        const profileMap = new Map(memProfiles.map((p: any) => [p.id, p]));

        const normalizedMemSaves: SavedMemorialPost[] = memPostIds
          .map((id: string) => {
            const mp = (memPosts || []).find((p: any) => p.id === id);
            if (!mp) return null;
            const savedEntry = (memSavedData || []).find((s: any) => s.memorial_post_id === id);
            return {
              id: mp.id,
              isMemorial: true as const,
              media_url: mp.media_url,
              media_type: mp.media_type,
              caption: mp.caption,
              created_by: mp.created_by,
              created_at: mp.created_at,
              likes_count: mp.likes_count || 0,
              views_count: mp.views_count || 0,
              savedAt: savedEntry?.created_at || mp.created_at,
              author: profileMap.get(mp.created_by) ?? null,
            };
          })
          .filter((p: any): p is SavedMemorialPost => p !== null);

        setSavedMemorialPosts(normalizedMemSaves);
      } else {
        setSavedMemorialPosts([]);
      }
    } catch (error) {
      console.error('Error fetching saved posts:', error);
    } finally {
      setIsLoading(false);
    }
  }, [effectiveUserId]);

  useEffect(() => {
    fetchSavedPosts();
  }, [fetchSavedPosts]);

  const toggleSavePost = useCallback(async (postId: string) => {
    if (!user) return false;

    const isSaved = savedPostIds.has(postId);

    if (isSaved) {
      setSavedPostIds(prev => { const s = new Set(prev); s.delete(postId); return s; });
      setSavedPosts(prev => prev.filter(p => p.id !== postId));
    } else {
      setSavedPostIds(prev => new Set([...prev, postId]));
    }

    try {
      if (isSaved) {
        const { error } = await supabase
          .from('saved_posts')
          .delete()
          .eq('user_id', user.id)
          .eq('post_id', postId);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('saved_posts')
          .insert({ user_id: user.id, post_id: postId });
        if (error) throw error;

        const { data: postData } = await supabase
          .from('posts')
          .select('*')
          .eq('id', postId)
          .single();

        if (postData) {
          const { data: profile } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', postData.user_id)
            .single();

          const newPost: Post = {
            ...postData,
            media_urls: postData.media_urls || [],
            author: profile ? {
              id: postData.user_id,
              full_name: profile.name || 'Foydalanuvchi',
              username: profile.username || 'user',
              bio: profile.bio || '',
              avatar_url: profile.avatar_url || '',
              cover_url: '',
              instagram: '',
              telegram: '',
              followers_count: 0,
              following_count: 0,
              relatives_count: 0,
              created_at: postData.created_at,
            } : undefined
          };
          setSavedPosts(prev => [newPost, ...prev]);
        }
      }
      return !isSaved;
    } catch (error) {
      console.error('Error toggling save post:', error);
      if (isSaved) {
        setSavedPostIds(prev => new Set([...prev, postId]));
      } else {
        setSavedPostIds(prev => { const s = new Set(prev); s.delete(postId); return s; });
      }
      return isSaved;
    }
  }, [user, savedPostIds]);

  const isPostSaved = useCallback((postId: string) => {
    return savedPostIds.has(postId);
  }, [savedPostIds]);

  return {
    savedPosts,
    savedMemorialPosts,
    savedPostIds,
    isLoading,
    fetchSavedPosts,
    toggleSavePost,
    isPostSaved
  };
};

import { useState, useCallback, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { FamilyMember } from '@/types/family';
import { TreeOverlay } from '@/hooks/useTreePosts';

export interface FeedTreePost {
  id: string;
  user_id: string;
  title: string | null;
  tree_data: Record<string, FamilyMember>;
  positions_data: Record<string, { x: number; y: number }>;
  overlays: TreeOverlay[];
  caption: string | null;
  created_at: string;
  likes_count: number;
  author?: {
    name: string | null;
    username: string | null;
    avatar_url: string | null;
  };
}

export const useTreeFeed = () => {
  const [treePosts, setTreePosts] = useState<FeedTreePost[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const fetchTreePosts = useCallback(async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('tree_posts')
        .select('*')
        .eq('is_published', true)
        .order('created_at', { ascending: false })
        .limit(50);

      if (error) {
        console.error('Tree feed query error:', error);
        throw error;
      }
      if (!data || data.length === 0) { setTreePosts([]); return; }

      // Fetch authors
      const userIds = [...new Set(data.map(d => d.user_id))];
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url')
        .in('id', userIds);

      const profileMap = new Map((profiles || []).map(p => [p.id, p]));

      // Fetch likes counts
      const postIds = data.map(d => d.id);
      const { data: likes } = await supabase
        .from('tree_post_likes')
        .select('tree_post_id')
        .in('tree_post_id', postIds);

      const likesMap = new Map<string, number>();
      ((likes as any[]) || []).forEach((l: any) => {
        likesMap.set(l.tree_post_id, (likesMap.get(l.tree_post_id) || 0) + 1);
      });

      const parsed = data.map((d: any) => ({
        id: d.id,
        user_id: d.user_id,
        title: d.title,
        tree_data: (typeof d.tree_data === 'string' ? JSON.parse(d.tree_data) : d.tree_data) || {},
        positions_data: (typeof d.positions_data === 'string' ? JSON.parse(d.positions_data) : d.positions_data) || {},
        overlays: (typeof d.overlays === 'string' ? JSON.parse(d.overlays) : d.overlays) || [],
        caption: d.caption,
        created_at: d.created_at,
        likes_count: likesMap.get(d.id) || 0,
        author: profileMap.get(d.user_id) || undefined,
      }));

      console.log('Tree feed loaded:', parsed.length, 'posts');
      setTreePosts(parsed);
    } catch (err) {
      console.error('Error fetching tree feed:', err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchTreePosts(); }, [fetchTreePosts]);

  return { treePosts, isLoading, refetch: fetchTreePosts };
};

import { useState, useCallback, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { FamilyMember } from '@/types/family';
import { toast } from 'sonner';

export interface TreeOverlay {
  id: string;
  type: 'text' | 'sticker' | 'image';
  content: string; // text content, emoji, or image URL
  x: number;
  y: number;
  scale: number;
  rotation: number;
  fontSize?: number;
  color?: string;
}

export interface TreePost {
  id: string;
  user_id: string;
  title: string;
  tree_data: Record<string, FamilyMember>;
  positions_data: Record<string, { x: number; y: number }>;
  overlays: TreeOverlay[];
  caption: string | null;
  is_published: boolean;
  is_personal: boolean;
  created_at: string;
  updated_at: string;
}

export const useTreePosts = () => {
  const { user } = useAuth();
  const [posts, setPosts] = useState<TreePost[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [currentPostId, setCurrentPostId] = useState<string | null>(null);

  const loadPosts = useCallback(async () => {
    if (!user?.id) return;
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('tree_posts')
        .select('*')
        .eq('user_id', user.id)
        .order('updated_at', { ascending: false });

      if (error) throw error;
      setPosts((data || []).map((d: any) => ({
        ...d,
        tree_data: d.tree_data || {},
        positions_data: d.positions_data || {},
        overlays: d.overlays || [],
      })));
    } catch (err) {
      console.error('Error loading tree posts:', err);
    } finally {
      setIsLoading(false);
    }
  }, [user?.id]);

  useEffect(() => {
    loadPosts();
  }, [loadPosts]);

  const createTreePost = useCallback(async (
    members: Record<string, FamilyMember>,
    positions: Record<string, { x: number; y: number }>,
    title?: string,
    isPersonal = false
  ): Promise<string | null> => {
    if (!user?.id) return null;
    try {
      const { data, error } = await supabase
        .from('tree_posts')
        .insert({
          user_id: user.id,
          title: title || `Daraxt - ${new Date().toLocaleDateString('uz')}`,
          tree_data: members as any,
          positions_data: positions as any,
          overlays: [] as any,
          is_personal: isPersonal,
        })
        .select('id')
        .single();

      if (error) throw error;
      await loadPosts();
      toast.success('Yangi daraxt yaratildi');
      return data.id;
    } catch (err) {
      console.error('Error creating tree post:', err);
      toast.error('Xatolik yuz berdi');
      return null;
    }
  }, [user?.id, loadPosts]);

  const saveOverlays = useCallback(async (postId: string, overlays: TreeOverlay[]) => {
    if (!user?.id) return;
    try {
      await supabase
        .from('tree_posts')
        .update({ overlays: overlays as any, updated_at: new Date().toISOString() })
        .eq('id', postId)
        .eq('user_id', user.id);
    } catch (err) {
      console.error('Error saving overlays:', err);
    }
  }, [user?.id]);

  const saveCaption = useCallback(async (postId: string, caption: string) => {
    if (!user?.id) return;
    try {
      await supabase
        .from('tree_posts')
        .update({ caption, updated_at: new Date().toISOString() })
        .eq('id', postId)
        .eq('user_id', user.id);
    } catch (err) {
      console.error('Error saving caption:', err);
    }
  }, [user?.id]);

  const publishPost = useCallback(async (postId: string, caption?: string) => {
    if (!user?.id) return false;
    try {
      const updates: any = { 
        is_published: true, 
        updated_at: new Date().toISOString() 
      };
      if (caption !== undefined) updates.caption = caption;
      
      await supabase
        .from('tree_posts')
        .update(updates)
        .eq('id', postId)
        .eq('user_id', user.id);

      await loadPosts();
      toast.success('Daraxt nashr qilindi!');
      return true;
    } catch (err) {
      console.error('Error publishing:', err);
      toast.error('Xatolik yuz berdi');
      return false;
    }
  }, [user?.id, loadPosts]);

  const deletePost = useCallback(async (postId: string) => {
    if (!user?.id) return;
    try {
      await supabase
        .from('tree_posts')
        .delete()
        .eq('id', postId)
        .eq('user_id', user.id);

      await loadPosts();
      if (currentPostId === postId) setCurrentPostId(null);
      toast.success("O'chirildi");
    } catch (err) {
      console.error('Error deleting:', err);
      toast.error('Xatolik yuz berdi');
    }
  }, [user?.id, loadPosts, currentPostId]);

  const updateTitle = useCallback(async (postId: string, title: string) => {
    if (!user?.id) return;
    await supabase
      .from('tree_posts')
      .update({ title, updated_at: new Date().toISOString() })
      .eq('id', postId)
      .eq('user_id', user.id);
    await loadPosts();
  }, [user?.id, loadPosts]);

  const currentPost = posts.find(p => p.id === currentPostId) || null;

  return {
    posts,
    currentPost,
    currentPostId,
    setCurrentPostId,
    isLoading,
    createTreePost,
    saveOverlays,
    saveCaption,
    publishPost,
    deletePost,
    updateTitle,
    loadPosts,
  };
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

interface UnfollowRecord {
  id: string;
  unfollowed_user_id: string;
  created_at: string;
  profile?: { name: string | null; username: string | null; avatar_url: string | null };
}

export type UnfollowHistoryMode = 'incoming';

interface UseUnfollowHistoryOptions {
  mode?: UnfollowHistoryMode;
  enabled?: boolean;
  userId?: string;
}

export const useUnfollowHistory = (options?: UseUnfollowHistoryOptions) => {
  const { user } = useAuth();
  const [history, setHistory] = useState<UnfollowRecord[]>([]);

  const RETENTION_DAYS = 30;

  const getCutoffIso = useCallback(() => {
    const d = new Date();
    d.setDate(d.getDate() - RETENTION_DAYS);
    return d.toISOString();
  }, []);

  const fetchHistory = useCallback(async () => {
    const ownerId = options?.userId || user?.id;
    if (!ownerId) return;
    if (options?.enabled === false) return;
    const cutoffIso = getCutoffIso();

    // Cleanup old records only for the current user's own history (RLS allows delete when auth.uid() = user_id).
    if (user?.id && ownerId === user.id) {
      await supabase.from('unfollow_history').delete().eq('user_id', ownerId).lt('created_at', cutoffIso);
    }

    const { data } = await supabase
      .from('unfollow_history')
      .select('*')
      .eq('user_id', ownerId)
      .gte('created_at', cutoffIso)
      .order('created_at', { ascending: false })
      .limit(50);
    
    if (data && data.length > 0) {
      const userIds = data.map(d => d.unfollowed_user_id);
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url')
        .in('id', userIds);
      
      const profileMap = new Map((profiles || []).map(p => [p.id, p]));
      setHistory(data.map(d => ({ ...d, profile: profileMap.get(d.unfollowed_user_id) || undefined })));
    } else {
      setHistory([]);
    }
  }, [getCutoffIso, options?.enabled, options?.userId, user?.id]);

  useEffect(() => {
    if (options?.enabled === false) return;
    fetchHistory();
  }, [fetchHistory, options?.enabled]);

  const recordUnfollow = useCallback(async (unfollowedUserId: string) => {
    // Record "incoming" unfollow for the user who got unfollowed.
    // user_id = owner of history (unfollowedUserId)
    // unfollowed_user_id = actor who unfollowed (current user)
    if (!user?.id) return;

    // Insert is allowed by RLS policy (see migration) where actor is auth.uid() = unfollowed_user_id.
    await supabase.from('unfollow_history').insert({ user_id: unfollowedUserId, unfollowed_user_id: user.id });
  }, [getCutoffIso, user?.id]);

  return { history, recordUnfollow, refetch: fetchHistory };
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Post } from '@/types';

const MEMBER_MENTION_COLUMNS = ['family_member_id', 'family_tree_member_id', 'member_id'] as const;

const fetchMentionPostIdsForMember = async (memberId: string) => {
  let lastErr: any = null;
  const columnErrors: string[] = [];
  for (const col of MEMBER_MENTION_COLUMNS) {
    // Prevent excessively deep type instantiation when using dynamic column names
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const sb: any = supabase;
    const { data, error } = await sb
      .from('post_mentions')
      .select('post_id')
      .eq(col, memberId);

    if (!error) {
      const postIds = (data || []).map((r: any) => r.post_id).filter(Boolean);
      return { postIds };
    }

    lastErr = error;
    const msg = String((error as any)?.message || '');
    if (msg.toLowerCase().includes('column')) {
      columnErrors.push(msg);
      continue;
    }

    break;
  }

  if (columnErrors.length === MEMBER_MENTION_COLUMNS.length) {
    throw new Error(
      "Supabase API schema cache yangilanmagan ko'rinadi: post_mentions jadvalida memorial ustun(lar)i topilmadi. " +
        "Kerakli ustun: post_mentions.family_member_id. Supabase Settings → API → Reload schema qiling va dev serverni qayta ishga tushiring."
    );
  }
  throw lastErr;
};

export const useUserPosts = (userId: string | undefined, isMemorial: boolean = false) => {
  const [posts, setPosts] = useState<Post[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [postsCount, setPostsCount] = useState(0);

  const fetchUserPosts = useCallback(async () => {
    if (!userId) {
      setPosts([]);
      setPostsCount(0);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    try {
      let postsData: any[] | null = null;

      if (isMemorial) {
        const { postIds } = await fetchMentionPostIdsForMember(userId);
        setPostsCount(postIds.length);

        if (postIds.length === 0) {
          setPosts([]);
          return;
        }

        const { data, error } = await supabase
          .from('posts')
          .select('*')
          .in('id', postIds)
          .order('created_at', { ascending: false });

        if (error) throw error;
        postsData = data || [];
      } else {
        const { data, error } = await supabase
          .from('posts')
          .select('*')
          .eq('user_id', userId)
          .order('created_at', { ascending: false });

        if (error) throw error;
        postsData = data || [];
        setPostsCount(postsData.length);
      }

      if (postsData && postsData.length > 0) {
        // Fetch profiles for the authors of these posts
        const authorIds = [...new Set(postsData.map(p => p.user_id))];
        const { data: profiles } = await supabase
          .from('profiles')
          .select('*')
          .in('id', authorIds);

        const postsWithAuthor = postsData.map(post => {
          const profile = profiles?.find(p => p.id === post.user_id);
          return {
            ...post,
            media_urls: post.media_urls || [],
            author: profile ? {
              id: profile.id,
              full_name: profile.name || 'Foydalanuvchi',
              username: profile.username || 'user',
              bio: profile.bio || '',
              avatar_url: profile.avatar_url || '',
              cover_url: '',
              instagram: '',
              telegram: '',
              followers_count: 0,
              following_count: 0,
              relatives_count: 0,
              created_at: post.created_at,
            } : undefined
          };
        });

        setPosts(postsWithAuthor);
      } else {
        setPosts([]);
      }
    } catch (error) {
      console.error('Error fetching user posts:', error);
    } finally {
      setIsLoading(false);
    }
  }, [userId, isMemorial]);

  useEffect(() => {
    fetchUserPosts();
  }, [fetchUserPosts]);

  const removePost = (postId: string) => {
    setPosts(prev => prev.filter(p => p.id !== postId));
    setPostsCount(prev => Math.max(0, prev - 1));
  };

  return { posts, isLoading, postsCount, refetch: fetchUserPosts, removePost };
};

import { useState, useEffect, useCallback, useRef } from 'react';
import DailyIframe, { DailyCall, DailyParticipant, DailyEventObject } from '@daily-co/daily-js';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import { clearLocalCallNotification } from '@/lib/pushNotifications';
import { ForegroundService } from '@capawesome-team/capacitor-android-foreground-service';

interface Call {
  id: string;
  caller_id: string;
  receiver_id: string;
  room_url: string;
  room_name: string;
  status: string;
  created_at: string;
}

export const useVideoCall = (otherUserId: string | null) => {
  const { user } = useAuth();
  const [callObject, setCallObject] = useState<DailyCall | null>(null);
  const [isInCall, setIsInCall] = useState(false);
  const [wasInCall, setWasInCall] = useState(false);
  const [partnerLeft, setPartnerLeft] = useState(false);
  const [isCreatingRoom, setIsCreatingRoom] = useState(false);
  const [incomingCall, setIncomingCall] = useState<Call | null>(null);
  const [currentCall, setCurrentCall] = useState<Call | null>(null);
  const [cameraOn, setCameraOn] = useState(true);
  const [micOn, setMicOn] = useState(true);
  const [remoteParticipant, setRemoteParticipant] = useState<DailyParticipant | null>(null);
  const callHistorySavedRef = useRef(false);
  const callObjectRef = useRef<DailyCall | null>(null);
  const reconnectAttemptsRef = useRef(0);
  const maxReconnectAttempts = 3;

  const [lastRoomUrl, setLastRoomUrl] = useState<string | null>(null);

  // Keep ref in sync
  useEffect(() => {
    callObjectRef.current = callObject;
  }, [callObject]);

  // Subscribe to incoming calls
  useEffect(() => {
    if (!user?.id) return;

    const channel = supabase
      .channel('incoming-calls')
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'calls',
          filter: `receiver_id=eq.${user.id}`,
        },
        (payload) => {
          const call = payload.new as Call;
          if (call.status === 'pending') {
            setIncomingCall(call);
          }
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'calls',
        },
        (payload) => {
          const call = payload.new as Call;
          
          if (call.status === 'ended') {
            if (currentCall?.id === call.id || incomingCall?.id === call.id) {
              // Don't call leaveCall() directly to avoid clearing everything if we want to show "Call Ended" UI
              // But for now, let's keep it simple
              if (callObjectRef.current) {
                callObjectRef.current.leave().catch(() => undefined);
              }
              setIsInCall(false);
              setRemoteParticipant(null);
              toast.info("Qo'ng'iroq tugadi");
            }
            if (incomingCall?.id === call.id) {
              clearLocalCallNotification(call.caller_id);
            }
            setIncomingCall(null);
          }
          
          if (call.status === 'active' && currentCall?.id === call.id) {
            setCurrentCall(call);
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id, currentCall?.id, incomingCall?.id]);

  // Cleanup on unmount
  useEffect(() => {
    // Listen for foreground service button clicks (e.g. "Tugatish" button)
    const setupForegroundListener = async () => {
      try {
        await ForegroundService.removeAllListeners();
        await ForegroundService.addListener('buttonTapped', (event) => {
          if (event.buttonId === 1) {
            // "Tugatish" was clicked
            leaveCall();
          }
        });
      } catch (e) {
        // usually fails on web/iOS, ignore
      }
    };
    
    setupForegroundListener();

    return () => {
      try { ForegroundService.removeAllListeners(); } catch (e) {}
      const co = callObjectRef.current;
      if (co) {
        try {
          co.leave();
          co.destroy();
        } catch {
          // ignore
        }
      }
    };
  }, []);

  const startCall = useCallback(async () => {
    if (!otherUserId || !user?.id || isCreatingRoom) return;

    setIsCreatingRoom(true);
    
    try {
      const { data, error } = await supabase.functions.invoke('create-daily-room', {
        body: { receiver_id: otherUserId },
      });

      if (error) throw error;
      
      setCurrentCall(data.call);
      setLastRoomUrl(data.room_url);
      callHistorySavedRef.current = false;
      
      await joinRoom(data.room_url);
      
    } catch (error) {
      console.error('Error starting call:', error);
      toast.error("Qo'ng'iroqni boshlashda xatolik");
    } finally {
      setIsCreatingRoom(false);
    }
  }, [otherUserId, user?.id, isCreatingRoom]);

  const answerCall = useCallback(async () => {
    if (!incomingCall) return;

    try {
      await supabase
        .from('calls')
        .update({ status: 'active' })
        .eq('id', incomingCall.id);

      setCurrentCall(incomingCall);
      setLastRoomUrl(incomingCall.room_url);
      callHistorySavedRef.current = false;
      await joinRoom(incomingCall.room_url);
      clearLocalCallNotification(incomingCall.caller_id);
      setIncomingCall(null);
      
    } catch (error) {
      console.error('Error answering call:', error);
      toast.error("Qo'ng'iroqqa javob berishda xatolik");
    }
  }, [incomingCall]);

  const rejoinCall = useCallback(async () => {
    if (!lastRoomUrl) return;
    await joinRoom(lastRoomUrl);
  }, [lastRoomUrl]);

  const declineCall = useCallback(async () => {
    if (!incomingCall) return;

    try {
      await supabase.functions.invoke('end-call', {
        body: { 
          call_id: incomingCall.id,
          room_name: incomingCall.room_name 
        },
      });
      
      clearLocalCallNotification(incomingCall.caller_id);
      setIncomingCall(null);
    } catch (error) {
      console.error('Error declining call:', error);
    }
  }, [incomingCall]);

  const joinRoom = async (roomUrl: string) => {
    try {
      // Destroy existing call object if any
      if (callObjectRef.current) {
        try {
          await callObjectRef.current.leave();
          callObjectRef.current.destroy();
        } catch {
          // ignore
        }
        setCallObject(null);
        callObjectRef.current = null;
      }

      reconnectAttemptsRef.current = 0;

      const newCallObject = DailyIframe.createCallObject({
        audioSource: true,
        videoSource: true,
      });

      newCallObject.on('joined-meeting', async () => {
        setIsInCall(true);
        setWasInCall(true);
        setPartnerLeft(false);
        reconnectAttemptsRef.current = 0;

        // Start Foreground Service so call doesn't drop when app is backgrounded
        try {
          await ForegroundService.startForegroundService({
            id: 2,
            title: "Avlodona Video Qo'ng'iroq",
            body: "Suhbat davom etmoqda... Qaytish uchun bosing",
            smallIcon: 'ic_stat_icon_config_sample',
            buttons: [
              { title: 'Tugatish', id: 1 }
            ],
            silent: true,
          });
        } catch (e) {
          console.error('Failed to start foreground service:', e);
        }
      });

      newCallObject.on('left-meeting', () => {
        setIsInCall(false);
        setRemoteParticipant(null);
        setPartnerLeft(false);
        
        try {
          ForegroundService.stopForegroundService();
        } catch (e) {}
      });

      newCallObject.on('participant-joined', (event: DailyEventObject) => {
        if (event?.participant && !event.participant.local) {
          setRemoteParticipant(event.participant);
          setPartnerLeft(false);
        }
      });

      newCallObject.on('participant-updated', (event: DailyEventObject) => {
        if (event?.participant && !event.participant.local) {
          setRemoteParticipant(event.participant);
          setPartnerLeft(false);
        }
      });

      newCallObject.on('participant-left', (event: DailyEventObject) => {
        if (event?.participant && !event.participant.local) {
          setRemoteParticipant(null);
          setPartnerLeft(true);
          toast.info("Suhbatdosh chiqib ketdi");
        }
      });

      // Handle network quality and reconnection
      newCallObject.on('network-quality-change', (event: DailyEventObject) => {
        const quality = (event as unknown as { quality?: string } | null)?.quality;
        if (quality === 'very-low') {
          toast.warning("Internet aloqasi yomon", { duration: 2000 });
        }
      });

      newCallObject.on('network-connection', (event: DailyEventObject) => {
        const evt = (event as unknown as { event?: string } | null)?.event;
        if (evt === 'interrupted') {
          toast.warning("Internet uzildi, qayta ulanmoqda...", { duration: 3000 });
        }
        if (evt === 'connected') {
          if (reconnectAttemptsRef.current > 0) {
            toast.success("Qayta ulandi!", { duration: 2000 });
          }
          reconnectAttemptsRef.current = 0;
        }
      });

      newCallObject.on('error', (event: DailyEventObject) => {
        console.error('Daily error:', event);
        const errorType = String(
          (event as unknown as { errorMsg?: unknown; error?: { type?: unknown } } | null)?.errorMsg ??
            (event as unknown as { error?: { type?: unknown } } | null)?.error?.type ??
            ''
        );
        
        // Camera/mic permission errors
        if (errorType.includes('not-allowed') || errorType.includes('NotAllowed')) {
          toast.error("Kamera yoki mikrofonga ruxsat bering");
          return;
        }
        
        // Device not found
        if (errorType.includes('not-found') || errorType.includes('NotFound')) {
          toast.error("Kamera yoki mikrofon topilmadi");
          // Continue call with available devices
          try {
            newCallObject.setLocalVideo(false);
            setCameraOn(false);
          } catch {
            // ignore
          }
          return;
        }

        // Network/connection errors - try reconnect
        if (reconnectAttemptsRef.current < maxReconnectAttempts) {
          reconnectAttemptsRef.current++;
          toast.error(`Xatolik yuz berdi, qayta urinish... (${reconnectAttemptsRef.current}/${maxReconnectAttempts})`);
          return;
        }

        toast.error("Video qo'ng'iroqda xatolik yuz berdi");
      });

      // Camera access error handling
      newCallObject.on('camera-error', (event: DailyEventObject) => {
        console.error('Camera error:', event);
        const errType = String((event as unknown as { error?: { type?: unknown } } | null)?.error?.type ?? '');
        if (errType === 'cam-in-use') {
          toast.error("Kamera boshqa ilova tomonidan ishlatilmoqda");
        } else if (errType === 'not-found') {
          toast.error("Kamera topilmadi");
        } else if (errType === 'permissions') {
          toast.error("Kameraga ruxsat berilmagan");
        } else {
          toast.error("Kamera xatosi");
        }
        setCameraOn(false);
      });

      setCallObject(newCallObject);
      callObjectRef.current = newCallObject;

      await newCallObject.join({ url: roomUrl });
      
    } catch (error: unknown) {
      console.error('Error joining room:', error);
      const msg = String((error as { message?: unknown } | null)?.message ?? '');
      
      // Specific error messages
      if (msg.includes('permission')) {
        toast.error("Kamera va mikrofonga ruxsat bering");
      } else if (msg.includes('network') || msg.includes('fetch')) {
        toast.error("Internet aloqasi yo'q");
      } else {
        toast.error("Xonaga qo'shilishda xatolik");
      }
    }
  };

  const leaveCall = useCallback(async () => {
    try {
      if (callObject) {
        try {
          await callObject.leave();
        } catch {
          // ignore
        }
        try {
          callObject.destroy();
        } catch {
          // ignore
        }
        setCallObject(null);
        callObjectRef.current = null;
      }
      
      try {
        await ForegroundService.stopForegroundService();
      } catch (e) {}

      if (currentCall) {
        try {
          await supabase.functions.invoke('end-call', {
            body: { 
              call_id: currentCall.id,
              room_name: currentCall.room_name 
            },
          });
        } catch (err) {
          console.error('Error ending call on server:', err);
        }

        // Save call history ONLY ONCE
        if (!callHistorySavedRef.current && user?.id) {
          callHistorySavedRef.current = true;
          try {
            const otherUserToSaveId = currentCall.caller_id === user.id 
              ? currentCall.receiver_id 
              : currentCall.caller_id;
            
            const { data: existing } = await supabase
              .from('conversations')
              .select('id')
              .or(`and(participant1_id.eq.${user.id},participant2_id.eq.${otherUserToSaveId}),and(participant1_id.eq.${otherUserToSaveId},participant2_id.eq.${user.id})`)
              .maybeSingle();

            let convId = existing?.id;
            if (!convId) {
              const { data: newConv } = await supabase
                .from('conversations')
                .insert({ participant1_id: user.id, participant2_id: otherUserToSaveId })
                .select('id')
                .single();
              convId = newConv?.id;
            }

            if (convId) {
              const startTime = new Date(currentCall.created_at);
              const endTime = new Date();
              const durationSec = Math.round((endTime.getTime() - startTime.getTime()) / 1000);
              const mins = Math.floor(durationSec / 60);
              const secs = durationSec % 60;
              const durationText = mins > 0 ? `${mins} daqiqa ${secs} soniya` : `${secs} soniya`;

              await supabase.from('messages').insert({
                conversation_id: convId,
                sender_id: user.id,
                content: `📹 Video qo'ng'iroq — ${durationText}`,
                status: 'sent',
              });
            }
          } catch (historyErr) {
            console.error('Error saving call history:', historyErr);
          }
        }
      }

      setIsInCall(false);
      // Don't clear currentCall or lastRoomUrl immediately so we can show Rejoin UI
      setRemoteParticipant(null);
      setPartnerLeft(false);
      setCameraOn(true);
      setMicOn(true);
      
    } catch (error) {
      console.error('Error leaving call:', error);
    }
  }, [callObject, currentCall, user?.id]);

  const endCallPermanently = useCallback(() => {
    leaveCall();
    setCurrentCall(null);
    setLastRoomUrl(null);
  }, [leaveCall]);

  const toggleCamera = useCallback(async () => {
    if (!callObject) return;
    try {
      const newState = !cameraOn;
      await callObject.setLocalVideo(newState);
      setCameraOn(newState);
    } catch (err) {
      console.error('Toggle camera error:', err);
      toast.error("Kamerani almashtirish imkonsiz");
    }
  }, [callObject, cameraOn]);

  const toggleMic = useCallback(async () => {
    if (!callObject) return;
    try {
      const newState = !micOn;
      await callObject.setLocalAudio(newState);
      setMicOn(newState);
    } catch (err) {
      console.error('Toggle mic error:', err);
      toast.error("Mikrofonni almashtirish imkonsiz");
    }
  }, [callObject, micOn]);

  return {
    isInCall,
    wasInCall,
    partnerLeft,
    isCreatingRoom,
    incomingCall,
    currentCall,
    cameraOn,
    micOn,
    callObject,
    remoteParticipant,
    lastRoomUrl,
    startCall,
    answerCall,
    rejoinCall,
    declineCall,
    leaveCall,
    endCallPermanently,
    toggleCamera,
    toggleMic,
  };
};

import { supabase } from '@/integrations/supabase/client';
import { uploadMedia } from '@/lib/r2Upload';

export type PublishTask = {
  id: string;
  userId: string;
  files: File[];
  storyFiles?: File[];
  caption: string;
  mentionIds: string[];
  collabIds: string[];
  postCollectionIds?: string[];
  ringId?: string;
  storyHighlightId?: string;
  sharePost: boolean;
  shareStory: boolean;
  audioFile?: File;
  audioMeta?: {
    audio_url?: string | null;
    audio_title?: string | null;
    audio_artist?: string | null;
  };
  memoryMemberId?: string;
};

const MEMBER_MENTION_COLUMNS = ['family_member_id', 'family_tree_member_id', 'member_id'] as const;

const insertMemoryMention = async (postId: string, memberId: string): Promise<void> => {
  for (const col of MEMBER_MENTION_COLUMNS) {
    const sb = supabase as unknown as Record<string, (t: string) => { insert: (r: Record<string, unknown>) => Promise<{ error: unknown }> }>;
    const { error } = await sb.from('post_mentions').insert({ post_id: postId, [col]: memberId });
    if (!error) return;
    const msg = String((error as { message?: string })?.message || '');
    // If it's a column-not-found error, try the next column name
    if (msg.toLowerCase().includes('column') || msg.toLowerCase().includes('does not exist')) continue;
    // Any other error — warn but don't throw so the post still saves
    console.warn('[insertMemoryMention] non-fatal error:', error);
    return;
  }
  // All columns failed — warn only, the memorial post itself saves fine without this extra row
  console.warn('[insertMemoryMention] could not link post to family member — schema may need fixing');
};

const ensureYearHighlight = async (userId: string) => {
  const year = new Date().getFullYear().toString();

  const { data: existing, error: findError } = await supabase
    .from('story_highlights')
    .select('id, name')
    .eq('user_id', userId)
    .eq('name', year)
    .maybeSingle();

  if (!findError && existing?.id) return existing.id as string;

  const { data: created, error: createError } = await supabase
    .from('story_highlights')
    .insert({ user_id: userId, name: year, cover_url: null, sort_order: 9999 })
    .select('id')
    .single();

  if (createError) throw createError;
  return created.id as string;
};

const addStoryToHighlight = async (highlightId: string, storyId: string, mediaUrl: string, mediaType: string, caption?: string | null) => {
  const { error } = await supabase.from('story_highlight_items').insert({
    highlight_id: highlightId,
    story_id: storyId,
    media_url: mediaUrl,
    media_type: mediaType,
    caption: caption || null,
  });
  if (error) throw error;
};

const mimeForAudio = (audio: File) => {
  const t = audio.type || '';
  if (t) return t;
  const name = audio.name.toLowerCase();
  if (name.endsWith('.mp3')) return 'audio/mpeg';
  if (name.endsWith('.wav')) return 'audio/wav';
  if (name.endsWith('.ogg')) return 'audio/ogg';
  if (name.endsWith('.m4a')) return 'audio/mp4';
  return 'audio/mpeg';
};

const getVideoDurationSeconds = async (file: File): Promise<number> => {
  const url = URL.createObjectURL(file);
  try {
    const video = document.createElement('video');
    video.src = url;
    video.preload = 'metadata';
    await new Promise<void>((resolve, reject) => {
      const ok = () => resolve();
      const err = () => reject(new Error('video load error'));
      video.addEventListener('loadedmetadata', ok, { once: true });
      video.addEventListener('error', err, { once: true });
      try {
        video.load();
      } catch {}
    });
    const d = Number.isFinite(video.duration) ? video.duration : 0;
    return d > 0 ? d : 0;
  } finally {
    URL.revokeObjectURL(url);
  }
};

const recordVideoSegment = async (file: File, startSec: number, endSec: number): Promise<File> => {
  const url = URL.createObjectURL(file);
  try {
    const video = document.createElement('video');
    video.src = url;
    video.preload = 'auto';
    (video as any).playsInline = true;
    video.muted = false;

    await new Promise<void>((resolve, reject) => {
      const ok = () => resolve();
      const err = () => reject(new Error('video load error'));
      video.addEventListener('loadedmetadata', ok, { once: true });
      video.addEventListener('error', err, { once: true });
      try {
        video.load();
      } catch {}
    });

    await new Promise<void>((resolve) => {
      const done = () => resolve();
      const onSeeked = () => {
        video.removeEventListener('seeked', onSeeked);
        resolve();
      };

      video.addEventListener('seeked', onSeeked);
      try {
        video.currentTime = Math.max(0, startSec);
      } catch {
        done();
      }
    });

    const stream = (video as any).captureStream?.() as MediaStream | undefined;
    if (!stream) return file;

    const mimeType = MediaRecorder.isTypeSupported('video/webm;codecs=vp9,opus')
      ? 'video/webm;codecs=vp9,opus'
      : (MediaRecorder.isTypeSupported('video/webm;codecs=vp8,opus') ? 'video/webm;codecs=vp8,opus' : 'video/webm');

    const recorder = new MediaRecorder(stream, { mimeType });
    const chunks: Blob[] = [];
    recorder.ondataavailable = (e) => {
      if (e.data.size > 0) chunks.push(e.data);
    };
    const done = new Promise<Blob>((resolve) => {
      recorder.onstop = () => resolve(new Blob(chunks, { type: 'video/webm' }));
    });

    recorder.start(250);
    await video.play().catch(() => undefined);

    await new Promise<void>((resolve) => {
      const stopIfPastEnd = () => {
        if (video.currentTime >= endSec || video.ended) {
          video.removeEventListener('timeupdate', stopIfPastEnd);
          resolve();
        }
      };
      video.addEventListener('timeupdate', stopIfPastEnd);
      stopIfPastEnd();
    });

    try {
      video.pause();
    } catch {}
    recorder.stop();

    const blob = await done;
    return new File([blob], `story-${Date.now()}-${Math.round(startSec)}.webm`, { type: 'video/webm' });
  } catch {
    return file;
  } finally {
    URL.revokeObjectURL(url);
  }
};

const splitVideoForStory = async (file: File, segmentSeconds = 60): Promise<File[]> => {
  const duration = await getVideoDurationSeconds(file);
  if (!duration || duration <= segmentSeconds) return [file];
  const segments: File[] = [];
  for (let s = 0; s < duration; s += segmentSeconds) {
    const seg = await recordVideoSegment(file, s, Math.min(duration, s + segmentSeconds));
    segments.push(seg);
  }
  return segments.length > 0 ? segments : [file];
};

const mixAudioIntoVideo = async (videoFile: File, audioFile: File): Promise<File> => {
  const videoUrl = URL.createObjectURL(videoFile);
  const audioUrl = URL.createObjectURL(audioFile);

  try {
    const videoEl = document.createElement('video');
    videoEl.src = videoUrl;
    videoEl.crossOrigin = 'anonymous';
    (videoEl as any).playsInline = true;
    videoEl.preload = 'auto';
    videoEl.muted = false;
    videoEl.volume = 0;

    await new Promise<void>((resolve, reject) => {
      const onLoaded = () => resolve();
      const onErr = () => reject(new Error('video load error'));
      videoEl.addEventListener('loadedmetadata', onLoaded, { once: true });
      videoEl.addEventListener('error', onErr, { once: true });
      try { videoEl.load(); } catch {}
    });

    const w = videoEl.videoWidth || 720;
    const h = videoEl.videoHeight || 1280;

    const canvas = document.createElement('canvas');
    canvas.width = w;
    canvas.height = h;
    const ctx = canvas.getContext('2d');
    if (!ctx) return videoFile;

    const canvasStream = (canvas as any).captureStream?.(30) as MediaStream;
    const videoTrack = canvasStream?.getVideoTracks?.()[0];

    let mixedStream: MediaStream;
    try {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const destination = audioCtx.createMediaStreamDestination();

      const audioEl = document.createElement('audio');
      audioEl.src = audioUrl;
      audioEl.crossOrigin = 'anonymous';
      audioEl.preload = 'auto';

      // Decode/playback pipeline requires a user gesture in some browsers; background publish usually starts from a user click.
      await new Promise<void>((resolve, reject) => {
        const ok = () => resolve();
        const err = () => reject(new Error('audio load error'));
        audioEl.addEventListener('canplay', ok, { once: true });
        audioEl.addEventListener('error', err, { once: true });
        try { audioEl.load(); } catch {}
      });

      const audioSource = audioCtx.createMediaElementSource(audioEl);
      const gain = audioCtx.createGain();
      gain.gain.value = 0.35;
      audioSource.connect(gain);
      gain.connect(destination);

      mixedStream = new MediaStream([
        ...(videoTrack ? [videoTrack] : []),
        ...destination.stream.getAudioTracks(),
      ]);

      const mimeType = MediaRecorder.isTypeSupported('video/webm;codecs=vp9,opus')
        ? 'video/webm;codecs=vp9,opus'
        : (MediaRecorder.isTypeSupported('video/webm;codecs=vp8,opus') ? 'video/webm;codecs=vp8,opus' : 'video/webm');

      const recorder = new MediaRecorder(mixedStream, { mimeType });
      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      const done = new Promise<Blob>((resolve) => {
        recorder.onstop = () => resolve(new Blob(chunks, { type: 'video/webm' }));
      });

      recorder.start(250);

      let raf = 0;
      const draw = () => {
        ctx.drawImage(videoEl, 0, 0, w, h);
        if (!videoEl.ended) raf = requestAnimationFrame(draw);
      };

      await videoEl.play().catch(() => undefined);
      await audioEl.play().catch(() => undefined);
      raf = requestAnimationFrame(draw);

      await new Promise<void>((resolve) => {
        const end = () => resolve();
        videoEl.addEventListener('ended', end, { once: true });
      });

      cancelAnimationFrame(raf);
      recorder.stop();
      const blob = await done;
      return new File([blob], `mixed-${Date.now()}.webm`, { type: 'video/webm' });
    } catch {
      return videoFile;
    }
  } finally {
    URL.revokeObjectURL(videoUrl);
    URL.revokeObjectURL(audioUrl);
  }
};

type PublishProgressEvent = {
  taskId: string;
  progress: number;
  status: 'uploading' | 'success' | 'error';
  message?: string;
};

const emitter = new EventTarget();

export const onPublishProgress = (handler: (e: PublishProgressEvent) => void) => {
  const listener = (evt: Event) => handler((evt as CustomEvent<PublishProgressEvent>).detail);
  emitter.addEventListener('publish-progress', listener);
  return () => emitter.removeEventListener('publish-progress', listener);
};

const emit = (detail: PublishProgressEvent) => {
  emitter.dispatchEvent(new CustomEvent('publish-progress', { detail }));
};

export const startBackgroundPublish = (task: PublishTask) => {
  void runPublish(task);
};

const runPublish = async (task: PublishTask) => {
  try {
    if (!task.sharePost && !task.shareStory) {
      emit({ taskId: task.id, progress: 0, status: 'error', message: 'Post yoki Story-dan kamida birini tanlang' });
      return;
    }

    emit({ taskId: task.id, progress: 5, status: 'uploading' });

    const storyInputFiles = Array.isArray(task.storyFiles) && task.storyFiles.length > 0 ? task.storyFiles : task.files.slice(0, 1);
    const total = (task.sharePost ? task.files.length : 0) + (task.shareStory ? storyInputFiles.length : 0) + 1 + (task.audioFile ? 1 : 0);
    let done = 0;
    const tick = () => {
      done += 1;
      const next = Math.min(95, Math.round((done / total) * 90) + 5);
      emit({ taskId: task.id, progress: next, status: 'uploading' });
    };

    // Upload audio file (optional)
    let audioUrl: string | null = null;
    if (task.audioFile) {
      audioUrl = await uploadMedia(new File([task.audioFile], task.audioFile.name, { type: mimeForAudio(task.audioFile) }), 'audio', task.userId);
      tick();
    }

    let postUrls: string[] = [];
    if (task.sharePost) {
      const uploads = await Promise.all(
        task.files.map(async (f) => {
          let fileToUpload = f;
          if (audioUrl && f.type.startsWith('video/')) {
            try {
              fileToUpload = await mixAudioIntoVideo(f, task.audioFile as File);
            } catch {
              fileToUpload = f;
            }
          }
          const url = await uploadMedia(fileToUpload, task.memoryMemberId ? 'memorial' : 'posts', task.userId);
          tick();
          return url;
        })
      );
      postUrls = uploads.filter(Boolean);

      // If we uploaded audio separately, keep it as part of post media urls as well.
      if (audioUrl) postUrls = [...postUrls, audioUrl];
    }

    const storyUrls: { url: string; mediaType: 'image' | 'video' }[] = [];
    if (task.shareStory) {
      for (const baseFile of storyInputFiles) {
        const isVideo = baseFile.type.startsWith('video/');
        let candidates: File[] = [baseFile];
        if (isVideo) {
          candidates = await splitVideoForStory(baseFile, 60);
        }

        for (const c of candidates) {
          let fileToUpload = c;
          if (audioUrl && c.type.startsWith('video/')) {
            try {
              fileToUpload = await mixAudioIntoVideo(c, task.audioFile as File);
            } catch {
              fileToUpload = c;
            }
          }
          const url = await uploadMedia(fileToUpload, 'stories', task.userId);
          storyUrls.push({ url, mediaType: (fileToUpload.type.startsWith('video/') ? 'video' : 'image') as 'image' | 'video' });
        }

        tick();
      }
    }

    if (task.sharePost && postUrls.length > 0) {
      const { data: post, error } = await supabase
        .from('posts')
        .insert({
          user_id: task.userId,
          content: task.caption || null,
          media_urls: postUrls,
          audio_url: task.audioMeta?.audio_url ?? null,
          audio_title: task.audioMeta?.audio_title ?? null,
          audio_artist: task.audioMeta?.audio_artist ?? null,
        })
        .select()
        .single();

      if (error) throw error;

      if (post) {
        const captionMentions = (task.caption.match(/@(\w+)/g) || []).map((m) => m.slice(1));
        const allMentionIds = [...task.mentionIds];
        if (captionMentions.length > 0) {
          const { data: mp } = await supabase.from('profiles').select('id, username').in('username', captionMentions);
          if (mp) {
            for (const p of mp) {
              if (p.id !== task.userId && !allMentionIds.includes(p.id)) allMentionIds.push(p.id);
            }
          }
        }
        if (allMentionIds.length > 0) {
          const { error: mentionInsertError } = await supabase
            .from('post_mentions')
            .insert(allMentionIds.map((uid) => ({ post_id: post.id, mentioned_user_id: uid })));

          if (mentionInsertError) throw mentionInsertError;
        }
        
        // Add memory post mention — wrapped in try/catch so post always saves
        if (task.memoryMemberId) {
          try {
            await insertMemoryMention(post.id, task.memoryMemberId);

            // Also directly save to memorial_posts table so it appears on the memorial wall
            await (supabase as unknown as { from: (t: string) => { insert: (r: Record<string, unknown>) => Promise<{ error: unknown }> } })
              .from('memorial_posts')
              .insert({
                family_member_id: task.memoryMemberId,
                created_by: task.userId,
                media_url: postUrls[0] ?? null,
                media_type: (task.files[0]?.type?.startsWith('video') ? 'video' : 'image'),
                caption: task.caption || null,
              });
          } catch (memErr) {
            console.warn('[backgroundPublish] memorial mention/post insert error (non-fatal):', memErr);
          }
        }

        if (task.collabIds.length > 0) {
          await supabase.from('post_collabs').insert(task.collabIds.map((uid) => ({ post_id: post.id, user_id: uid })));
        }

        if (Array.isArray(task.postCollectionIds) && task.postCollectionIds.length > 0) {
          for (const colId of task.postCollectionIds) {
            await supabase.from('post_collection_items').insert({ collection_id: colId, post_id: post.id });
          }
        }
      }

      tick();
    }

    if (task.shareStory && storyUrls.length > 0) {
      for (const s of storyUrls) {
        const { data: story, error } = await supabase
          .from('stories')
          .insert({
            user_id: task.userId,
            media_url: s.url,
            media_type: s.mediaType,
            caption: task.caption || null,
            ring_id: task.ringId,
            audio_url: task.audioMeta?.audio_url ?? null,
            audio_title: task.audioMeta?.audio_title ?? null,
            audio_artist: task.audioMeta?.audio_artist ?? null,
          })
          .select('id')
          .single();

        if (error) throw error;

        try {
          const yearHighlightId = await ensureYearHighlight(task.userId);
          await addStoryToHighlight(yearHighlightId, story.id, s.url, s.mediaType, task.caption || null);

          if (task.storyHighlightId) {
            await addStoryToHighlight(task.storyHighlightId, story.id, s.url, s.mediaType, task.caption || null);
          }
        } catch (e) {
          console.error('Story highlight autosave error:', e);
        }

        tick();
      }
    }

    emit({ taskId: task.id, progress: 100, status: 'success' });
  } catch (err: any) {
    emit({ taskId: task.id, progress: 0, status: 'error', message: err?.message || 'Yuklashda xatolik yuz berdi' });
  }
};

import { useEffect, useMemo, useState, useRef, useCallback, type ReactNode } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, MessageSquare, Wand2, Sparkles, Menu, SquarePen, X } from 'lucide-react';
import { motion } from 'framer-motion';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { addSwipeGestures } from '@/utils/scrollBehavior';
import AIChatView from '@/components/ai/AIChatView';
import AIImageView from '@/components/ai/AIImageView';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

type AITab = 'chat' | 'image' | 'voice';

interface AIChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  model?: string;
  attachments?: {type: string; data: string; name: string;}[];
}

interface ChatSession {
  id: string;
  title: string;
  updatedAt: number;
  messages: AIChatMessage[];
}

const DEFAULT_SESSION_STORAGE_KEY = 'avlodona:ai_default_session_id';

const newId = () => {
  if (typeof crypto !== 'undefined' && 'randomUUID' in crypto) return crypto.randomUUID();
  return `${Date.now()}-${Math.random().toString(16).slice(2)}`;
};

const AIChat = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState<AITab>('chat');
  const swipeTabRef = useRef<HTMLDivElement | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string>('');
  const [dbLoaded, setDbLoaded] = useState(false);
  const saveTimerRef = useRef<number>(0);
  const savedMsgIdsRef = useRef<Set<string>>(new Set());

  // Load from DB on mount
  useEffect(() => {
    const loadFromDB = async () => {
      if (!user?.id) return;
      try {
        const { data: conversations } = await (supabase as any)
          .from('ai_conversations')
          .select('*')
          .eq('user_id', user.id)
          .order('created_at', { ascending: false });

        if (!conversations || conversations.length === 0) {
          setDbLoaded(true);
          return;
        }

        const convIds = (conversations as any[]).map((c: any) => c.id);
        const { data: allMessages } = await (supabase as any)
          .from('ai_messages')
          .select('*')
          .in('conversation_id', convIds)
          .order('created_at');

        const msgsByConv = new Map<string, any[]>();
        ((allMessages || []) as any[]).forEach((m: any) => {
          if (!m.conversation_id) return;
          const list = msgsByConv.get(m.conversation_id) || [];
          list.push(m);
          msgsByConv.set(m.conversation_id, list);
        });

        const loadedSessions: ChatSession[] = (conversations as any[]).map((conv: any) => {
          const msgs = msgsByConv.get(conv.id) || [];
          msgs.forEach((m: any) => savedMsgIdsRef.current.add(m.id));
          return {
            id: conv.id,
            title: conv.title || 'New Chat',
            updatedAt: new Date(conv.created_at || Date.now()).getTime(),
            messages: msgs.map((m: any) => ({
              id: m.id,
              role: (m.role as 'user' | 'assistant') || 'user',
              content: m.content || '',
              timestamp: new Date(m.created_at || Date.now()),
              attachments: m.media_url ? (() => { try { return JSON.parse(m.media_url); } catch { return undefined; } })() : undefined,
            })),
          };
        });

        if (loadedSessions.length > 0) {
          setSessions(loadedSessions);
          setActiveSessionId(loadedSessions[0].id);
        }
      } catch (e) {
        console.error('Failed to load AI chat from DB:', e);
      } finally {
        setDbLoaded(true);
      }
    };

    loadFromDB();
  }, [user?.id]);

  // Ensure we have exactly one stable default session when DB is empty
  useEffect(() => {
    if (!dbLoaded || !user?.id) return;
    if (sessions.length > 0) return;

    let id = '';
    try {
      id = localStorage.getItem(DEFAULT_SESSION_STORAGE_KEY) || '';
    } catch (idErr) {
      console.error('LocalStorage access error:', idErr);
    }

    if (!id) {
      id = newId();
      try {
        localStorage.setItem(DEFAULT_SESSION_STORAGE_KEY, id);
      } catch (e) {
        console.error('Failed to save to local storage', e);
      }
    }

    const s: ChatSession = { id, title: 'New Chat', updatedAt: Date.now(), messages: [] };
    setSessions([s]);
    setActiveSessionId(id);
  }, [dbLoaded, user?.id, sessions.length]);

  // Debounced save to DB
  const saveToDb = useCallback(async (sessionsToSave: ChatSession[]) => {
    if (!user?.id) return;
    try {
      for (const session of sessionsToSave) {
        // Skip empty sessions - don't save to DB
        if (session.messages.length === 0) continue;

        // Determine title
        const title = (session.title && session.title !== 'New Chat')
          ? session.title
          : (session.messages.find(m => m.role === 'user' && m.content?.trim())?.content?.trim().slice(0, 32) || 'New Chat');

        // Upsert conversation
        await (supabase as any).from('ai_conversations').upsert({
          id: session.id,
          user_id: user.id,
          title,
        }, { onConflict: 'id' });

        // Find new messages
        const newMsgs = session.messages.filter(m => !savedMsgIdsRef.current.has(m.id));
        if (newMsgs.length > 0) {
          const { error } = await (supabase as any).from('ai_messages').upsert(
            newMsgs.map(m => ({
              id: m.id,
              conversation_id: session.id,
              role: m.role,
              content: m.content,
              media_url: m.attachments ? JSON.stringify(m.attachments) : null,
            })),
            { onConflict: 'id' }
          );
          if (error) {
            console.error('Supabase upsert error:', error);
            toast.error('Xabarlarni saqlashda xatolik');
          } else {
            newMsgs.forEach(m => savedMsgIdsRef.current.add(m.id));
          }
        }
      }
    } catch (e) {
      console.error('Failed to save AI chat to DB:', e);
    }
  }, [user?.id]);

  // Delete empty conversations from DB on cleanup
  useEffect(() => {
    if (!dbLoaded || !user?.id) return;
    // Remove DB conversations that have no messages
    const cleanupEmpty = async () => {
      try {
        const emptyConvIds = sessions.filter(s => s.messages.length === 0).map(s => s.id);
        if (emptyConvIds.length > 0) {
          await (supabase as any).from('ai_conversations').delete().in('id', emptyConvIds);
        }
      } catch (cleanupErr) {
        console.error('Cleanup empty conversations error:', cleanupErr);
      }
    };
    cleanupEmpty();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [dbLoaded, user?.id]); // Only run once after load

  useEffect(() => {
    if (!dbLoaded || !user?.id) return;
    clearTimeout(saveTimerRef.current);
    saveTimerRef.current = window.setTimeout(() => {
      saveToDb(sessions);
    }, 2000);
    return () => clearTimeout(saveTimerRef.current);
  }, [sessions, dbLoaded, user?.id, saveToDb]);

  const activeSession = useMemo(() => {
    return sessions.find((s) => s.id === activeSessionId) || null;
  }, [sessions, activeSessionId]);

  const ensureSession = () => {
    if (activeSession) return activeSession;
    // Fallback: if something cleared activeSessionId, reuse the first session if present
    const first = sessions[0];
    if (first) {
      setActiveSessionId(first.id);
      return first;
    }
    const s: ChatSession = { id: newId(), title: 'New Chat', updatedAt: Date.now(), messages: [] };
    setSessions([s]);
    setActiveSessionId(s.id);
    return s;
  };

  const createNewChat = () => {
    const s: ChatSession = { id: newId(), title: 'New Chat', updatedAt: Date.now(), messages: [] };
    setSessions((prev) => [s, ...prev]);
    setActiveSessionId(s.id);
    setActiveTab('chat');
    setSidebarOpen(false);
  };

  const setMessagesForActive = (updater: React.SetStateAction<AIChatMessage[]>) => {
    const s = ensureSession();
    setSessions((prev) =>
      prev.map((sess) => {
        if (sess.id !== s.id) return sess;
        const nextMessages = typeof updater === 'function' ? (updater as (prev: AIChatMessage[]) => AIChatMessage[])(sess.messages) : updater;

        let title = sess.title;
        if (!title || title === 'New Chat') {
          const firstUser = nextMessages.find((m: AIChatMessage) => m.role === 'user' && m.content?.trim());
          if (firstUser?.content) title = firstUser.content.trim().slice(0, 32);
        }

        return {
          ...sess,
          title,
          messages: nextMessages,
          updatedAt: Date.now()
        };
      })
    );
  };

  const tabs = [
    { id: 'chat' as const, label: 'Chat', icon: MessageSquare },
    { id: 'image' as const, label: 'Studio', icon: Wand2 },
  ];

  useEffect(() => {
    const el = swipeTabRef.current;
    if (!el) return;
    const order: AITab[] = ['chat', 'image'];
    const idx = order.indexOf(activeTab);
    if (idx < 0) return;

    const cleanup = addSwipeGestures(
      el,
      () => {
        const next = order[idx + 1];
        if (next) setActiveTab(next);
      },
      () => {
        const prev = order[idx - 1];
        if (prev) setActiveTab(prev);
      }
    );

    return () => {
      if (typeof cleanup === 'function') cleanup();
    };
  }, [activeTab]);

  return (
    <div className="min-h-screen bg-background flex flex-col overflow-hidden" style={{ height: '100dvh' }}>
      {/* Header */}
      <div className="sticky top-0 z-40 border-b border-white/10 bg-background/30 backdrop-blur-2xl">
        <div className="px-4 py-3 flex items-center gap-3">
          <motion.button
            type="button"
            onClick={() => navigate('/messages')}
            whileTap={{ scale: 0.95 }}
            whileHover={{ scale: 1.05 }}
            className="h-10 w-10 rounded-2xl bg-white/[0.03] hover:bg-white/[0.08] backdrop-blur-xl border border-white/5 flex items-center justify-center shadow-2xl transition-all">
            <ArrowLeft className="h-5 w-5 opacity-80" />
          </motion.button>
          <div className="relative">
            <div className="h-9 w-9 rounded-full bg-gradient-to-br from-violet-500 via-purple-500 to-pink-500 p-[1.5px] shadow-lg shadow-purple-500/30">
              <img
                src="/ai-avatar.png"
                alt="AI"
                className="h-full w-full rounded-full object-cover bg-background"
                onError={(e) => {
                  (e.currentTarget as HTMLImageElement).src = '/favicon.ico';
                }} />
            </div>
            <div className="absolute -bottom-0.5 -right-0.5 h-3 w-3 rounded-full bg-green-500 border-2 border-background" />
          </div>
          <div className="flex-1 min-w-0">
            <h1 className="font-bold text-foreground text-sm tracking-tight truncate">AI Do'stim</h1>
            <div className="flex items-center gap-1.5">
              <div className="h-1.5 w-1.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.5)]" />
              <span className="text-[10px] text-muted-foreground font-medium uppercase tracking-wider">Online</span>
            </div>
          </div>
        </div>

        <div className="flex justify-center px-4 pb-3">
          <div className="max-w-[400px] w-full flex items-center gap-2.5">
            <motion.button
              type="button"
              onClick={() => setSidebarOpen((v) => !v)}
              whileTap={{ scale: 0.95 }}
              whileHover={{ scale: 1.05 }}
              className="h-11 w-11 rounded-2xl bg-white/[0.03] hover:bg-white/[0.08] border border-white/5 flex items-center justify-center shadow-xl backdrop-blur-xl transition-all"
              aria-label="History"
              title="History">
              <Menu className="h-5 w-5 opacity-70" />
            </motion.button>
            <div className="flex-1 bg-white/[0.03] backdrop-blur-3xl p-1.5 rounded-[22px] flex items-center border border-white/5 shadow-2xl relative overflow-hidden">
              {tabs.map((tab) => (
                <motion.button
                  type="button"
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  whileTap={{ scale: 0.98 }}
                  className={cn(
                    'relative flex-1 flex items-center justify-center gap-2 py-2 px-3 rounded-xl text-xs font-bold transition-all duration-300 z-10',
                    activeTab === tab.id ? 'text-background' : 'text-muted-foreground hover:text-foreground opacity-70 hover:opacity-100'
                  )}
                >
                  {activeTab === tab.id && (
                    <motion.div
                      layoutId="activeTab"
                      className="absolute inset-0 bg-foreground rounded-[14px] -z-10 shadow-lg shadow-white/5"
                      transition={{ type: 'spring', bounce: 0.22, duration: 0.6 }}
                    />
                  )}
                  <tab.icon className={cn("h-3.5 w-3.5", activeTab === tab.id ? "animate-pulse" : "")} />
                  {tab.label}
                </motion.button>
              ))}
            </div>
            <motion.button
              type="button"
              onClick={createNewChat}
              whileTap={{ scale: 0.95 }}
              whileHover={{ scale: 1.05, y: -1 }}
              className="h-11 w-11 rounded-2xl bg-gradient-to-br from-indigo-500/20 via-purple-500/20 to-pink-500/20 hover:from-indigo-500/30 hover:to-pink-500/30 border border-white/10 flex items-center justify-center shadow-xl backdrop-blur-xl transition-all"
              aria-label="New Chat"
              title="New Chat">
              <SquarePen className="h-5 w-5 text-purple-300" />
            </motion.button>
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 flex relative z-0 overflow-hidden">
        {/* Sidebar */}
        <div
          className={cn(
            'absolute inset-y-0 left-0 z-50 w-[290px] max-w-[84vw] bg-background/70 backdrop-blur-2xl border-r border-white/10 transition-transform duration-300 shadow-[0_0_0_1px_rgba(255,255,255,0.05),0_30px_90px_-60px_rgba(0,0,0,0.9)]',
            sidebarOpen ? 'translate-x-0' : '-translate-x-full'
          )}>
          <div className="p-4 flex items-center justify-between">
            <div className="font-bold text-foreground">Avlodona</div>
            <Button variant="ghost" size="icon" onClick={() => setSidebarOpen(false)}>
              <X className="h-5 w-5" />
            </Button>
          </div>
          <div className="px-4">
            <button
              onClick={createNewChat}
              className="w-full flex items-center gap-2 px-3 py-3 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-colors font-semibold">
              <span className="inline-flex w-6 h-6 rounded-full bg-background/40 items-center justify-center">+</span>
              New Chat
            </button>
          </div>
          <div className="px-4 pt-5 text-[11px] font-bold tracking-wider text-muted-foreground">RECENT</div>
          <div className="p-3 space-y-2 overflow-y-auto" style={{ maxHeight: 'calc(100dvh - 210px)' }}>
            {sessions.
              slice().
              sort((a, b) => b.updatedAt - a.updatedAt).
              map((s) => {
                const isActive = s.id === activeSessionId;
                const lastAssistant = [...s.messages].reverse().find((m) => m.role === 'assistant');
                return (
                  <button
                    key={s.id}
                    onClick={() => {
                      setActiveSessionId(s.id);
                      setActiveTab('chat');
                      setSidebarOpen(false);
                    }}
                    className={cn(
                      'w-full text-left p-3 rounded-2xl border transition-colors',
                      isActive ? 'bg-card/60 border-border/60' : 'bg-card/20 border-border/30 hover:bg-card/40'
                    )}>
                    <div className="font-semibold text-foreground truncate">{s.title || 'New Chat'}</div>
                    <div className="text-xs text-muted-foreground truncate mt-1">
                      {lastAssistant?.content || '...'}
                    </div>
                  </button>
                );
              })}
          </div>
        </div>

        {sidebarOpen &&
          <button
            className="absolute inset-0 z-40 bg-black/40"
            onClick={() => setSidebarOpen(false)}
            aria-label="Close sidebar" />
        }

        {/* Main */}
        <main ref={swipeTabRef} className="flex-1 flex flex-col relative z-0 min-h-0 overflow-hidden">
          {activeTab === 'chat' &&
            <AIChatView
              messages={activeSession?.messages || []}
              setMessages={setMessagesForActive} />
          }
          {activeTab === 'image' && <AIImageView />}
        </main>
      </div>

      {/* Decorative Background */}
      <div className="fixed inset-0 pointer-events-none -z-10 overflow-hidden">
        <div className="absolute top-[-10%] left-[-20%] w-[70vw] h-[70vw] blur-[100px] rounded-full bg-primary/5 animate-pulse" style={{ animationDuration: '10s' }} />
        <div className="absolute bottom-[-10%] right-[-20%] w-[70vw] h-[70vw] blur-[100px] rounded-full bg-purple-500/5 animate-pulse" style={{ animationDuration: '7s' }} />
      </div>
    </div>
  );
};

export default AIChat;

import { useState, useRef, useCallback, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { StarUsername } from '@/components/user/StarUsername';
import { Checkbox } from '@/components/ui/checkbox';
import { Progress } from '@/components/ui/progress';
import { Textarea } from '@/components/ui/textarea';
import { Input } from '@/components/ui/input';
import { toast } from 'sonner';
import { supabase } from '@/integrations/supabase/client';
import { uploadMedia } from '@/lib/r2Upload';
import { Check, AtSign, Users, ChevronRight, X, ChevronLeft, Video, Music, MapPin, Loader2 } from 'lucide-react';
import { MusicPicker, type SelectedMusic } from '@/components/create/MusicPicker';
import InstagramMediaCapture from '@/components/create/InstagramMediaCapture';
import { STORY_RINGS, type StoryRingId } from '@/components/stories/storyRings';
import { StoryRingPreview } from '@/components/stories/StoryRingPreview';
import { useMentionsCollabs } from '@/hooks/useMentionsCollabs';
import { usePostCollections } from '@/hooks/usePostCollections';
import { useStoryHighlights } from '@/hooks/useStoryHighlights';
import { UserSearchPicker } from '@/components/post/UserSearchPicker';
import { startBackgroundPublish } from '@/lib/backgroundPublish';

interface NominatimPlace {
  place_id: number;
  display_name: string;
  lat: string;
  lon: string;
}

type Step = 'media' | 'publish';

const CreateContent = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const memoryMemberId = searchParams.get('memberId');
  const { user } = useAuth();

  const { collections: postCollections, createCollection: createPostCollection } = usePostCollections();
  const { highlights: storyHighlights, createHighlight: createStoryHighlight } = useStoryHighlights();

  const [step, setStep] = useState<Step>('media');
  const [editedFiles, setEditedFiles] = useState<{file: File;filter: string;}[]>([]);
  const [caption, setCaption] = useState('');
  const [sharePost, setSharePost] = useState(true);
  const [shareStory, setShareStory] = useState(false);
  const [storySelected, setStorySelected] = useState<Set<number>>(new Set());
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [showSuccess, setShowSuccess] = useState(false);
  const [selectedRingId, setSelectedRingId] = useState<StoryRingId>('default');
  const [mentionIds, setMentionIds] = useState<string[]>([]);
  const [collabIds, setCollabIds] = useState<string[]>([]);
  const [showMentionPicker, setShowMentionPicker] = useState(false);
  const [showCollabPicker, setShowCollabPicker] = useState(false);
  const [mentionProfiles, setMentionProfiles] = useState<any[]>([]);
  const [collabProfiles, setCollabProfiles] = useState<any[]>([]);
  const [selectedMusic, setSelectedMusic] = useState<SelectedMusic | null>(null);
  const [showMusicPicker, setShowMusicPicker] = useState(false);
  const { addMentions, addCollabs } = useMentionsCollabs();

  const [selectedPostCollectionIds, setSelectedPostCollectionIds] = useState<Set<string>>(new Set());
  const [showNewPostCollection, setShowNewPostCollection] = useState(false);
  const [newPostCollectionName, setNewPostCollectionName] = useState('');

  const [selectedStoryHighlightId, setSelectedStoryHighlightId] = useState<string | null>(null);
  const [showNewStoryHighlight, setShowNewStoryHighlight] = useState(false);
  const [newStoryHighlightName, setNewStoryHighlightName] = useState('');

  const [showLocationSearch, setShowLocationSearch] = useState(false);
  const [locationQuery, setLocationQuery] = useState('');
  const [locationResults, setLocationResults] = useState<NominatimPlace[]>([]);
  const [locationLoading, setLocationLoading] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [selectedLocation, setSelectedLocation] = useState<NominatimPlace | null>(null);

  useEffect(() => {
    if (mentionIds.length > 0) {
      supabase.from('profiles').select('id, name, username, avatar_url').in('id', mentionIds).
      then(({ data }) => setMentionProfiles(data || []));
    } else setMentionProfiles([]);
  }, [mentionIds]);

  useEffect(() => {
    if (collabIds.length > 0) {
      supabase.from('profiles').select('id, name, username, avatar_url').in('id', collabIds).
      then(({ data }) => setCollabProfiles(data || []));
    } else setCollabProfiles([]);
  }, [collabIds]);

  useEffect(() => {
    if (!showLocationSearch) return;
    if (selectedLocation) return;

    const q = locationQuery.trim();
    if (q.length < 2) {
      setLocationResults([]);
      setLocationError(null);
      setLocationLoading(false);
      return;
    }

    const t = window.setTimeout(async () => {
      setLocationLoading(true);
      setLocationError(null);
      try {
        const targetUrl = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(q)}&format=json&limit=5&accept-language=uz`;
        const proxyUrl = `https://corsproxy.io/?${encodeURIComponent(targetUrl)}`;
        const res = await fetch(proxyUrl, {
          headers: {
            Accept: 'application/json'
          }
        });
        if (!res.ok) throw new Error('Joy qidirishda xatolik');
        const data = (await res.json()) as NominatimPlace[];
        setLocationResults(Array.isArray(data) ? data : []);
      } catch (e: any) {
        setLocationResults([]);
        setLocationError(e?.message || 'Joy qidirishda xatolik');
      } finally {
        setLocationLoading(false);
      }
    }, 450);

    return () => {
      window.clearTimeout(t);
    };
  }, [locationQuery, showLocationSearch, selectedLocation]);

  const handleMediaFromCapture = useCallback((items: {file: File;filter: string;}[], captureCaption?: string) => {
    setEditedFiles(items);
    if (memoryMemberId && user) {
      startBackgroundPublish({
        id: `${Date.now()}-${Math.random().toString(16).slice(2)}`,
        userId: user.id,
        files: items.map((m) => m.file),
        storyFiles: [],
        audioFile: null,
        audioMeta: null,
        caption: captureCaption || '',
        sharePost: true,
        shareStory: false,
        ringId: 'default',
        mentionIds: [],
        collabIds: [],
        postCollectionIds: [],
        storyHighlightId: null,
        memoryMemberId
      });
      toast.success('Xotira yuklanmoqda…');
      navigate('/');
    } else {
      if (captureCaption) setCaption(captureCaption);
      setStep('publish');
    }
  }, [memoryMemberId, user, navigate]);

  useEffect(() => {
    if (memoryMemberId) {
      setSharePost(true);
      setShareStory(false);
    }
  }, [memoryMemberId]);

  useEffect(() => {
    if (!shareStory) {
      setStorySelected(new Set());
      return;
    }
    setStorySelected(new Set(editedFiles.map((_, idx) => idx)));
  }, [editedFiles, shareStory]);

  const storyFiles = editedFiles.
  map((m, idx) => ({ m, idx })).
  filter(({ idx }) => storySelected.has(idx)).
  map(({ m }) => m.file);

  const storyPreviewSrc = storyFiles[0] ? URL.createObjectURL(storyFiles[0]) : editedFiles[0] ? URL.createObjectURL(editedFiles[0].file) : '';

  const handleBack = useCallback(() => {
    if (step === 'publish') setStep('media');else
    navigate(-1);
  }, [step, navigate]);

  const handlePublish = async () => {
    if (!user || editedFiles.length === 0) return;
    if (!sharePost && !shareStory) {
      toast.error("Post yoki Story-dan kamida birini tanlang");
      return;
    }
    try {
      const shortLocation = (full: string) => {
        const parts = full.split(',').map((p) => p.trim()).filter(Boolean);
        return parts.slice(Math.max(parts.length - 2, 0)).join(', ');
      };

      const finalCaption = selectedLocation ?
      `${caption || ''}${caption ? '\n\n' : ''}📍 ${shortLocation(selectedLocation.display_name)} || ${selectedLocation.lat},${selectedLocation.lon}` :
      caption || '';

      startBackgroundPublish({
        id: `${Date.now()}-${Math.random().toString(16).slice(2)}`,
        userId: user.id,
        files: editedFiles.map((m) => m.file),
        storyFiles: shareStory ? storyFiles : [],
        audioFile: null,
        audioMeta: selectedMusic,
        caption: finalCaption,
        sharePost,
        shareStory,
        ringId: selectedRingId,
        mentionIds,
        collabIds,
        postCollectionIds: sharePost ? Array.from(selectedPostCollectionIds) : [],
        storyHighlightId: shareStory ? selectedStoryHighlightId : null,
        memoryMemberId
      });

      toast.success('Yuklanmoqda…');
      navigate('/');
    } catch (err: any) {
      console.error('Publish error:', err);
      toast.error(err.message || "Yuklashda xatolik yuz berdi");
    }
  };

  if (showSuccess) {
    return null;
  }

  if (step === 'media') {
    return (
      <InstagramMediaCapture
        memoryMemberId={memoryMemberId}
        onClose={() => navigate(-1)}
        onNext={handleMediaFromCapture} />);
  }

  // Publish form - minimalist modern design
  return (
    <div className="fixed inset-0 z-[60] bg-background flex flex-col">
      {isUploading && false &&
      <div className="absolute top-0 left-0 right-0 z-50">
          <Progress value={uploadProgress} className="h-0.5 rounded-none" />
        </div>
      }

      {/* Header */}
      <header className="flex items-center justify-between px-3 py-2.5 border-b border-border/50">
        <button onClick={handleBack} className="flex items-center gap-0.5 text-sm text-muted-foreground active:scale-95 transition-transform">
          <ChevronLeft className="w-5 h-5" />
        </button>
        <h1 className="text-sm font-semibold">Yangi post</h1>
        <Button
          size="sm"
          className="h-8 px-4 rounded-full text-xs font-semibold"
          onClick={handlePublish}
          disabled={editedFiles.length === 0}>
          Ulashish
        </Button>
      </header>

      {memoryMemberId && (
        <div className="bg-primary/10 px-4 py-2 border-b border-primary/20 flex items-center gap-2">
          <AtSign className="w-4 h-4 text-primary" />
          <span className="text-sm font-medium text-primary">Bu post xotira sifatida saqlanadi</span>
        </div>
      )}

      <div className="flex-1 overflow-y-auto">
        <div className="max-w-lg mx-auto px-3 py-3 space-y-3">
          {/* Media preview - horizontal scroll */}
          <div className="flex gap-1.5 overflow-x-auto pb-1" style={{ scrollbarWidth: 'none' }}>
            {editedFiles.map((m, i) =>
            <button
              key={i}
              type="button"
              onClick={() => {
                if (!shareStory) return;
                setStorySelected((prev) => {
                  const next = new Set(prev);
                  if (next.has(i)) next.delete(i);else
                  next.add(i);
                  return next;
                });
              }}
              className="relative flex-shrink-0 w-20 h-20 rounded-xl overflow-hidden bg-muted">
              
                {m.file.type.startsWith('video/') ?
              <div className="relative w-full h-full">
                    <video src={URL.createObjectURL(m.file)} className="w-full h-full object-cover" />
                    <Video className="absolute inset-0 m-auto w-5 h-5 text-white drop-shadow" />
                  </div> :

              <img src={URL.createObjectURL(m.file)} alt="" className="w-full h-full object-cover" />
              }
                {shareStory && storySelected.has(i) &&
              <div className="absolute top-1 left-1 rounded-full bg-black/55 backdrop-blur px-2 py-0.5">
                    <span className="text-[10px] font-semibold text-white">Story</span>
                  </div>
              }
                {shareStory && !storySelected.has(i) &&
              <div className="absolute inset-0 bg-black/35" />
              }
              </button>
            )}
          </div>

          {/* Caption - clean minimal */}
          <div className="py-0 my-[4px]">
            <Textarea
              placeholder="Izoh yozing..."
              value={caption}
              onChange={(e) => setCaption(e.target.value)}
              rows={3}
              className="resize-none text-sm rounded-xl border-border/50 bg-muted/30 focus:bg-background transition-colors min-h-0" />
            
            <p className="text-[10px] text-muted-foreground mt-0.5 text-right">{caption.length}/2200</p>
          </div>

          {/* Tag & Collab - clean rows */}
          {!memoryMemberId && (
            <div className="rounded-xl border border-border/50 overflow-hidden divide-y divide-border/50 my-[3px]">
              <button
                onClick={() => setShowMentionPicker(true)}
                className="w-full flex items-center px-3 py-2.5 bg-background hover:bg-muted/30 transition-colors gap-[10px]">
                
                <AtSign className="h-4 w-4 text-muted-foreground" />
                <span className="flex-1 text-left text-xs font-medium">Belgilash</span>
                {mentionIds.length > 0 &&
                <span className="text-[10px] text-primary font-semibold bg-primary/10 px-1.5 py-0.5 rounded-full">{mentionIds.length}</span>
                }
                <ChevronRight className="h-3.5 w-3.5 text-muted-foreground/50" />
              </button>
              <button
                onClick={() => setShowCollabPicker(true)}
                className="w-full flex items-center gap-2.5 px-3 py-2.5 bg-background hover:bg-muted/30 transition-colors">
                
                <Users className="h-4 w-4 text-muted-foreground" />
                <span className="flex-1 text-left text-xs font-medium">Hamkorlik</span>
                {collabIds.length > 0 &&
                <span className="text-[10px] text-primary font-semibold bg-primary/10 px-1.5 py-0.5 rounded-full">{collabIds.length}</span>
                }
                <ChevronRight className="h-3.5 w-3.5 text-muted-foreground/50" />
              </button>

              {!selectedLocation ?
              <button
                onClick={() => {
                  setShowLocationSearch((prev) => {
                    const next = !prev;
                    if (!next) {
                      setLocationQuery('');
                      setLocationResults([]);
                      setLocationError(null);
                      setLocationLoading(false);
                    }
                    return next;
                  });
                }}
                className="w-full flex items-center gap-2.5 px-3 py-2.5 bg-background hover:bg-muted/30 transition-colors">
                
                  <MapPin className="h-4 w-4 text-muted-foreground" />
                  <span className="flex-1 text-left text-xs font-medium">Joylashuv qo'shish</span>
                  <ChevronRight className="h-3.5 w-3.5 text-muted-foreground/50" />
                </button> :

              <div className="w-full flex items-center gap-2.5 px-3 py-2.5 bg-background">
                  <MapPin className="h-4 w-4 text-muted-foreground" />
                  <span className="flex-1 text-left text-xs font-medium truncate">{selectedLocation.display_name}</span>
                  <button
                  onClick={() => {
                    setSelectedLocation(null);
                    setLocationQuery('');
                    setLocationResults([]);
                    setLocationError(null);
                    setShowLocationSearch(false);
                  }}
                  aria-label="Joylashuvni o'chirish">
                  
                    <X className="h-3.5 w-3.5 text-muted-foreground/70" />
                  </button>
                </div>
              }
            </div>
          )}

          {memoryMemberId && (
            <div className="rounded-xl border border-border/50 overflow-hidden divide-y divide-border/50 my-[3px]">
              {!selectedLocation ?
              <button
                onClick={() => {
                  setShowLocationSearch((prev) => {
                    const next = !prev;
                    if (!next) {
                      setLocationQuery('');
                      setLocationResults([]);
                      setLocationError(null);
                      setLocationLoading(false);
                    }
                    return next;
                  });
                }}
                className="w-full flex items-center gap-2.5 px-3 py-2.5 bg-background hover:bg-muted/30 transition-colors">
                
                  <MapPin className="h-4 w-4 text-muted-foreground" />
                  <span className="flex-1 text-left text-xs font-medium">Joylashuv qo'shish</span>
                  <ChevronRight className="h-3.5 w-3.5 text-muted-foreground/50" />
                </button> :

              <div className="w-full flex items-center gap-2.5 px-3 py-2.5 bg-background">
                  <MapPin className="h-4 w-4 text-muted-foreground" />
                  <span className="flex-1 text-left text-xs font-medium truncate">{selectedLocation.display_name}</span>
                  <button
                  onClick={() => {
                    setSelectedLocation(null);
                    setLocationQuery('');
                    setLocationResults([]);
                    setLocationError(null);
                    setShowLocationSearch(false);
                  }}
                  aria-label="Joylashuvni o'chirish">
                  
                    <X className="h-3.5 w-3.5 text-muted-foreground/70" />
                  </button>
                </div>
              }
            </div>
          )}

          {showLocationSearch && !selectedLocation &&
          <div className="rounded-xl border border-border/50 p-3 space-y-2">
              <div className="relative">
                <Input
                value={locationQuery}
                onChange={(e) => setLocationQuery(e.target.value)}
                placeholder="Joy qidiring..."
                className="h-9 text-sm rounded-xl border-border/50 bg-muted/30 focus:bg-background transition-colors pr-9"
                autoFocus />
              
                {locationLoading &&
              <div className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground">
                    <Loader2 className="h-4 w-4 animate-spin" />
                  </div>
              }
              </div>

              {locationError &&
            <p className="text-xs text-destructive">{locationError}</p>
            }

              {locationResults.length > 0 &&
            <div className="space-y-2">
                  {locationResults.map((p) =>
              <button
                key={p.place_id}
                onClick={() => {
                  setSelectedLocation(p);
                  setShowLocationSearch(false);
                  setLocationResults([]);
                  setLocationError(null);
                }}
                className="w-full text-left px-3 py-2.5 rounded-xl border border-border/50 bg-background hover:bg-muted/30 transition-colors">
                
                      <p className="text-xs font-medium">{p.display_name}</p>
                    </button>
              )}
                </div>
            }

              {!locationLoading && !locationError && locationQuery.trim().length >= 2 && locationResults.length === 0 &&
            <p className="text-xs text-muted-foreground">Hech narsa topilmadi</p>
            }
            </div>
          }

          {/* Audio/Music picker */}
          <div className="rounded-xl border border-border/50 overflow-hidden">
            <button
              onClick={() => setShowMusicPicker(true)}
              className="w-full flex items-center gap-2.5 px-3 py-2.5 bg-background hover:bg-muted/30 transition-colors">
              
              <Music className="h-4 w-4 text-muted-foreground" />
              <span className="flex-1 text-left text-xs font-medium">Musiqa qo'shish</span>
              {selectedMusic &&
              <span className="text-[10px] text-primary font-semibold bg-primary/10 px-1.5 py-0.5 rounded-full truncate max-w-[120px]">
                  {selectedMusic.audio_title}
                </span>
              }
              <ChevronRight className="h-3.5 w-3.5 text-muted-foreground/50" />
            </button>
          </div>

          {/* Selected chips */}
          {!memoryMemberId && (mentionProfiles.length > 0 || collabProfiles.length > 0) &&
          <div className="flex flex-wrap gap-1.5">
              {mentionProfiles.map((u) =>
            <div key={u.id} className="flex items-center gap-1 px-2 py-0.5 bg-primary/8 rounded-full">
                  <Avatar className="h-4 w-4">
                    <AvatarImage src={u.avatar_url || undefined} />
                    <AvatarFallback className="text-[8px]">U</AvatarFallback>
                  </Avatar>
                  <StarUsername
                username={u.username || u.name || 'user'}
                textClassName="text-[10px] font-medium text-foreground"
                iconClassName="h-3 w-3" />
              
                  <button onClick={() => setMentionIds((prev) => prev.filter((id) => id !== u.id))}>
                    <X className="h-2.5 w-2.5 text-muted-foreground" />
                  </button>
                </div>
            )}
              {collabProfiles.map((u) =>
            <div key={u.id} className="flex items-center gap-1 px-2 py-0.5 bg-accent/15 rounded-full">
                  <Avatar className="h-4 w-4">
                    <AvatarImage src={u.avatar_url || undefined} />
                    <AvatarFallback className="text-[8px]">U</AvatarFallback>
                  </Avatar>
                  <span className="text-[10px] font-medium">{u.name || u.username}</span>
                  <button onClick={() => setCollabIds((prev) => prev.filter((id) => id !== u.id))}>
                    <X className="h-2.5 w-2.5 text-muted-foreground" />
                  </button>
                </div>
            )}
            </div>
          }

          {/* Share destination */}
          {!memoryMemberId && (
            <div className="rounded-xl border border-border/50 p-3 space-y-2">
              <p className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider">Qayerga</p>
              <label className="flex items-center gap-2.5 cursor-pointer py-1.5">
                <Checkbox checked={sharePost} onCheckedChange={(v) => setSharePost(!!v)} className="h-4 w-4" />
                <div className="flex-1">
                  <p className="text-xs font-medium">📸 Post</p>
                </div>
              </label>
              <label className="flex items-center gap-2.5 cursor-pointer py-1.5">
                <Checkbox
                  checked={shareStory}
                  onCheckedChange={(v) => {
                    const next = !!v;
                    setShareStory(next);
                    if (next) setStorySelected(new Set(editedFiles.map((_, idx) => idx)));else
                    setStorySelected(new Set());
                  }}
                  className="h-4 w-4" />
                
                <div className="flex-1">
                  <p className="text-xs font-medium">⏳ Story</p>
                  {shareStory &&
                  <p className="text-[10px] text-muted-foreground mt-0.5">
                      {storySelected.size}/{editedFiles.length} tanlandi
                    </p>
                  }
                </div>
              </label>
            </div>
          )}

          {/* Post collections */}
          {!memoryMemberId && sharePost &&
          <div className="rounded-xl border border-border/50 p-3 space-y-2">
              <p className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider">Post ro'yxati</p>
              <div className="space-y-2">
                {postCollections.map((c) => {
                const selected = selectedPostCollectionIds.has(c.id);
                return (
                  <button
                    key={c.id}
                    onClick={() => {
                      setSelectedPostCollectionIds((prev) => {
                        const next = new Set(prev);
                        if (next.has(c.id)) next.delete(c.id);else
                        next.add(c.id);
                        return next;
                      });
                    }}
                    className="w-full flex items-center justify-between px-3 py-2.5 rounded-xl border border-border/50 bg-background hover:bg-muted/30 transition-colors">
                    
                      <span className="text-xs font-medium">{c.name}</span>
                      {selected &&
                    <div className="w-5 h-5 rounded-full bg-primary flex items-center justify-center">
                          <Check className="h-3 w-3 text-primary-foreground" />
                        </div>
                    }
                    </button>);

              })}

                {showNewPostCollection ?
              <div className="flex gap-2">
                    <Input
                  value={newPostCollectionName}
                  onChange={(e) => setNewPostCollectionName(e.target.value)}
                  placeholder="Ro'yxat nomi"
                  className="h-9 text-sm rounded-xl border-border/50 bg-muted/30 focus:bg-background transition-colors"
                  autoFocus
                  onKeyDown={async (e) => {
                    if (e.key !== 'Enter') return;
                    const name = newPostCollectionName.trim();
                    if (!name) return;
                    const created = await createPostCollection(name);
                    if (created?.id) {
                      setSelectedPostCollectionIds((prev) => new Set(prev).add(created.id));
                      setNewPostCollectionName('');
                      setShowNewPostCollection(false);
                    }
                  }} />
                
                    <Button
                  size="sm"
                  className="h-9 rounded-xl"
                  disabled={!newPostCollectionName.trim()}
                  onClick={async () => {
                    const name = newPostCollectionName.trim();
                    if (!name) return;
                    const created = await createPostCollection(name);
                    if (created?.id) {
                      setSelectedPostCollectionIds((prev) => new Set(prev).add(created.id));
                      setNewPostCollectionName('');
                      setShowNewPostCollection(false);
                    }
                  }}>
                  
                      <Check className="h-4 w-4" />
                    </Button>
                    <Button
                  size="sm"
                  variant="ghost"
                  className="h-9 rounded-xl"
                  onClick={() => {
                    setShowNewPostCollection(false);
                    setNewPostCollectionName('');
                  }}>
                  
                      <X className="h-4 w-4" />
                    </Button>
                  </div> :

              <button
                onClick={() => setShowNewPostCollection(true)}
                className="w-full flex items-center gap-2 px-3 py-2.5 rounded-xl border border-dashed border-border/60 text-muted-foreground text-xs hover:bg-muted/20 transition-colors">
                
                    <span className="text-sm leading-none">+</span>
                    Yangi ro'yxat yaratish
                  </button>
              }
              </div>
            </div>
          }

          {/* Story ring selector */}
          {!memoryMemberId && shareStory &&
          <div className="rounded-xl border border-border/50 p-3 space-y-2">
              <p className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider">Halqa</p>
              <div className="flex gap-2 overflow-x-auto" style={{ scrollbarWidth: 'none' }}>
                {STORY_RINGS.map((ring) =>
              <StoryRingPreview
                key={ring.id}
                ringId={ring.id}
                avatarSrc={storyPreviewSrc}
                size="sm"
                selected={selectedRingId === ring.id}
                onClick={() => setSelectedRingId(ring.id)}
                label={ring.label} />

              )}
              </div>
            </div>
          }

          {/* Story collections (highlights) */}
          {!memoryMemberId && shareStory &&
          <div className="rounded-xl border border-border/50 p-3 space-y-2">
              <p className="text-[11px] font-semibold text-muted-foreground uppercase tracking-wider">Story kolleksiya</p>
              <div className="space-y-2">
                {storyHighlights.map((h) => {
                const selected = selectedStoryHighlightId === h.id;
                return (
                  <button
                    key={h.id}
                    onClick={() => setSelectedStoryHighlightId(selected ? null : h.id)}
                    className="w-full flex items-center justify-between px-3 py-2.5 rounded-xl border border-border/50 bg-background hover:bg-muted/30 transition-colors">
                    
                      <span className="text-xs font-medium">{h.name}</span>
                      {selected &&
                    <div className="w-5 h-5 rounded-full bg-primary flex items-center justify-center">
                          <Check className="h-3 w-3 text-primary-foreground" />
                        </div>
                    }
                    </button>);

              })}

                {showNewStoryHighlight ?
              <div className="flex gap-2">
                    <Input
                  value={newStoryHighlightName}
                  onChange={(e) => setNewStoryHighlightName(e.target.value)}
                  placeholder="Kolleksiya nomi"
                  className="h-9 text-sm rounded-xl border-border/50 bg-muted/30 focus:bg-background transition-colors"
                  autoFocus
                  onKeyDown={async (e) => {
                    if (e.key !== 'Enter') return;
                    const name = newStoryHighlightName.trim();
                    if (!name) return;
                    const created = await createStoryHighlight(name);
                    if (created?.id) {
                      setSelectedStoryHighlightId(created.id);
                      setNewStoryHighlightName('');
                      setShowNewStoryHighlight(false);
                    }
                  }} />
                
                    <Button
                  size="sm"
                  className="h-9 rounded-xl"
                  disabled={!newStoryHighlightName.trim()}
                  onClick={async () => {
                    const name = newStoryHighlightName.trim();
                    if (!name) return;
                    const created = await createStoryHighlight(name);
                    if (created?.id) {
                      setSelectedStoryHighlightId(created.id);
                      setNewStoryHighlightName('');
                      setShowNewStoryHighlight(false);
                    }
                  }}>
                  
                      <Check className="h-4 w-4" />
                    </Button>
                    <Button
                  size="sm"
                  variant="ghost"
                  className="h-9 rounded-xl"
                  onClick={() => {
                    setShowNewStoryHighlight(false);
                    setNewStoryHighlightName('');
                  }}>
                  
                      <X className="h-4 w-4" />
                    </Button>
                  </div> :

              <button
                onClick={() => setShowNewStoryHighlight(true)}
                className="w-full flex items-center gap-2 px-3 py-2.5 rounded-xl border border-dashed border-border/60 text-muted-foreground text-xs hover:bg-muted/20 transition-colors">
                
                    <span className="text-sm leading-none">+</span>
                    Yangi kolleksiya
                  </button>
              }
              </div>
            </div>
          }

          {/* Big publish button */}
          <Button
            className="w-full h-11 text-sm font-semibold rounded-xl"
            onClick={handlePublish}
            disabled={isUploading || editedFiles.length === 0 || !sharePost && !shareStory}>
            
            {isUploading ?
            <span className="flex items-center gap-2">
                <span className="animate-spin h-3.5 w-3.5 border-2 border-primary-foreground border-t-transparent rounded-full" />
                {uploadProgress}%
              </span> :

            sharePost && shareStory ? 'Post & Story' : sharePost ? 'Post ulashish' : 'Story ulashish'
            }
          </Button>
          <div className="h-4" />
        </div>
      </div>

      {showMentionPicker &&
      <UserSearchPicker
        open={showMentionPicker}
        onClose={() => setShowMentionPicker(false)}
        selectedIds={mentionIds}
        onSelectionChange={setMentionIds}
        title="Odamlarni belgilash" />

      }
      {showCollabPicker &&
      <UserSearchPicker
        open={showCollabPicker}
        onClose={() => setShowCollabPicker(false)}
        selectedIds={collabIds}
        onSelectionChange={setCollabIds}
        title="Hamkor qo'shish"
        maxSelection={5} />

      }
      <MusicPicker
        open={showMusicPicker}
        onOpenChange={setShowMusicPicker}
        onSelect={setSelectedMusic}
        selectedMusic={selectedMusic}
        onRemove={() => setSelectedMusic(null)} />
      
    </div>);

};

export default CreateContent;

import { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { AppLayout } from '@/components/layout/AppLayout';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Input } from '@/components/ui/input';
import { useToast } from '@/hooks/use-toast';
import { ArrowLeft, X, Plus, Check, AtSign, Users, MapPin, Loader2, Music, Navigation, ToggleLeft, ToggleRight, Heart } from 'lucide-react';
import { supabase } from '@/integrations/supabase/client';
import InstagramMediaCapture from '@/components/create/InstagramMediaCapture';
import { uploadMedia } from '@/lib/r2Upload';
import { usePostCollections } from '@/hooks/usePostCollections';
import { useMentionsCollabs } from '@/hooks/useMentionsCollabs';
import { UserSearchPicker } from '@/components/post/UserSearchPicker';
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { StarUsername } from "@/components/user/StarUsername";
import { cn } from '@/lib/utils';
import { MusicPicker, type SelectedMusic } from '@/components/create/MusicPicker';

interface NominatimPlace {
  place_id: number;
  display_name: string;
  lat: string;
  lon: string;
}

interface MediaFile {
  file: File;
  preview: string;
  type: 'image' | 'video';
  filter?: string;
  gifOverlays?: Array<{ id: string; url: string; originalUrl?: string; x: number; y: number; scale: number; rotation: number }>;
}

type Step = 'media' | 'caption';

const CreatePost = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const targetMemberId = searchParams.get('memberId');
  const { toast } = useToast();
  const { collections, createCollection, addPostToCollection } = usePostCollections();
  
  const [step, setStep] = useState<Step>('media');
  const [selectedMedia, setSelectedMedia] = useState<MediaFile[]>([]);
  const [content, setContent] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedCollectionIds, setSelectedCollectionIds] = useState<Set<string>>(new Set());
  const [showNewCollection, setShowNewCollection] = useState(false);
  const [newCollectionName, setNewCollectionName] = useState('');
  const [mentionIds, setMentionIds] = useState<string[]>([]);
  const [collabIds, setCollabIds] = useState<string[]>([]);
  const [showMentionPicker, setShowMentionPicker] = useState(false);
  const [showCollabPicker, setShowCollabPicker] = useState(false);
  const [mentionProfiles, setMentionProfiles] = useState<any[]>([]);
  const [collabProfiles, setCollabProfiles] = useState<any[]>([]);
  const { addMentions, addCollabs } = useMentionsCollabs();

  const [selectedMusic, setSelectedMusic] = useState<SelectedMusic | null>(null);
  const [showMusicPicker, setShowMusicPicker] = useState(false);
  const [targetMemberName, setTargetMemberName] = useState<string | null>(null);

  // Fetch target member name for tribute banner
  useEffect(() => {
    if (!targetMemberId) return;
    supabase
      .from('family_tree_members')
      .select('member_name')
      .eq('id', targetMemberId)
      .maybeSingle()
      .then(({ data }) => {
        if (data?.member_name) setTargetMemberName(data.member_name);
      });
  }, [targetMemberId]);

  const [showLocationSearch, setShowLocationSearch] = useState(false);
  const [locationQuery, setLocationQuery] = useState('');
  const [locationResults, setLocationResults] = useState<NominatimPlace[]>([]);
  const [locationLoading, setLocationLoading] = useState(false);
  const [locationError, setLocationError] = useState<string | null>(null);
  const [selectedLocation, setSelectedLocation] = useState<NominatimPlace | null>(null);
  const [autoLocationEnabled, setAutoLocationEnabled] = useState(false);
  const [detectingLocation, setDetectingLocation] = useState(false);

  const handleMediaFromCapture = (items: { file: File; filter: string; gifOverlays?: Array<{ id: string; url: string; originalUrl?: string; x: number; y: number; scale: number; rotation: number }> }[]) => {
    const newMedia: MediaFile[] = items.map((item) => ({
      file: item.file,
      preview: URL.createObjectURL(item.file),
      type: item.file.type.startsWith('video/') ? 'video' : 'image',
      filter: item.filter,
      gifOverlays: item.gifOverlays,
    }));
    setSelectedMedia(newMedia);
    setStep('caption');
  };

  // Fetch profiles for selected mention/collab users
  useEffect(() => {
    if (mentionIds.length > 0) {
      supabase.from('profiles').select('id, name, username, avatar_url').in('id', mentionIds)
        .then(({ data }) => setMentionProfiles(data || []));
    } else setMentionProfiles([]);
  }, [mentionIds]);

  useEffect(() => {
    if (collabIds.length > 0) {
      supabase.from('profiles').select('id, name, username, avatar_url').in('id', collabIds)
        .then(({ data }) => setCollabProfiles(data || []));
    } else setCollabProfiles([]);
  }, [collabIds]);

  // Auto-detect location on mount if enabled
  useEffect(() => {
    const saved = localStorage.getItem('avlodona_auto_location');
    if (saved === 'true') {
      setAutoLocationEnabled(true);
      detectCurrentLocation();
    }
  }, []);

  const detectCurrentLocation = async () => {
    if (!navigator.geolocation) {
      toast({ title: "Xatolik", description: "Geolokatsiya qo'llab-quvvatlanmaydi", variant: "destructive" });
      return;
    }
    setDetectingLocation(true);
    try {
      const pos = await new Promise<GeolocationPosition>((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, { enableHighAccuracy: true, timeout: 10000 });
      });
      const { latitude, longitude } = pos.coords;
      // Reverse geocode via edge function
      const { data, error } = await supabase.functions.invoke('nominatim-search', {
        body: { q: `${latitude},${longitude}`, limit: 1, lang: 'uz', reverse: true, lat: latitude, lon: longitude },
      });
      if (error) throw error;
      const results = Array.isArray(data) ? data : [];
      if (results.length > 0) {
        setSelectedLocation(results[0]);
      } else {
        // Fallback: just use coords
        setSelectedLocation({ place_id: 0, display_name: `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`, lat: String(latitude), lon: String(longitude) });
      }
    } catch (err: any) {
      console.error('Location detect error:', err);
      if (err?.code === 1) {
        toast({ title: "Ruxsat berilmadi", description: "Joylashuvga ruxsat bering", variant: "destructive" });
      }
    } finally {
      setDetectingLocation(false);
    }
  };

  const toggleAutoLocation = () => {
    const next = !autoLocationEnabled;
    setAutoLocationEnabled(next);
    localStorage.setItem('avlodona_auto_location', String(next));
    if (next && !selectedLocation) {
      detectCurrentLocation();
    }
  };

  useEffect(() => {
    if (!showLocationSearch) return;
    if (selectedLocation) return;

    const q = locationQuery.trim();
    if (q.length < 2) {
      setLocationResults([]);
      setLocationError(null);
      setLocationLoading(false);
      return;
    }

    const t = window.setTimeout(async () => {
      setLocationLoading(true);
      setLocationError(null);
      try {
        const { data, error } = await supabase.functions.invoke('nominatim-search', {
          body: { q, limit: 5, lang: 'uz' },
        });
        if (error) throw error;
        setLocationResults(Array.isArray(data) ? data : []);
      } catch (e: any) {
        setLocationResults([]);
        setLocationError(e?.message || 'Joy qidirishda xatolik');
      } finally {
        setLocationLoading(false);
      }
    }, 450);

    return () => {
      window.clearTimeout(t);
    };
  }, [locationQuery, showLocationSearch, selectedLocation]);

  const handleBack = () => {
    if (step === 'caption') setStep('media');
    else navigate(-1);
  };

  const uploadFile = async (file: File): Promise<string | null> => {
    if (!user) return null;
    try { return await uploadMedia(file, 'posts', user.id); }
    catch (error) { console.error('Upload error:', error); return null; }
  };

  const toggleCollection = (id: string) => {
    setSelectedCollectionIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const handleCreateCollection = async () => {
    if (!newCollectionName.trim()) return;
    const c = await createCollection(newCollectionName.trim());
    if (c) {
      setSelectedCollectionIds(prev => new Set(prev).add(c.id));
      setNewCollectionName('');
      setShowNewCollection(false);
    }
  };

  const handlePublish = async () => {
    if (!user) return;
    if (selectedMedia.length === 0) {
      toast({ title: "Xatolik", description: "Kamida bitta rasm yoki video tanlang", variant: "destructive" });
      return;
    }

    setIsLoading(true);
    try {
      const finalContent = selectedLocation
        ? `${content || ''}${content ? '\n\n' : ''}📍 ${selectedLocation.display_name}`
        : (content || '');

      const uploadPromises = selectedMedia.map(media => uploadFile(media.file));
      const uploadedUrls = await Promise.all(uploadPromises);
      const validUrls = uploadedUrls.filter((url): url is string => url !== null);
      
      if (validUrls.length === 0) throw new Error('Media yuklashda xatolik');

      const { data: post, error } = await supabase
        .from('posts')
        .insert({
          user_id: user.id,
          content: finalContent || null,
          media_urls: validUrls,
          audio_url: selectedMusic?.audio_url ?? null,
          audio_title: selectedMusic?.audio_title ?? null,
          audio_artist: selectedMusic?.audio_artist ?? null,
          target_member_id: targetMemberId || null,
          visibility: targetMemberId ? 'profile' : 'public',
          // Store GIF overlay metadata per media index so they can be displayed as live animated overlays
          media_metadata: selectedMedia.some(m => m.gifOverlays?.length)
            ? selectedMedia.map(m => ({ gifOverlays: m.gifOverlays || [] }))
            : null,
        })
        .select()
        .single();

      if (error) throw error;

      // Add to selected collections
      if (post) {
        for (const colId of selectedCollectionIds) {
          await addPostToCollection(colId, post.id);
        }

        // Parse @mentions from caption text
        const captionMentionUsernames = (content.match(/@(\w+)/g) || []).map(m => m.slice(1));
        const allMentionIds = [...mentionIds];
        
        if (captionMentionUsernames.length > 0) {
          const { data: mentionedProfiles } = await supabase
            .from('profiles')
            .select('id, username')
            .in('username', captionMentionUsernames);
          
          if (mentionedProfiles) {
            for (const p of mentionedProfiles) {
              if (p.id !== user.id && !allMentionIds.includes(p.id)) {
                allMentionIds.push(p.id);
              }
            }
          }
        }

        // Add mentions and collabs
        if (allMentionIds.length > 0) {
          await addMentions(post.id, allMentionIds);
        }
        if (collabIds.length > 0) {
          await addCollabs(post.id, collabIds);
        }
      }

      selectedMedia.forEach(media => URL.revokeObjectURL(media.preview));
      toast({ title: "Muvaffaqiyat!", description: "Post joylandi" });
      navigate('/');
    } catch (error: any) {
      console.error('Error creating post:', error);
      toast({ title: "Xatolik", description: error.message || "Post yaratishda xatolik yuz berdi", variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AppLayout showNav={false}>
      {step === 'media' ? (
        <InstagramMediaCapture
          onClose={() => navigate(-1)}
          onNext={handleMediaFromCapture}
        />
      ) : (
      <div className="max-w-lg mx-auto min-h-screen flex flex-col">
        {/* Header */}
        <header className="sticky top-0 bg-background/95 backdrop-blur-sm border-b border-border z-40 flex items-center justify-between px-4 py-3">
          <Button variant="ghost" size="icon" onClick={handleBack}>
            <ArrowLeft className="h-6 w-6" />
          </Button>
          <h1 className="text-lg font-semibold">Nashr qilish</h1>
          <Button className="font-semibold" onClick={handlePublish} disabled={isLoading}>
            {isLoading ? "Yuklanmoqda..." : "Ulashish"}
          </Button>
        </header>

        {/* Tribute banner */}
        {targetMemberId && (
          <div className="mx-4 mt-2 px-3 py-2 rounded-xl bg-primary/10 border border-primary/20 flex items-center gap-2">
            <Heart className="h-4 w-4 text-primary flex-shrink-0" />
            <p className="text-sm text-primary">
              <span className="font-medium">{targetMemberName || 'A\'zo'}</span> uchun xotira post
            </p>
          </div>
        )}

        {/* Content */}
        <div className="flex-1 p-4">
          <div className="space-y-4">
            {/* Preview */}
            <div className="flex gap-2 overflow-x-auto pb-2">
              {selectedMedia.map((media, index) => (
                <div key={index} className="flex-shrink-0 w-20 h-20 rounded-lg overflow-hidden bg-muted">
                  {media.type === 'image' ? (
                    <img src={media.preview} alt={`Preview ${index + 1}`} className="w-full h-full object-cover" />
                  ) : (
                    <video src={media.preview} className="w-full h-full object-cover" />
                  )}
                </div>
              ))}
            </div>
            
            {/* Caption */}
            <div className="space-y-2">
              <Textarea placeholder="Izoh yozing... @username bilan belgilang (ixtiyoriy)" value={content} onChange={(e) => setContent(e.target.value)} rows={4} className="resize-none text-base" />
              <p className="text-xs text-muted-foreground text-right">{content.length}/2200</p>
            </div>

            {/* Mention & Collab buttons */}
            <div className="flex gap-2">
              <button
                onClick={() => setShowMentionPicker(true)}
                className={cn(
                  "flex-1 flex items-center gap-2 px-3 py-3 rounded-xl border transition-colors",
                  mentionIds.length > 0 ? "border-primary bg-primary/5" : "border-border hover:bg-muted"
                )}
              >
                <AtSign className="h-5 w-5 text-primary" />
                <div className="text-left">
                  <p className="text-sm font-semibold">Belgilash</p>
                  <p className="text-xs text-muted-foreground">
                    {mentionIds.length > 0 ? `${mentionIds.length} kishi` : 'Tag'}
                  </p>
                </div>
              </button>
              <button
                onClick={() => setShowCollabPicker(true)}
                className={cn(
                  "flex-1 flex items-center gap-2 px-3 py-3 rounded-xl border transition-colors",
                  collabIds.length > 0 ? "border-primary bg-primary/5" : "border-border hover:bg-muted"
                )}
              >
                <Users className="h-5 w-5 text-primary" />
                <div className="text-left">
                  <p className="text-sm font-semibold">Hamkorlik</p>
                  <p className="text-xs text-muted-foreground">
                    {collabIds.length > 0 ? `${collabIds.length} hamkor` : 'Collab'}
                  </p>
                </div>
              </button>
            </div>

            {/* Location */}
            <div className="space-y-2">
              <div className="flex gap-2">
                {!selectedLocation ? (
                  <>
                    <button
                      onClick={() => {
                        setShowLocationSearch(prev => {
                          const next = !prev;
                          if (!next) {
                            setLocationQuery('');
                            setLocationResults([]);
                            setLocationError(null);
                            setLocationLoading(false);
                          }
                          return next;
                        });
                      }}
                      className={cn(
                        "flex-1 flex items-center gap-2 px-3 py-3 rounded-xl border transition-colors",
                        showLocationSearch ? "border-primary bg-primary/5" : "border-border hover:bg-muted",
                      )}
                    >
                      <MapPin className="h-5 w-5 text-primary" />
                      <div className="text-left">
                        <p className="text-sm font-semibold">Joylashuv qo'shish</p>
                        <p className="text-xs text-muted-foreground">Qayerda</p>
                      </div>
                    </button>
                    <button
                      onClick={detectCurrentLocation}
                      disabled={detectingLocation}
                      className={cn(
                        "flex items-center gap-2 px-3 py-3 rounded-xl border transition-colors",
                        "border-border hover:bg-muted",
                      )}
                    >
                      {detectingLocation ? (
                        <Loader2 className="h-5 w-5 text-primary animate-spin" />
                      ) : (
                        <Navigation className="h-5 w-5 text-primary" />
                      )}
                    </button>
                  </>
                ) : (
                  <div className="flex-1 flex items-center justify-between px-3 py-3 rounded-xl border border-primary bg-primary/5">
                    <div className="flex items-center gap-2 min-w-0">
                      <MapPin className="h-5 w-5 text-primary flex-shrink-0" />
                      <p className="text-sm font-medium truncate">{selectedLocation.display_name}</p>
                    </div>
                    <button
                      onClick={() => {
                        setSelectedLocation(null);
                        setLocationQuery('');
                        setLocationResults([]);
                        setLocationError(null);
                        setShowLocationSearch(false);
                      }}
                      className="ml-2"
                      aria-label="Joylashuvni o'chirish"
                    >
                      <X className="h-4 w-4 text-muted-foreground" />
                    </button>
                  </div>
                )}
              </div>

              {/* Auto-location toggle */}
              <button
                onClick={toggleAutoLocation}
                className="flex items-center gap-2 px-3 py-2 rounded-lg text-xs text-muted-foreground hover:text-foreground transition-colors"
              >
                {autoLocationEnabled ? (
                  <ToggleRight className="h-4 w-4 text-primary" />
                ) : (
                  <ToggleLeft className="h-4 w-4" />
                )}
                <span>Har doim joylashuvni avtomatik aniqlash</span>
              </button>

              {showLocationSearch && !selectedLocation && (
                <div className="space-y-2">
                  <div className="relative">
                    <Input
                      value={locationQuery}
                      onChange={(e) => setLocationQuery(e.target.value)}
                      placeholder="Joy qidiring..."
                      className="pr-10"
                      autoFocus
                    />
                    {locationLoading && (
                      <div className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground">
                        <Loader2 className="h-4 w-4 animate-spin" />
                      </div>
                    )}
                  </div>

                  {locationError && (
                    <p className="text-xs text-destructive">{locationError}</p>
                  )}

                  {locationResults.length > 0 && (
                    <div className="space-y-2">
                      {locationResults.map((p) => (
                        <button
                          key={p.place_id}
                          onClick={() => {
                            setSelectedLocation(p);
                            setShowLocationSearch(false);
                            setLocationResults([]);
                            setLocationError(null);
                          }}
                          className="w-full text-left px-3 py-2.5 rounded-lg border border-border hover:bg-muted transition-colors"
                        >
                          <p className="text-sm font-medium">{p.display_name}</p>
                        </button>
                      ))}
                    </div>
                  )}

                  {!locationLoading && !locationError && locationQuery.trim().length >= 2 && locationResults.length === 0 && (
                    <p className="text-xs text-muted-foreground">Hech narsa topilmadi</p>
                  )}
                </div>
              )}
            </div>

            {/* Music */}
            <div className="space-y-2">
              <button
                onClick={() => setShowMusicPicker(true)}
                className={cn(
                  "w-full flex items-center gap-2 px-3 py-3 rounded-xl border transition-colors",
                  selectedMusic ? "border-primary bg-primary/5" : "border-border hover:bg-muted"
                )}
              >
                <Music className="h-5 w-5 text-primary" />
                <div className="text-left min-w-0 flex-1">
                  <p className="text-sm font-semibold">Musiqa qo'shish</p>
                  <p className="text-xs text-muted-foreground truncate">
