import { useState } from 'react';
import { AppLayout } from '@/components/layout/AppLayout';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { Loader2, ArrowLeft, Send } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Support = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [subject, setSubject] = useState('');
  const [message, setMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!subject.trim() || !message.trim()) {
      toast.error('Iltimos, barcha maydonlarni toldiring');
      return;
    }

    setIsSubmitting(true);

    try {
      const { data, error } = await supabase.functions.invoke('send-support-email', {
        body: {
          subject: subject.trim(),
          message: message.trim(),
          userEmail: user?.email || '',
        },
      });

      if (error) {
        throw error;
      }

      toast.success('Murojaatingiz muvaffaqiyatli yuborildi!');
      setSubject('');
      setMessage('');
      navigate(-1); // or go to home navigate('/')
    } catch (err: any) {
      console.error('Error submitting support ticket:', err);
      toast.error('Xatolik yuz berdi. Iltimos keyinroq urinib koring.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <AppLayout showNav={false}>
      <div className="max-w-md mx-auto p-4 min-h-screen">
        <div className="flex items-center gap-3 mb-6 sticky top-0 bg-background/80 backdrop-blur-md pb-4 pt-2 z-10">
          <Button variant="ghost" size="icon" onClick={() => navigate(-1)}>
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <h1 className="text-xl font-bold">Qo'llab-quvvatlash</h1>
        </div>

        <div className="space-y-6">
          <div className="text-muted-foreground text-sm space-y-2">
            <p>Biz bilan bog'laning. Fikr-muloxazalar, takliflar yoki muammolar bo'lsa darhol yordam berishga tayyormiz.</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="subject">Mavzu</Label>
              <Input
                id="subject"
                placeholder="Nima haqida ekanligini qisqacha yozing..."
                value={subject}
                onChange={(e) => setSubject(e.target.value)}
                maxLength={100}
                className="bg-background"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="message">Xabar</Label>
              <Textarea
                id="message"
                placeholder="Muammo yoki taklifingizni batafsil yozing..."
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                rows={6}
                className="resize-none bg-background"
              />
            </div>

            <Button 
              type="submit" 
              className="w-full h-12 rounded-xl text-md font-bold mt-4" 
              disabled={isSubmitting || !subject.trim() || !message.trim()}
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                  Yuborilmoqda...
                </>
              ) : (
                <>
                  <Send className="mr-2 h-5 w-5" />
                  Yuborish
                </>
              )}
            </Button>
          </form>
        </div>
      </div>
    </AppLayout>
  );
};

export default Support;

import { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { useToast } from '@/hooks/use-toast';
import { Users, ArrowLeft, Loader2 } from 'lucide-react';
import { InputOTP, InputOTPGroup, InputOTPSlot } from '@/components/ui/input-otp';
import { supabase } from '@/integrations/supabase/client';
import { LegalFooter } from '@/components/legal/LegalFooter';

const VerifyOtp = () => {
  const [otp, setOtp] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [resendTimer, setResendTimer] = useState(60);
  const navigate = useNavigate();
  const location = useLocation();
  const { toast } = useToast();
  
  const email = location.state?.email;
  const password = location.state?.password;
  const username = location.state?.username;
  const gender = location.state?.gender;

  useEffect(() => {
    if (!email || !password) {
      navigate('/auth');
      return;
    }
  }, [email, password, navigate]);

  useEffect(() => {
    if (resendTimer > 0) {
      const timer = setTimeout(() => setResendTimer(resendTimer - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [resendTimer]);

  const handleVerifyOTP = async () => {
    if (otp.length !== 6) return;
    
    setIsLoading(true);

    try {
      const response = await supabase.functions.invoke('verify-otp', {
        body: { email, otp, password, username, gender }
      });

      if (response.error) {
        throw new Error(response.error.message);
      }

      const data = response.data;

      if (data.access_token && data.refresh_token) {
        // Set the session
        const { error } = await supabase.auth.setSession({
          access_token: data.access_token,
          refresh_token: data.refresh_token
        });

        if (error) throw error;

        toast({ 
          title: "Muvaffaqiyatli!", 
          description: "Tizimga kirdingiz" 
        });
        
        navigate('/');
      } else {
        throw new Error("Authentication failed");
      }
    } catch (error: any) {
      toast({ 
        title: "Xato", 
        description: error.message || "Kod noto'g'ri", 
        variant: "destructive" 
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleResendOTP = async () => {
    try {
      const response = await supabase.functions.invoke('send-otp', {
        body: { email }
      });

      if (response.error) {
        throw new Error(response.error.message);
      }

      setResendTimer(60);
      toast({ 
        title: "Kod qayta yuborildi!", 
        description: "Email pochtangizni tekshiring" 
      });
    } catch (error: any) {
      toast({ 
        title: "Xato", 
        description: error.message || "Kod yuborishda xato", 
        variant: "destructive" 
      });
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gradient-to-br from-primary/20 via-background to-accent/20 p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="text-center">
          <Button 
            variant="ghost" 
            size="icon"
            className="absolute left-4 top-4"
            onClick={() => navigate('/auth')}
          >
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div className="mx-auto mb-4 h-16 w-16 rounded-full bg-primary/10 flex items-center justify-center">
            <Users className="h-8 w-8 text-primary" />
          </div>
          <CardTitle className="text-2xl">Kodni kiriting</CardTitle>
          <CardDescription>
            {email} ga yuborilgan 6 xonali kodni kiriting
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="flex justify-center">
            <InputOTP
              maxLength={6}
              value={otp}
              onChange={(value) => setOtp(value)}
            >
              <InputOTPGroup>
                <InputOTPSlot index={0} />
                <InputOTPSlot index={1} />
                <InputOTPSlot index={2} />
                <InputOTPSlot index={3} />
                <InputOTPSlot index={4} />
                <InputOTPSlot index={5} />
              </InputOTPGroup>
            </InputOTP>
          </div>

          <Button 
            className="w-full" 
            onClick={handleVerifyOTP}
            disabled={otp.length !== 6 || isLoading}
          >
            {isLoading ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Tekshirilmoqda...
              </>
            ) : (
              "Tasdiqlash"
            )}
          </Button>

          <div className="text-center">
            <p className="text-sm text-muted-foreground">
              Kod kelmadimi?{' '}
              {resendTimer > 0 ? (
                <span>{resendTimer} soniyadan keyin qayta yuborish mumkin</span>
              ) : (
                <Button 
                  variant="link" 
                  className="p-0 h-auto"
                  onClick={handleResendOTP}
                >
                  Qayta yuborish
                </Button>
              )}
            </p>
          </div>
        </CardContent>
      </Card>

      <LegalFooter className="mt-6" />
    </div>
  );
};

export default VerifyOtp;

// Instagram-like smooth scrolling utilities

export const enableSmoothScrolling = () => {
  // Enable smooth scrolling for the entire document
  if (typeof document !== 'undefined') {
    document.documentElement.style.scrollBehavior = 'smooth';
    document.body.style.scrollBehavior = 'smooth';
    
    // Enable momentum scrolling for touch devices
    (document.body.style as any).webkitOverflowScrolling = 'touch';
    
    // Prevent overscroll bounce on mobile
    document.body.style.overscrollBehavior = 'none';
  }
};

export const enableMomentumScrolling = (element: HTMLElement) => {
  if (!element) return;
  
  // Enable momentum scrolling for touch devices
  (element.style as any).webkitOverflowScrolling = 'touch';
  
  // Add smooth scroll behavior
  element.style.scrollBehavior = 'smooth';
  
  // Prevent rubber band effect
  element.style.overscrollBehavior = 'none';
};

export const createSmoothScrollContainer = () => {
  const styles = `
    .smooth-scroll-container {
      -webkit-overflow-scrolling: touch;
      overscroll-behavior: none;
    }
    
    /* Custom scrollbar for webkit browsers */
    .smooth-scroll-container::-webkit-scrollbar {
      width: 0px;
      background: transparent;
    }
    
    /* Hide scrollbar for Firefox */
    .smooth-scroll-container {
      scrollbar-width: none;
      -ms-overflow-style: none;
    }
  `;
  
  if (typeof document !== 'undefined') {
    const styleSheet = document.createElement('style');
    styleSheet.textContent = styles;
    document.head.appendChild(styleSheet);
  }
};

export const addScrollMomentum = (element: HTMLElement) => {
  if (!element) return;
  
  // Use native smooth scrolling and moment scrolling on iOS instead of manual JS
  element.style.scrollBehavior = 'smooth';
  (element.style as any).webkitOverflowScrolling = 'touch';
  
  return () => {
    // cleanup not strictly needed for CSS styles
  };
};

export const addSwipeGestures = (element: HTMLElement, onSwipeLeft?: () => void, onSwipeRight?: () => void) => {
  if (!element) return;
  
  let startX = 0;
  let startY = 0;
  let distX = 0;
  let distY = 0;
  let startTime = 0;
  
  const handleTouchStart = (e: TouchEvent) => {
    startX = e.touches[0].clientX;
    startY = e.touches[0].clientY;
    startTime = Date.now();
    distX = 0;
    distY = 0;
  };
  
  const handleTouchMove = (e: TouchEvent) => {
    distX = e.touches[0].clientX - startX;
    distY = e.touches[0].clientY - startY;
  };
  
  const handleTouchEnd = () => {
    const endTime = Date.now();
    const elapsedTime = endTime - startTime;
    
    // Check if it's a valid swipe (fast enough and far enough)
    if (elapsedTime < 550 && Math.abs(distX) > 45 && Math.abs(distY) < 260) {
      if (distX > 0 && onSwipeRight) {
        onSwipeRight();
      } else if (distX < 0 && onSwipeLeft) {
        onSwipeLeft();
      }
    }
    
    // Reset values
    distX = 0;
    distY = 0;
  };
  
  element.addEventListener('touchstart', handleTouchStart, { passive: true, capture: true });
  element.addEventListener('touchmove', handleTouchMove, { passive: true, capture: true });
  element.addEventListener('touchend', handleTouchEnd, { passive: true, capture: true });
  element.addEventListener('touchcancel', handleTouchEnd, { passive: true, capture: true });
  
  return () => {
    element.removeEventListener('touchstart', handleTouchStart, true);
    element.removeEventListener('touchmove', handleTouchMove, true);
    element.removeEventListener('touchend', handleTouchEnd, true);
    element.removeEventListener('touchcancel', handleTouchEnd, true);
  };
};
